        return NextResponse.json({ error: 'Server configuration error: DIOGENES_API_KEY not set' }, { status: 500 });
    }

    if (authHeader !== `Bearer ${apiKey}`) {
        return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    // Use Service Role to bypass RLS since we are accessing on behalf of the user via API Key
    const supabase = createClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL!,
        process.env.SUPABASE_SERVICE_ROLE_KEY!
    );

    // We need to know which user to fetch for.
    // Ideally this is set in env, or passed as a query param if we supported multi-tenancy.
    // For personal use, we'll try to find the user via ID in env, or fallback to the first profile found (dangerous but convenient for single user).

    let userId = process.env.DIOGENES_USER_ID;

    if (!userId) {
        // Fallback: Try to get the username from query params
        const { searchParams } = new URL(req.url);
        const username = searchParams.get('username');

        if (username) {
            const { data: profile } = await supabase.from('profiles').select('id').eq('username', username).single();
            if (profile) userId = profile.id;
        }
    }

    if (!userId) {
        // Last resort/Lazy mode: Just grab the first user in profiles (Assumes single-tenant/personal instance)
        const { data: profiles } = await supabase.from('profiles').select('id').limit(1);
        if (profiles && profiles.length > 0) {
            userId = profiles[0].id;
        }
    }

    if (!userId) {
        return NextResponse.json({ error: 'User not specified and no default found. Set DIOGENES_USER_ID in env.' }, { status: 400 });
    }

    // Parallel fetch for speed
    const [
        { data: profile },
        { data: tasks },
        { data: pacts },
        { data: vows },
        { data: notes },
        { data: recentRecords }
    ] = await Promise.all([
        supabase.from('profiles').select('*').eq('id', userId).single(),
        supabase.from('tasks').select('*').eq('user_id', userId).eq('is_archived', false),
        supabase.from('pacts').select('*').eq('user_id', userId).eq('is_completed', false),
        supabase.from('vows').select('*').eq('user_id', userId).eq('status', 'active'),
        supabase.from('notes').select('*').eq('user_id', userId).limit(5).order('updated_at', { ascending: false }),
        supabase.from('records').select('*').eq('user_id', userId).gte('date', new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().split('T')[0])
    ]);

    // Construct the context packet
    const context = {
        user: {
            name: profile?.full_name,
            username: profile?.username,
            bio: profile?.bio
        },
        active_vows: vows,
        daily_habits: tasks?.map(t => ({
            id: t.id,
            name: t.name,
            metric: t.metric_config,
            recent_logs: recentRecords?.filter((r: any) => r.task_id === t.id)
        })),
        pending_pacts: pacts,
        recent_notes: notes
    };

    return NextResponse.json(context);
}

import { createClient } from '@supabase/supabase-js';
import { NextRequest, NextResponse } from 'next/server';

export async function POST(req: NextRequest) {
    const authHeader = req.headers.get('Authorization');
    const apiKey = process.env.DIOGENES_API_KEY;
    let userId = process.env.DIOGENES_USER_ID;

    if (!apiKey) return NextResponse.json({ error: 'Server config error' }, { status: 500 });
    if (authHeader !== `Bearer ${apiKey}`) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    const supabase = createClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL!,
        process.env.SUPABASE_SERVICE_ROLE_KEY!
    );

    // Identity resolution
    if (!userId) {
        const { searchParams } = new URL(req.url);
        const username = searchParams.get('username');
        if (username) {
            const { data } = await supabase.from('profiles').select('id').eq('username', username).single();
            if (data) userId = data.id;
        }
    }
    if (!userId) {
        const { data } = await supabase.from('profiles').select('id').limit(1);
        if (data?.[0]) userId = data[0].id;
    }
    if (!userId) return NextResponse.json({ error: 'User target not found' }, { status: 400 });

    try {
        const body = await req.json();

        if (!body.text) {
            return NextResponse.json({ error: 'Missing "text" field' }, { status: 400 });
        }

        const { data, error } = await supabase.from('pacts').insert({
            user_id: userId,
            text: body.text,
            date: body.date || new Date().toISOString().split('T')[0], // Default to today
            is_completed: false
        }).select();

        if (error) throw error;

        return NextResponse.json({ success: true, pact: data[0] });

    } catch (e: any) {
        return NextResponse.json({ error: e.message }, { status: 500 });
    }
}

import { createClient } from '@/utils/supabase/server';
import { createAdminClient } from '@/utils/supabase/admin';
import { NextRequest, NextResponse } from 'next/server';
import { adminMessaging } from '@/lib/firebase-admin';

export async function POST(req: NextRequest) {
    // Auth check for testing trigger
    const supabase = await createClient();
    const { data: { user: currentUser } } = await supabase.auth.getUser();
    if (!currentUser) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

    // Use admin client to bypass RLS
    const adminClient = createAdminClient();
    const { data: tokens, error } = await adminClient
        .from('fcm_tokens')
        .select('*');

    if (error) {
        console.error('Error fetching FCM tokens:', error);
        return NextResponse.json({ error: 'Database error: ' + error.message }, { status: 500 });
    }

    if (!tokens || tokens.length === 0) {
        return NextResponse.json({ error: 'No FCM tokens found' }, { status: 404 });
    }

    if (!adminMessaging) {
        return NextResponse.json({ error: 'Firebase Admin SDK not initialized' }, { status: 500 });
    }

    const results = [];

    for (const device of tokens) {
        try {
            const message = {
                token: device.token,
                notification: {
                    title: "Evening Evaluation",
                    body: "The day ends. Update your records. Did you live according to your nature?",
                },
                data: {
                    url: "/",
                },
                android: {
                    notification: {
                        icon: 'ic_stat_ic_notification'
                    }
                }
            };

            await adminMessaging.send(message);

            results.push({ success: true, user: device.user_id });
        } catch (e: any) {
            console.error(`Failed to send FCM to ${device.user_id} (${device.token})`, e?.message);
            results.push({ success: false, user: device.user_id });
        }
    }

    return NextResponse.json({
        success: true,
        sent: results.filter(r => r.success).length
    });
}

