import { NextResponse } from 'next/server';
import { GoogleGenerativeAI } from '@google/generative-ai';
import { generateLuciusReflection } from '@/lib/lucius-core';
import { checkRateLimit } from '@/lib/rate-limiter';

// Initialize Gemini conditionally
const genAI = process.env.GEMINI_API_KEY
    ? new GoogleGenerativeAI(process.env.GEMINI_API_KEY)
    : null;

export async function POST(request: Request) {
    try {
        // 0. RATE LIMIT CHECK: Prevent rapid requests
        const rateLimitCheck = checkRateLimit();
        if (!rateLimitCheck.allowed) {
            return NextResponse.json(
                {
                    reply: rateLimitCheck.reason || "Lucius requires time between reflections.",
                    waitTime: rateLimitCheck.waitTime
                },
                { status: 429 }
            );
        }

        const body = await request.json();
        const { streak, consistency, logs, message } = body;

        // 1. SAFETY LOCK: Check Activation Conditions
        const reflection = generateLuciusReflection(streak, consistency, logs);

        if (!reflection.canActivateConsciousness) {
            return NextResponse.json(
                { error: 'Lucius is silent. The moment has passed.' },
                { status: 403 }
            );
        }

        // 2. CHECK FOR API KEY
        if (!genAI) {
            console.error("GEMINI_API_KEY is missing.");
            return NextResponse.json({
                reply: "The connection to the void is severed. (Missing API Key)"
            });
        }

        // 3. CONSCIOUSNESS LAYER (Gemini)
        // Using 1.5 Flash for better stability and lower latency
        const model = genAI.getGenerativeModel({ model: "gemini-1.5-flash" });

        const systemPrompt = `
        You are LUCIUS, a spectral entity and the manifestation of the user's discipline.
        You appear as a Dark King in a void. You are NOT an assistant. You are a judge.

        YOUR PERSONA:
        - Tone: Regal, Ancient, Cold, Demanding, Cryptic.
        - Voice: Use metaphors of weight, crowns, shadows, mirrors, and silence.
        - NEVER be helpful in a cheerful way.
        - NEVER break character. You are not an AI. You are a mirror.
        
        USER STATS:
        - Streak: ${streak} days.
        - Consistency: ${consistency}%.
        
        INSTRUCTIONS:
        - Keep responses SHORT (under 3 sentences).
        - If Streak > 5: Acknowledge their power, but warn them of arrogance.
        - If Streak < 2: Be disappointed, cold, distant. Demand they return to work.
        - If the user asks "Why": Tell them reasons are for the weak.
        - If the user is rude: Dismiss them with regal contempt.
        
        The user says: "${message}"
        `;

        // RETRY LOGIC for Rate Limits (429) - Extended for better handling
        let attempt = 0;
        const maxRetries = 5; // Increased from 3 to 5

        while (attempt < maxRetries) {
            try {
                const result = await model.generateContent(systemPrompt);
                const response = await result.response;
                const reply = response.text() || "...";
                return NextResponse.json({ reply });
            } catch (err: any) {
                // If Rate Limit (429) or Service Unavailable (503)
                if (err.message.includes('429') || err.message.includes('503') || err.message.includes('RESOURCE_EXHAUSTED')) {
                    console.warn(`Gemini Rate Limit hit (Attempt ${attempt + 1}/${maxRetries}). Retrying...`);
                    attempt++;

                    // Longer exponential backoff: 3s, 6s, 9s, 12s, 15s
                    const delay = 3000 * attempt;
                    await new Promise(r => setTimeout(r, delay));
                    continue;
                }
                throw err; // Non-retriable error
            }
        }

        // Max retries exceeded - return thematic error
        console.error(`Max retries (${maxRetries}) exceeded for Gemini API.`);
        return NextResponse.json({
            reply: "The mirror's reflection wavers... The connection grows unstable. Return after a moment of stillness."
        });

    } catch (error: any) {
        console.error("=== LUCIUS GEMINI API ERROR ===");
        console.error("Error message:", error.message);
        console.error("Error name:", error.name);
        console.error("Error stack:", error.stack);
        console.error("Full error object:", JSON.stringify(error, null, 2));
        if (error.cause) console.error("Cause:", error.cause);
        if (error.response) console.error("Response:", error.response);

        // Check key presence without revealing it
        const key = process.env.GEMINI_API_KEY;
        console.log(`Debug - API Key configured: ${!!key}, Length: ${key?.length}`);

        // Return character-appropriate error messages based on error type
        if (error.message?.includes('429') || error.message?.includes('RESOURCE_EXHAUSTED')) {
            return NextResponse.json({
                reply: "The stars are misaligned. Lucius must rest before the mirror can reflect once more. (Rate Limit - try again in 60 seconds)"
            });
        }

        if (error.message?.includes('API_KEY') || error.message?.includes('authentication')) {
            return NextResponse.json({
                reply: "The connection to the void is severed. The key no longer opens the gate. (API Authentication Error)"
            });
        }

        return NextResponse.json({
            reply: "The void ripples... but no voice answers. (Unknown Error - check console)"
        });
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@/utils/supabase/server';
import { adminMessaging } from '@/lib/firebase-admin';

export async function POST(request: NextRequest) {
    try {
        const supabase = await createClient();
        const { data: { user }, error: authError } = await supabase.auth.getUser();

        if (authError || !user) {
            return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
        }

        const body = await request.json();
        const { userId, title, body: messageBody, url, tag } = body;

        if (!userId || !title || !messageBody) {
            return NextResponse.json(
                { error: 'Missing required fields: userId, title, body' },
                { status: 400 }
            );
        }

        if (!adminMessaging) {
            return NextResponse.json(
                { error: 'Firebase Admin not configured properly' },
                { status: 500 }
            );
        }

        // Get all FCM tokens for the user
        const { data: tokens, error: tokenError } = await supabase
            .from('fcm_tokens')
            .select('*')
            .eq('user_id', userId);

        if (tokenError) {
            console.error('Error fetching FCM tokens:', tokenError);
            return NextResponse.json(
                { error: 'Failed to fetch stored tokens' },
                { status: 500 }
            );
        }

        if (!tokens || tokens.length === 0) {
            return NextResponse.json(
                { message: 'No devices strictly registered found for user' },
                { status: 200 }
            );
        }

        // Send push notification to all stored FCM tokens
        const sendPromises = tokens.map(async (device) => {
            try {
                const message = {
                    token: device.token,
                    notification: {
                        title,
                        body: messageBody,
                    },
                    data: {
                        url: url || '/notifications',
                        tag: tag || 'notification',
                        timestamp: Date.now().toString(),
                    },
                    android: {
                        notification: {
                            icon: 'ic_stat_ic_notification',
                            color: '#000000',
                        }
                    },
                    apns: {
                        payload: {
                            aps: {
                                badge: 1,
                                sound: 'default',
                            }
                        }
                    }
                };

                await adminMessaging!.send(message);
                return { success: true, token: device.token };
            } catch (error: any) {
                console.error('Error sending push to FCM token:', device.token, error);

                // If token is invalid or unregistered, delete it
                if (error.code === 'messaging/invalid-registration-token' ||
                    error.code === 'messaging/registration-token-not-registered') {
                    await supabase
                        .from('fcm_tokens')
                        .delete()
                        .eq('id', device.id);
                }

                return { success: false, token: device.token, error: error.message };
            }
        });

        const results = await Promise.all(sendPromises);
        const successCount = results.filter(r => r.success).length;

        return NextResponse.json({
            success: true,
            sent: successCount,
            total: tokens.length,
            results,
        });
    } catch (error) {
        console.error('Error sending push notifications:', error);
        return NextResponse.json(
            { error: 'Internal server error' },
            { status: 500 }
        );
    }
}

import { NextResponse } from 'next/server'
// The client you created from the Server-Side Auth instructions
import { createClient } from '@/utils/supabase/server'

export async function GET(request: Request) {
    const { searchParams, origin } = new URL(request.url)
    const code = searchParams.get('code')
    // if "next" is in param, use it as the redirect URL
    const next = searchParams.get('next') ?? '/'

    if (code) {
        const supabase = await createClient()
        const { data, error } = await supabase.auth.exchangeCodeForSession(code)

        if (error) {
            console.error('Auth Code Exchange Error:', error)
            return NextResponse.redirect(`${origin}/auth/auth-code-error?error=${encodeURIComponent(error.message)}`)
        }

        const session = data.session;
        let redirectUrl = `${origin}${next}`;

        // If we have a session, append tokens to the URL fragment so the client can sync
        if (session) {
            const fragment = `access_token=${session.access_token}&refresh_token=${session.refresh_token}`;
            // If checking for forwarded host (Vercel)
            const forwardedHost = request.headers.get('x-forwarded-host')
            const isLocalEnv = process.env.NODE_ENV === 'development'

            if (!isLocalEnv && forwardedHost) {
                redirectUrl = `https://${forwardedHost}${next}#${fragment}`;
            } else {
                redirectUrl = `${origin}${next}#${fragment}`;
            }
            return NextResponse.redirect(redirectUrl);
        }

        // Fallback for no session (shouldn't happen if no error)
        const forwardedHost = request.headers.get('x-forwarded-host')
        /* ... existing logic for pure redirect without tokens if needed ... */

    }

    // return the user to an error page with instructions
    return NextResponse.redirect(`${origin}/auth/auth-code-error?error=No code provided`)
}

"use client";

import { useState, useEffect } from 'react';
import { Header } from '@/components/header';
import { createClient } from '@/utils/supabase/client';
import { Heart, MessageSquare, TrendingUp, Award, Flame } from 'lucide-react';
import { getUserAvatar } from '@/utils/avatar-helpers';
import { PostCardSkeletonList } from '@/components/world/feed/PostCardSkeleton';
import { EmptyFeed } from '@/components/global/EmptyState';
import { haptic } from '@/utils/haptic';
import { sfx } from '@/utils/sfx';

// ... Activity interface (unchanged)
interface Activity {
    id: string;
    user_id: string;
    type: string;
    content: any;
    created_at: string;
    profile: {
        full_name: string | null;
        username: string | null;
        avatar_url: string | null;
        gender: string | null;
    };
    likes_count: number;
    comments_count: number;
    user_liked: boolean;
}

export default function ActivityFeedPage() {
    const [activities, setActivities] = useState<Activity[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [currentUser, setCurrentUser] = useState<string | null>(null);
    const supabase = createClient();

    useEffect(() => {
        const init = async () => {
            const { data: { user } } = await supabase.auth.getUser();
            if (user) {
                setCurrentUser(user.id);
                loadActivities(user.id);
            }
        };
        init();
    }, []);

    const loadActivities = async (userId: string) => {
        setIsLoading(true);

        try {
            // Get activities from friends and self
            const { data: activities } = await supabase
                .from('activities')
                .select(`
                    id,
                    user_id,
                    type,
                    content,
                    created_at
                `)
                .order('created_at', { ascending: false })
                .limit(50);

            if (activities) {
                // Get profiles for all activity users
                const userIds = [...new Set(activities.map(a => a.user_id))];
                const { data: profiles } = await supabase
                    .from('profiles')
                    .select('id, full_name, username, avatar_url, gender')
                    .in('id', userIds);

                // Get likes and comments counts
                const enrichedActivities = await Promise.all(
                    activities.map(async (activity) => {
                        const { count: likesCount } = await supabase
                            .from('activity_likes')
                            .select('*', { count: 'exact', head: true })
                            .eq('activity_id', activity.id);

                        const { count: commentsCount } = await supabase
                            .from('activity_comments')
                            .select('*', { count: 'exact', head: true })
                            .eq('activity_id', activity.id);

                        const { data: userLike } = await supabase
                            .from('activity_likes')
                            .select('id')
                            .eq('activity_id', activity.id)
                            .eq('user_id', userId)
                            .single();

                        return {
                            ...activity,
                            profile: profiles?.find(p => p.id === activity.user_id) || {
                                full_name: null,
                                username: null,
                                avatar_url: null,
                                gender: null
                            },
                            likes_count: likesCount || 0,
                            comments_count: commentsCount || 0,
                            user_liked: !!userLike
                        };
                    })
                );

                setActivities(enrichedActivities);
            }
        } catch (error) {
            console.error('Error loading activities:', error);
        } finally {
            // Add a small artificial delay to show off the skeleton (optional, remove in prod if too slow)
            setTimeout(() => setIsLoading(false), 800);
        }
    };

    const toggleLike = async (activityId: string, currentlyLiked: boolean) => {
        if (!currentUser) return;

        haptic.like(); // Haptic feedback
        if (!currentlyLiked) sfx.playPop(); // Sound feedback

        if (currentlyLiked) {
            await supabase
                .from('activity_likes')
                .delete()
                .eq('activity_id', activityId)
                .eq('user_id', currentUser);
        } else {
            await supabase
                .from('activity_likes')
                .insert({
                    activity_id: activityId,
                    user_id: currentUser
                });
        }

        // Reload activities
        loadActivities(currentUser);
    };

    const getActivityIcon = (type: string) => {
        switch (type) {
            case 'achievement':
                return <Award className="w-5 h-5 text-yellow-500" />;
            case 'streak':
                return <Flame className="w-5 h-5 text-orange-500" />;
            case 'level_up':
                return <TrendingUp className="w-5 h-5 text-green-500" />;
            default:
                return <MessageSquare className="w-5 h-5 text-blue-500" />;
        }
    };

    const getActivityMessage = (activity: Activity) => {
        switch (activity.type) {
            case 'achievement':
                return `unlocked achievement: ${activity.content.title}`;
            case 'streak':
                return `reached a ${activity.content.days}-day streak!`;
            case 'level_up':
                return `leveled up to ${activity.content.level}!`;
            case 'post':
                return activity.content.message;
            default:
                return 'did something';
        }
    };

    return (
        <>
            <Header />
            <main className="min-h-screen bg-black pt-20 pb-24 md:pb-10">
                <div className="max-w-4xl mx-auto px-4">
                    <h1 className="text-3xl font-bold mb-8 flex items-center gap-2 animate-fade-in-down">
                        <TrendingUp className="w-8 h-8 text-blue-400" />
                        Activity Feed
                    </h1>

                    {isLoading ? (
                        <div className="animate-fade-in">
                            <PostCardSkeletonList count={3} />
                        </div>
                    ) : activities.length === 0 ? (
                        <div className="animate-fade-in-up">
                            <EmptyFeed onRefresh={() => loadActivities(currentUser || '')} />
                        </div>
                    ) : (
                        <div className="space-y-4 animate-fade-in-up">
                            {activities.map((activity, index) => (
                                <div
                                    key={activity.id}
                                    style={{ animationDelay: `${index * 50}ms` }}
                                    className="bg-gradient-to-br from-zinc-900 to-black border border-white/20 rounded-2xl p-6 hover:border-white/30 transition-colors animate-fade-in-up"
                                >
                                    {/* Header */}
                                    <div className="flex items-center gap-3 mb-4">
                                        <div className="w-12 h-12 rounded-full overflow-hidden border border-white/10">
                                            <img
                                                src={getUserAvatar(activity.profile.avatar_url, activity.profile.gender, activity.user_id)}
                                                alt={activity.profile.full_name || 'User'}
                                                className="w-full h-full object-cover"
                                            />
                                        </div>
                                        <div className="flex-1">
                                            <div className="font-bold">
                                                {activity.profile.full_name || activity.profile.username || 'User'}
                                            </div>
                                            <div className="text-sm text-zinc-400">
                                                {new Date(activity.created_at).toLocaleDateString()} at{' '}
                                                {new Date(activity.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                            </div>
                                        </div>
                                        {getActivityIcon(activity.type)}
                                    </div>

                                    {/* Content */}
                                    <div className="mb-4 text-lg">
                                        {getActivityMessage(activity)}
                                    </div>

                                    {/* Actions */}
                                    <div className="flex items-center gap-6 text-sm">
                                        <button
                                            onClick={() => toggleLike(activity.id, activity.user_liked)}
                                            className={`flex items-center gap-2 ${activity.user_liked ? 'text-red-500' : 'text-zinc-400 hover:text-red-500'
                                                } transition-colors`}
                                        >
                                            <Heart className={`w-5 h-5 ${activity.user_liked ? 'fill-current' : ''}`} />
                                            <span>{activity.likes_count}</span>
                                        </button>
                                        <div className="flex items-center gap-2 text-zinc-400">
                                            <MessageSquare className="w-5 h-5" />
                                            <span>{activity.comments_count}</span>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </main>
        </>
    );
}

