"use client";

import { useEffect, useState, useCallback } from "react";
import { login, signup, continueAsGuest, signInWithGoogle } from "./actions";
import { createClient as createSupabaseClient } from "@supabase/supabase-js";

export function LoginForm({
    message,
    error: initialError,
}: {
    message?: string;
    error?: string;
}) {
    const [isCapacitor, setIsCapacitor] = useState(false);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(initialError);

    useEffect(() => {
        const cap = (window as unknown as { Capacitor?: { isNativePlatform?: () => boolean } }).Capacitor;
        if (cap?.isNativePlatform?.()) {
            setIsCapacitor(true);
        }
    }, []);

    const handleGoogleSignIn = useCallback(async () => {
        if (!isCapacitor) return;
        setLoading(true);
        setError(undefined);

        try {
            // IMPORTANT: Use @supabase/supabase-js directly (NOT @supabase/ssr)
            // with flowType: 'implicit' to avoid PKCE.
            // The @supabase/ssr createBrowserClient defaults to PKCE which stores
            // a code_verifier in cookies — but the callback opens in Chrome which
            // doesn't share the WebView's cookies.
            const supabase = createSupabaseClient(
                process.env.NEXT_PUBLIC_SUPABASE_URL!,
                process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
                {
                    auth: {
                        flowType: "implicit",
                        autoRefreshToken: false,
                        persistSession: false,
                    },
                }
            );

            const { data, error: oauthError } = await supabase.auth.signInWithOAuth({
                provider: "google",
                options: {
                    redirectTo: "com.diogenes.app://callback",
                    skipBrowserRedirect: true,
                    queryParams: {
                        access_type: "offline",
                        prompt: "consent",
                    },
                },
            });

            if (oauthError) {
                setError("Could not initiate Google login");
                setLoading(false);
                return;
            }

            if (data.url) {
                // Navigate the WebView to the OAuth URL.
                // Capacitor will intercept the external domain (accounts.google.com)
                // and open it in the system browser (Chrome).
                // After OAuth, Google will redirect to:
                //   https://gyral.vercel.app/#access_token=...&refresh_token=...
                // The deep link intent filter intercepts this and opens the app.
                // CapacitorAuthHandler picks up the tokens and calls setSession().
                window.location.href = data.url;
                return; // Don't reset loading — we're navigating away
            }
        } catch (e) {
            console.error("[Login] Google sign-in error:", e);
            setError("Something went wrong. Please try again.");
        }

        setLoading(false);
    }, [isCapacitor]);

    return (
        <>
            {/* Message / Error */}
            {message && (
                <div className="mb-6 p-4 bg-blue-500/10 border border-blue-500/20 text-blue-400 text-sm rounded-lg text-center backdrop-blur-sm">
                    {message}
                </div>
            )}
            {error && (
                <div className="mb-6 p-4 bg-red-500/10 border border-red-500/20 text-red-400 text-sm rounded-lg text-center backdrop-blur-sm">
                    {error}
                </div>
            )}

            <form className="space-y-6">
                <div className="space-y-2">
                    <label className="text-xs uppercase tracking-wider text-zinc-500 ml-1" htmlFor="email">Email</label>
                    <input
                        id="email"
                        name="email"
                        type="email"
                        required
                        placeholder="initiate@gyral.com"
                        className="w-full bg-white/5 border border-white/10 rounded-lg px-4 py-3 text-white placeholder:text-zinc-700 focus:outline-none focus:border-white/30 focus:ring-1 focus:ring-white/30 transition-all font-mono"
                    />
                </div>

                <div className="space-y-2">
                    <label className="text-xs uppercase tracking-wider text-zinc-500 ml-1" htmlFor="password">Password</label>
                    <input
                        id="password"
                        name="password"
                        type="password"
                        required
                        placeholder="••••••••"
                        className="w-full bg-white/5 border border-white/10 rounded-lg px-4 py-3 text-white placeholder:text-zinc-700 focus:outline-none focus:border-white/30 focus:ring-1 focus:ring-white/30 transition-all font-mono"
                    />
                </div>

                <div className="flex flex-col gap-4 pt-4">
                    <button
                        formAction={login}
                        className="w-full bg-white text-black font-bold py-3 rounded-lg hover:scale-105 transition-transform shadow-[0_0_20px_rgba(255,255,255,0.2)] hover:shadow-[0_0_30px_rgba(255,255,255,0.4)]"
                    >
                        Log In
                    </button>
                    <div className="flex gap-4">
                        <button
                            formAction={signup}
                            className="flex-1 bg-transparent border border-white/20 text-white font-bold py-3 rounded-lg hover:bg-white/5 hover:border-white/40 transition-all text-sm"
                        >
                            Sign Up (Email)
                        </button>
                    </div>
                </div>
            </form>

            <div className="flex flex-col gap-4">
                <div className="relative flex py-2 items-center">
                    <div className="flex-grow border-t border-white/10"></div>
                    <span className="flex-shrink-0 mx-4 text-zinc-600 text-[10px] uppercase tracking-widest">Or Authenticate With</span>
                    <div className="flex-grow border-t border-white/10"></div>
                </div>

                {isCapacitor ? (
                    /* Capacitor: client-side IMPLICIT flow — no PKCE, no code_verifier, no cookies */
                    <button
                        onClick={handleGoogleSignIn}
                        disabled={loading}
                        type="button"
                        className="w-full bg-white/10 hover:bg-white/20 border border-white/20 text-white font-bold py-3 rounded-lg transition-all flex items-center justify-center gap-3 shadow-lg group disabled:opacity-50"
                    >
                        <svg className="w-5 h-5 bg-white rounded-full p-0.5 group-hover:scale-110 transition-transform" viewBox="0 0 24 24">
                            <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4" />
                            <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" />
                            <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05" />
                            <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" />
                        </svg>
                        {loading ? "Connecting..." : "Google"}
                    </button>
                ) : (
                    /* Web: server action with PKCE (unchanged) */
                    <form>
                        <button
                            formAction={signInWithGoogle}
                            className="w-full bg-white/10 hover:bg-white/20 border border-white/20 text-white font-bold py-3 rounded-lg transition-all flex items-center justify-center gap-3 shadow-lg group"
                        >
                            <svg className="w-5 h-5 bg-white rounded-full p-0.5 group-hover:scale-110 transition-transform" viewBox="0 0 24 24">
                                <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4" />
                                <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" />
                                <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05" />
                                <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" />
                            </svg>
                            Google
                        </button>
                    </form>
                )}

                <form>
                    <button
                        formAction={continueAsGuest}
                        className="w-full bg-transparent border border-white/10 text-zinc-500 hover:text-white font-mono text-xs uppercase tracking-widest py-3 rounded-lg hover:bg-white/5 transition-all"
                    >
                        Continue as Guest
                    </button>
                </form>
            </div>
        </>
    );
}

"use client";

import { useEffect, useState, useRef } from 'react';
import { Ghost, Minimize2, Maximize2 } from 'lucide-react'; // Simpler icons
import { Header } from "@/components/header";
import { useUserData } from '@/context/user-data-context';
import { LuciusReflection } from '@/lib/lucius-core';
import { LuciusChat } from '@/components/lucius/lucius-chat';
import { LuciusDenial } from '@/components/lucius/lucius-denial';

export default function LuciusPage() {
    const { currentStreak, consistencyScore, records } = useUserData();
    const [reflection, setReflection] = useState<LuciusReflection | null>(null);
    const [isLoading, setIsLoading] = useState(true);

    // Consciousness Interface state
    const [chatOpen, setChatOpen] = useState(false);
    const [chatHistory, setChatHistory] = useState<{ role: 'user' | 'lucius', text: string }[]>([]);
    const [turns, setTurns] = useState(0);
    const [isChatLocked, setIsChatLocked] = useState(true);

    const [showHistory, setShowHistory] = useState(false); // Toggle for timeline
    const [showDenial, setShowDenial] = useState(false);

    useEffect(() => {
        const logs = Object.entries(records).flatMap(([date, recs]) => recs);

        const fetchReflection = async () => {
            try {
                const response = await fetch('/api/lucius/reflect', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ streak: currentStreak, consistency: consistencyScore, logs })
                });
                if (response.ok) {
                    const data = await response.json();
                    setReflection(data);
                    setIsChatLocked(!data.canActivateConsciousness);
                }
            } catch (e) {
                console.error(e);
            } finally {
                setIsLoading(false);
            }
        };
        fetchReflection();
    }, [currentStreak, consistencyScore, records]);

    const handleSendMessage = async (message: string) => {
        const newHistory = [...chatHistory, { role: 'user' as const, text: message }];
        setChatHistory(newHistory);
        setTurns(prev => prev + 1);

        try {
            const logs = Object.entries(records).flatMap(([date, recs]) => recs);
            // Dramatic pause
            await new Promise(r => setTimeout(r, 1200));

            const response = await fetch('/api/lucius/chat', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    streak: currentStreak,
                    consistency: consistencyScore,
                    logs,
                    message
                })
            });

            if (response.status === 403) {
                setChatHistory(prev => [...prev, { role: 'lucius', text: "The reflection fades..." }]);
                setIsChatLocked(true);
                setTimeout(() => setShowDenial(true), 2500);
                return;
            }

            const data = await response.json();
            setChatHistory(prev => [...prev, { role: 'lucius', text: data.reply }]);

            if (turns >= 2) {
                setTimeout(() => {
                    setChatHistory(prev => [...prev, { role: 'lucius', text: "Enough for now." }]);
                    setIsChatLocked(true);
                    setTimeout(() => setShowDenial(true), 2500);
                }, 2000);
            }

        } catch (e) {
            setChatHistory(prev => [...prev, { role: 'lucius', text: "..." }]);
        }
    };

    if (showDenial) {
        return <LuciusDenial onReturn={() => {
            setShowDenial(false);
            setChatOpen(false);
        }} />;
    }

    return (
        <div className="min-h-screen flex flex-col bg-[var(--lucius-void-900)] text-[var(--lucius-text-primary)] relative selection:bg-white/20">
            <Header />

            {/* Living Background */}
            <div className="lucius-aura" />

            {/* AVATAR PRESENCE */}
            <div className={`absolute inset-0 z-0 flex items-center justify-center transition-opacity duration-1000 pointer-events-none ${chatOpen ? 'opacity-40 scale-105' : 'opacity-20 scale-100'}`}>
                <img
                    src="/lucius-avatar.png"
                    alt=""
                    className="h-[80vh] w-auto object-cover opacity-80 mix-blend-screen"
                    style={{
                        maskImage: 'linear-gradient(to bottom, transparent 0%, black 20%, black 60%, transparent 100%)',
                        WebkitMaskImage: 'linear-gradient(to bottom, transparent 0%, black 20%, black 60%, transparent 100%)',
                        filter: 'grayscale(100%) contrast(120%) brightness(0.8)'
                    }}
                />
            </div>

            {/* Main Content Area - Center Stage */}
            <main className="flex-1 flex flex-col justify-center items-center p-6 relative z-10 w-full max-w-5xl mx-auto">

                {isLoading ? (
                    <div className="animate-pulse space-y-4 text-center">
                        <div className="h-2 w-24 bg-white/10 mx-auto rounded-full" />
                        <p className="text-xs uppercase tracking-[0.2em] text-white/30">Gazing into the mirror...</p>
                    </div>
                ) : (
                    <div className="w-full max-w-3xl space-y-12 transition-all duration-1000 ease-out">

                        {/* State Header (Minimal) */}
                        {!chatOpen && (
                            <div className="text-center space-y-2 lucius-enter-active">
                                <p className="text-[10px] uppercase tracking-[0.4em] text-white/20">Current State</p>
                                <h2 className={`text-xl font-mono tracking-[0.2em] ${reflection?.state === 'ALIGNED' ? 'text-white drop-shadow-[0_0_10px_rgba(255,255,255,0.3)]' :
                                    reflection?.state === 'RETURNING' ? 'text-emerald-500/80' :
                                        'text-white/60'
                                    }`}>
                                    {reflection?.state}
                                </h2>
                            </div>
                        )}

                        {/* Core Interaction */}
                        {!chatOpen ? (
                            <div className="text-center space-y-12 lucius-enter-active">
                                {/* The Message */}
                                <div className="space-y-6 max-w-2xl mx-auto">
                                    <p className="text-3xl md:text-5xl font-serif leading-tight italic text-transparent bg-clip-text bg-gradient-to-b from-white to-white/60 drop-shadow-lg">
                                        "{reflection?.message}"
                                    </p>
                                </div>

                                {/* Actions */}
                                <div className="flex flex-col items-center gap-6">
                                    {!isChatLocked ? (
                                        <button
                                            onClick={() => setChatOpen(true)}
                                            className="group relative px-8 py-4 overflow-hidden rounded-sm bg-white/5 hover:bg-white/10 transition-all duration-500 border border-white/5 hover:border-white/20"
                                        >
                                            <div className="absolute inset-0 bg-white/5 opacity-0 group-hover:opacity-100 transition-opacity blur-xl" />
                                            <span className="relative z-10 font-serif italic text-lg tracking-wide flex items-center gap-3">
                                                <Ghost className="w-5 h-5 opacity-50 group-hover:opacity-100 transition-opacity" />
                                                <span>Invoke Consciousness</span>
                                            </span>
                                        </button>
                                    ) : (
                                        <div className="text-xs text-white/20 uppercase tracking-[0.2em] flex items-center gap-2 cursor-not-allowed">
                                            <span>Silence reigns</span>
                                        </div>
                                    )}

                                    {/* History Toggle */}
                                    <button
                                        onClick={() => setShowHistory(!showHistory)}
                                        className="text-xs text-white/20 hover:text-white/50 uppercase tracking-widest transition-colors flex items-center gap-2 mt-8"
                                    >
                                        {showHistory ? <Minimize2 className="w-3 h-3" /> : <Maximize2 className="w-3 h-3" />}
                                        {showHistory ? "Hide Reflection" : "View Reflection Path"}
                                    </button>
                                </div>
                            </div>
                        ) : (
                            <LuciusChat
                                initialHistory={chatHistory}
                                onSendMessage={handleSendMessage}
                                isLocked={isChatLocked}
                                turnsLeft={3 - turns}
                                onClose={() => setChatOpen(false)}
                            />
                        )}

                        {/* Timeline / History Drawer (Conditional) */}
                        {showHistory && !chatOpen && reflection?.checkpoints && (
                            <div className="border-t border-white/5 pt-12 mt-12 grid grid-cols-1 md:grid-cols-3 gap-8 lucius-enter-active">
                                {reflection.checkpoints.map((cp, idx) => (
                                    <div key={idx} className="space-y-2 group">
                                        <div className="flex items-center gap-3 mb-2">
                                            <div className={`h-1.5 w-1.5 rounded-full ${cp.status === 'BOTH_ACTED' ? 'bg-white shadow-[0_0_8px_rgba(255,255,255,0.5)]' : 'bg-white/10'
                                                }`} />
                                            <span className="text-[10px] font-mono text-white/30">{cp.day}</span>
                                        </div>
                                        <p className="text-sm text-white/60 font-serif leading-relaxed group-hover:text-white/90 transition-colors">
                                            {cp.description}
                                        </p>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                )}
            </main>
        </div>
    );
}

"use client";

import { useUserData, LifeEvent } from '@/context/user-data-context';
import { Skull, ArrowLeft, Calendar, Settings, Plus, Star, Flag } from 'lucide-react';
import Link from 'next/link';
import { useState, useEffect } from 'react';
import { SettingsModal } from '@/components/modals/settings-modal';
import { AddLifeEventModal } from '@/components/modals/add-life-event-modal';

export default function MementoPage() {
    const { birthDate, lifeEvents, deleteLifeEvent, mementoViewMode } = useUserData();
    const [isSettingsOpen, setIsSettingsOpen] = useState(false);
    const [isMobile, setIsMobile] = useState(false);

    // Interaction State
    const [selectedId, setSelectedId] = useState<number | null>(null); // Week or Day index
    const [hoveredEvent, setHoveredEvent] = useState<LifeEvent | null>(null);

    // Detect mobile screen size
    useEffect(() => {
        const checkMobile = () => {
            setIsMobile(window.innerWidth < 768);
        };

        checkMobile();
        window.addEventListener('resize', checkMobile);
        return () => window.removeEventListener('resize', checkMobile);
    }, []);

    const calculateStats = () => {
        if (!birthDate) return null;
        const birth = new Date(birthDate);
        const today = new Date();

        if (mementoViewMode === 'year') {
            const startOfYear = new Date(today.getFullYear(), 0, 1);
            const isLeap = (year: number) => (year % 4 === 0 && year % 100 !== 0) || (year % 400 === 0);
            const totalDays = isLeap(today.getFullYear()) ? 366 : 365;

            // Days passed since start of year
            const diffTime = today.getTime() - startOfYear.getTime();
            const daysPassed = Math.floor(diffTime / (1000 * 60 * 60 * 24));

            return {
                passed: daysPassed,
                total: totalDays,
                percentage: (daysPassed / totalDays) * 100,
                labelPassed: 'Days Passed',
                labelRemaining: 'Days Remaining',
                labelTotal: 'Year Progress'
            };
        } else {
            // Life View (Weeks)
            const diffTime = Math.abs(today.getTime() - birth.getTime());
            const weeksLived = Math.floor(diffTime / (1000 * 60 * 60 * 24 * 7));
            const totalWeeks = 90 * 52; // Assuming 90 years
            return {
                passed: weeksLived,
                total: totalWeeks,
                percentage: (weeksLived / totalWeeks) * 100,
                labelPassed: 'Weeks Lived',
                labelRemaining: 'Weeks Remaining',
                labelTotal: 'Life Complete'
            };
        }
    };

    const stats = calculateStats();

    const getEventForIndex = (index: number) => {
        if (!birthDate || !lifeEvents.length) return null;

        if (mementoViewMode === 'year') {
            // Check if any event falls on this day of the current year
            // index 0 = Jan 1st
            const today = new Date();
            const year = today.getFullYear();
            const targetDate = new Date(year, 0, 1);
            targetDate.setDate(targetDate.getDate() + index);
            const targetDateStr = targetDate.toISOString().split('T')[0];

            return lifeEvents.find(e => e.event_date === targetDateStr);
        } else {
            // Life mode (Weeks)
            const birth = new Date(birthDate);
            const weekStart = new Date(birth);
            weekStart.setDate(birth.getDate() + (index * 7));
            const weekEnd = new Date(weekStart);
            weekEnd.setDate(weekStart.getDate() + 6);

            return lifeEvents.find(e => {
                const eDate = new Date(e.event_date);
                return eDate >= weekStart && eDate <= weekEnd;
            });
        }
    };

    return (
        <main className="min-h-screen bg-black text-white p-4 md:p-6 lg:p-12 font-sans selection:bg-white/20 pb-20 md:pb-12">
            {/* Header / Nav */}
            <div className="max-w-7xl mx-auto flex items-center justify-between mb-8 md:mb-12 animate-[fadeIn_0.5s_ease-out]">
                <Link href="/" className="flex items-center gap-2 text-zinc-500 hover:text-white transition-colors group">
                    <ArrowLeft className="w-5 h-5 group-hover:-translate-x-1 transition-transform" />
                    <span className="font-bold tracking-wide">RETURN</span>
                </Link>

                <div className="flex items-center gap-4">
                    <div className="px-3 py-1 bg-zinc-800 rounded-full text-xs font-mono text-zinc-400 border border-white/10">
                        {mementoViewMode === 'year' ? 'YEAR VIEW' : 'LIFE VIEW'}
                    </div>
                    <button
                        onClick={() => setIsSettingsOpen(true)}
                        className="flex items-center gap-2 px-4 py-2 rounded-full border border-white/10 hover:bg-white/5 transition-colors text-sm text-zinc-400 hover:text-white"
                    >
                        <Settings className="w-4 h-4" />
                        <span>Configure</span>
                    </button>
                </div>
            </div>

            <div className="max-w-5xl mx-auto animate-[slideUp_0.6s_ease-out]">
                {/* Title Section */}
                <div className="text-center mb-8 md:mb-16 space-y-4">
                    <div className="inline-flex items-center justify-center p-3 md:p-4 rounded-full bg-white/5 mb-4 border border-white/10">
                        <Skull className="w-6 h-6 md:w-8 md:h-8 text-white/80" />
                    </div>
                    <h1 className="text-3xl md:text-4xl lg:text-6xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-b from-white to-zinc-600">
                        MEMENTO MORI
                    </h1>
                    <p className="text-zinc-500 text-sm md:text-base lg:text-lg max-w-xl mx-auto px-4">
                        {mementoViewMode === 'year'
                            ? "A single orbit around the sun. Make today count."
                            : "Your life is a finite grit. Click a square to etch a memory or set a goal."}
                    </p>
                </div>

                {!birthDate ? (
                    <div className="flex flex-col items-center justify-center py-20 border border-dashed border-white/10 rounded-2xl bg-white/5">
                        <Calendar className="w-12 h-12 text-zinc-600 mb-4" />
                        <h3 className="text-xl font-bold text-white mb-2">No Birth Date Set</h3>
                        <p className="text-zinc-500 mb-6">Enter your birth date to generate your life grid.</p>
                        <button
                            onClick={() => setIsSettingsOpen(true)}
                            className="px-6 py-3 bg-white text-black font-bold rounded-full hover:scale-105 transition-transform"
                        >
                            Set Birth Date
                        </button>
                    </div>
                ) : (
                    <div className="space-y-12">
                        {/* Stats Bar */}
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                            <div className="p-6 rounded-2xl bg-zinc-900/50 border border-white/5 text-center group hover:border-white/20 transition-colors">
                                <div className="text-3xl font-black text-white mb-1 group-hover:scale-110 transition-transform duration-300">
                                    {stats?.passed.toLocaleString()}
                                </div>
                                <div className="text-xs font-bold text-zinc-500 uppercase tracking-widest">{stats?.labelPassed}</div>
                            </div>
                            <div className="p-6 rounded-2xl bg-zinc-900/50 border border-white/5 text-center group hover:border-white/20 transition-colors">
                                <div className="text-3xl font-black text-white mb-1 group-hover:scale-110 transition-transform duration-300">
                                    {stats && (stats.total - stats.passed).toLocaleString()}
                                </div>
                                <div className="text-xs font-bold text-zinc-500 uppercase tracking-widest">{stats?.labelRemaining}</div>
                            </div>
                            <div className="p-6 rounded-2xl bg-zinc-900/50 border border-white/5 text-center group hover:border-white/20 transition-colors">
                                <div className="text-3xl font-black text-white mb-1 group-hover:scale-110 transition-transform duration-300">
                                    {stats?.percentage.toFixed(1)}%
                                </div>
                                <div className="text-xs font-bold text-zinc-500 uppercase tracking-widest">{stats?.labelTotal}</div>
                            </div>
                        </div>

                        {/* The Grid */}
                        <div className="p-4 md:p-8 bg-zinc-950 border border-white/10 rounded-2xl md:rounded-3xl shadow-2xl relative overflow-hidden">

                            <div className="flex justify-between items-center mb-4 md:mb-6">
                                <div className="text-[10px] font-mono text-zinc-700">{mementoViewMode === 'year' ? 'JAN 1' : 'YEAR 0'}</div>

                                {/* Active Event Display on Hover/Selection */}
                                <div className="h-6 flex items-center justify-center">
                                    {hoveredEvent ? (
                                        <div className="flex items-center gap-2 animate-in fade-in slide-in-from-bottom-2">
                                            {hoveredEvent.type === 'MEMORY' ? (
                                                <Star className="w-3 h-3 text-yellow-500 fill-current" />
                                            ) : (
                                                <Flag className="w-3 h-3 text-blue-500 fill-current" />
                                            )}
                                            <span className="text-xs md:text-sm font-bold text-white">{hoveredEvent.title}</span>
                                            <span className="text-[10px] md:text-xs text-zinc-500">({hoveredEvent.event_date})</span>
                                        </div>
                                    ) : (
                                        <span className="text-[10px] md:text-xs text-zinc-800">Hover {mementoViewMode === 'year' ? 'days' : 'squares'} to inspect</span>
                                    )}
                                </div>

                                <div className="text-[10px] font-mono text-zinc-700">{mementoViewMode === 'year' ? 'DEC 31' : 'YEAR 90'}</div>
                            </div>

                            {/* Grid container - scrollable on mobile */}
                            <div className="overflow-x-auto -mx-4 px-4 md:mx-0 md:px-0 scrollbar-thin scrollbar-thumb-zinc-700 scrollbar-track-transparent">
                                {/* Mobile: 26 columns (half), Desktop: 52 columns (full) */}
                                <div
                                    className="grid gap-[4px] w-full"
                                    style={{
                                        gridTemplateColumns: `repeat(${isMobile ? 26 : 52}, minmax(0, 1fr))`
                                    }}
                                >
                                    {Array.from({ length: stats!.total }).map((_, i) => {
                                        const isLived = i < stats!.passed;
                                        const isCurrent = i === stats!.passed;

                                        // Check for event
                                        const event = getEventForIndex(i);

                                        let cellClass = "bg-zinc-900 border-transparent opacity-50";

                                        if (isLived) cellClass = "bg-zinc-700/50 active:bg-zinc-500";
                                        if (isCurrent) cellClass = "bg-white animate-pulse shadow-[0_0_10px_white]";

                                        if (event) {
                                            if (event.type === 'MEMORY') {
                                                cellClass = "bg-yellow-500 shadow-[0_0_10px_rgba(234,179,8,0.5)] z-10 scale-110 rounded-sm";
                                            } else {
                                                cellClass = "bg-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.5)] z-10 scale-110 animate-pulse rounded-sm";
                                            }
                                        }

                                        return (
                                            <button
                                                key={i}
                                                onClick={() => setSelectedId(i)}
                                                onMouseEnter={() => event && setHoveredEvent(event)}
                                                onMouseLeave={() => setHoveredEvent(null)}
                                                className={`
                                                    aspect-square rounded-full transition-all duration-200 relative
                                                    ${cellClass}
                                                    active:scale-110
                                                `}
                                                style={{ minWidth: isMobile ? '8px' : '10px', minHeight: isMobile ? '8px' : '10px' }}
                                                title={mementoViewMode === 'year' ? `Day ${i + 1}` : `Week ${i + 1}`}
                                            />
                                        );
                                    })}
                                </div>
                            </div>
                        </div>
                    </div>
                )}
            </div>

            <SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} />

            {/* Add/View Event Modal */}
            <AddLifeEventModal
                isOpen={selectedId !== null}
                onClose={() => setSelectedId(null)}
                weekIndex={selectedId || 0}
                birthDate={birthDate || new Date().toISOString()}
            />
        </main>
    );
}

