"use client";

import { Header } from "@/components/header";
import { useUserData } from "@/context/user-data-context";
import { Settings, Grid, Calendar, LogOut, Share2, LayoutGrid, Video, FileText } from "lucide-react";
import { createClient } from "@/utils/supabase/client";
import { useEffect, useState } from "react";
import { User } from "@supabase/supabase-js";
import { SettingsModal } from "@/components/modals/settings-modal";
import { EditProfileModal } from "@/components/modals/edit-profile-modal";
import { CreateStoryModal } from "@/components/stories/create-story-modal";
import { StoryViewer } from "@/components/stories/story-viewer";
import { useStories } from "@/context/stories-context";
import { useRouter } from "next/navigation";
import { getUserAvatar } from "@/utils/avatar-helpers";
import { ArtifactGallery } from "@/components/artifact-gallery";
import { ARTIFACTS } from "@/lib/artifacts";
import { Lock, CheckCircle, Flame, Triangle, Hexagon, Compass, Skull, Box, Shield, Book, Zap, Activity, BookOpen, Clock } from "lucide-react";

const ICON_MAP = {
    'Flame': Flame,
    'Triangle': Triangle,
    'Hexagon': Hexagon,
    'Compass': Compass,
    'Skull': Skull,
    'Box': Box,
    'Shield': Shield,
    'Book': Book,
    'Zap': Zap,
    'Activity': Activity,
    'BookOpen': BookOpen,
    'Clock': Clock
};

export default function ProfilePage() {
    const { consistencyScore, currentStreak, streakTier, streakStrength, tasks, records, profileStreakMode, calculateAverageStreak, getStreakForDate, defaultFilterTaskId, unlockedArtifacts } = useUserData();
    const { myStories, stories } = useStories();
    const [user, setUser] = useState<User | null>(null);
    const [profile, setProfile] = useState<any>(null);
    const [isSettingsOpen, setIsSettingsOpen] = useState(false);
    const [isEditProfileOpen, setIsEditProfileOpen] = useState(false);
    const [isCreateStoryOpen, setIsCreateStoryOpen] = useState(false);
    const [isArtifactGalleryOpen, setIsArtifactGalleryOpen] = useState(false);
    const [viewingStoryIndex, setViewingStoryIndex] = useState<number | null>(null);
    const [activeTab, setActiveTab] = useState<'artifacts' | 'streaks' | 'history' | 'notes'>('artifacts');
    const router = useRouter();

    const getUser = async () => {
        const supabase = createClient();
        const { data: { user } } = await supabase.auth.getUser();
        setUser(user);

        // Fetch profile data from profiles table
        if (user) {
            const { data: profileData } = await supabase
                .from('profiles')
                .select('*')
                .eq('id', user.id)
                .single();
            setProfile(profileData);
        }
    };

    useEffect(() => {
        getUser();
    }, []);

    const handleLogout = async () => {
        const supabase = createClient();
        await supabase.auth.signOut();
        router.push('/login');
    };

    // Derived Stats
    const allRecords = Object.values(records).flat();
    const totalEntries = allRecords.length;
    const historyDates = Object.keys(records).sort((a, b) => b.localeCompare(a));

    return (
        <div className="min-h-screen bg-black text-white font-[family-name:var(--font-geist-sans)] pb-20 md:pb-8">
            {/* Desktop only header */}
            <div className="hidden md:block">
                <Header />
            </div>

            <div className="max-w-4xl mx-auto md:pt-28 px-4 sm:px-6 lg:px-8">

                {/* Mobile-First Profile Header */}
                <div className="flex items-start gap-5 mb-6 pt-4">
                    {/* Profile Picture */}
                    <div className="relative flex-shrink-0">
                        <div
                            onClick={() => {
                                if (myStories.length > 0) {
                                    // Find the index of the first story by current user
                                    const index = stories.findIndex(s => s.user_id === user?.id);
                                    if (index !== -1) setViewingStoryIndex(index);
                                }
                            }}
                            className={`w-20 h-20 md:w-32 md:h-32 rounded-full p-[2px] ${myStories.length > 0 ? 'bg-gradient-to-tr from-yellow-500 via-red-500 to-purple-600 cursor-pointer hover:scale-105 transition-transform' : 'bg-zinc-800'}`}
                        >
                            <div className="w-full h-full rounded-full bg-black flex items-center justify-center overflow-hidden border-4 border-black">
                                <img
                                    src={user?.id ? getUserAvatar(profile?.avatar_url || user?.user_metadata?.avatar_url, profile?.gender, user.id) : '/avatars/default-male1.jpeg.jpeg'}
                                    alt="Profile"
                                    className="w-full h-full object-cover"
                                />
                            </div>
                        </div>
                    </div>

                    {/* Stats - Instagram Style */}
                    <div className="flex-1 flex flex-col gap-3">
                        {/* Username - Mobile visible, desktop hidden in this section */}
                        <div className="flex items-center gap-2 md:hidden pl-8">
                            <h1 className="text-base font-semibold">{profile?.full_name || user?.user_metadata?.full_name || user?.email?.split('@')[0] || "Initiate"}</h1>
                            {profile?.displayed_artifact_id && (() => {
                                const art = ARTIFACTS.find(a => a.id === profile.displayed_artifact_id);
                                if (!art) return null;
                                const Icon = ICON_MAP[art.icon as keyof typeof ICON_MAP] || Box;
                                return (
                                    <div className="w-5 h-5 rounded-full flex items-center justify-center bg-zinc-900 border border-zinc-800" style={{ boxShadow: `0 0 10px ${art.color}40` }}>
                                        <Icon className="w-3 h-3" style={{ color: art.color }} />
                                    </div>
                                );
                            })()}
                        </div>

                        {/* Username and action buttons - mobile hidden, shown on desktop */}
                        <div className="hidden md:flex items-center gap-4">
                            <h1 className="text-xl font-light tracking-wide">{profile?.full_name || user?.user_metadata?.full_name || user?.email?.split('@')[0] || "Initiate"}</h1>
                            <div className="flex gap-2">
                                <button
                                    onClick={() => setIsEditProfileOpen(true)}
                                    className="px-4 py-1.5 bg-zinc-800 hover:bg-zinc-700 rounded-lg text-sm font-semibold transition-colors"
                                >
                                    Edit Profile
                                </button>
                                <button
                                    onClick={() => setIsSettingsOpen(true)}
                                    className="p-2 bg-zinc-800 hover:bg-zinc-700 rounded-lg transition-colors"
                                >
                                    <Settings className="w-4 h-4" />
                                </button>
                                <button
                                    onClick={handleLogout}
                                    className="p-2 bg-zinc-800 hover:bg-red-900/50 hover:text-red-400 rounded-lg transition-colors"
                                    title="Log Out"
                                >
                                    <LogOut className="w-4 h-4" />
                                </button>
                            </div>
                        </div>

                        {/* Stats Row - horizontal on mobile */}
                        <div className="flex justify-around md:justify-start gap-6 md:gap-10">
                            <div className="text-center md:text-left">
                                <div className="font-bold text-base md:text-lg">{totalEntries}</div>
                                <div className="text-xs md:text-sm text-zinc-400">entries</div>
                            </div>
                            <div className="text-center md:text-left">
                                <div className="font-bold text-base md:text-lg">
                                    {profileStreakMode === 'combined' ? calculateAverageStreak() : getStreakForDate(new Date().toISOString().split('T')[0], defaultFilterTaskId)}
                                </div>
                                <div className="text-xs md:text-sm text-zinc-400">{profileStreakMode === 'combined' ? 'avg streak' : 'pinned streak'}</div>
                            </div>
                            <div className="text-center md:text-left">
                                <div className="font-bold text-base md:text-lg">{consistencyScore}%</div>
                                <div className="text-xs md:text-sm text-zinc-400">consistency</div>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Name and Bio - Mobile */}
                <div className="mb-4 md:hidden">
                    <h2 className="font-semibold text-sm mb-0.5">{profile?.full_name || user?.user_metadata?.full_name || user?.email?.split('@')[0] || "Initiate"}</h2>
                    <p className="text-sm text-zinc-300 whitespace-pre-wrap">
                        {profile?.bio || user?.user_metadata?.bio || ""}
                    </p>
                </div>

                {/* Desktop Bio */}
                <div className="hidden md:block mb-6">
                    <p className="text-sm text-zinc-300 whitespace-pre-wrap">
                        {profile?.bio || user?.user_metadata?.bio || ""}
                    </p>
                </div>

                {/* Action Buttons - Mobile Only */}
                <div className="flex gap-2 mb-6 md:hidden">
                    <button
                        onClick={() => setIsEditProfileOpen(true)}
                        className="flex-1 px-4 py-2 bg-zinc-800/80 backdrop-blur-md border border-white/10 hover:border-white/30 hover:bg-zinc-700/80 rounded-lg text-sm font-semibold transition-all active:scale-95"
                    >
                        Edit profile
                    </button>
                    <button
                        onClick={() => setIsArtifactGalleryOpen(true)}
                        className="flex-1 px-4 py-2 bg-zinc-800/80 backdrop-blur-md border border-white/10 hover:border-white/30 hover:bg-zinc-700/80 rounded-lg text-sm font-semibold transition-all active:scale-95 flex items-center justify-center gap-2"
                    >
                        <Box className="w-4 h-4" />
                        Open Vault
                    </button>
                    <button
                        onClick={() => setIsSettingsOpen(true)}
                        className="px-3 py-2 bg-zinc-800/80 backdrop-blur-md border border-white/10 hover:border-white/30 hover:bg-zinc-700/80 rounded-lg transition-all active:scale-95"
                    >
                        <Settings className="w-5 h-5" />
                    </button>
                </div>

                {/* Tab Navigation - Instagram Style with Icons */}
                <div className="flex border-t border-white/10 mb-1">
                    <button
                        onClick={() => setActiveTab('artifacts')}
                        className={`flex-1 flex items-center justify-center gap-2 py-3 md:py-4 text-xs font-semibold uppercase tracking-widest transition-colors relative ${activeTab === 'artifacts' ? 'text-white' : 'text-zinc-500 hover:text-white'}`}
                    >
                        <Hexagon className="w-5 h-5 md:w-4 md:h-4" />
                        <span className="hidden md:inline">Vault</span>
                        {activeTab === 'artifacts' && <div className="absolute top-0 left-0 right-0 h-[1px] bg-white" />}
                    </button>
                    <button
                        onClick={() => setActiveTab('streaks')}
                        className={`flex-1 flex items-center justify-center gap-2 py-3 md:py-4 text-xs font-semibold uppercase tracking-widest transition-colors relative ${activeTab === 'streaks' ? 'text-white' : 'text-zinc-500 hover:text-white'}`}
                    >
                        <Flame className="w-5 h-5 md:w-4 md:h-4" />
                        <span className="hidden md:inline">Streaks</span>
                        {activeTab === 'streaks' && <div className="absolute top-0 left-0 right-0 h-[1px] bg-white" />}
                    </button>
                    <button
                        onClick={() => setActiveTab('history')}
                        className={`flex-1 flex items-center justify-center gap-2 py-3 md:py-4 text-xs font-semibold uppercase tracking-widest transition-colors relative ${activeTab === 'history' ? 'text-white' : 'text-zinc-500 hover:text-white'}`}
                    >
                        <Calendar className="w-5 h-5 md:w-4 md:h-4" />
                        <span className="hidden md:inline">History</span>
                        {activeTab === 'history' && <div className="absolute top-0 left-0 right-0 h-[1px] bg-white" />}
                    </button>
                    <button
                        onClick={() => setActiveTab('notes')}
                        className={`flex-1 flex items-center justify-center gap-2 py-3 md:py-4 text-xs font-semibold uppercase tracking-widest transition-colors relative ${activeTab === 'notes' ? 'text-white' : 'text-zinc-500 hover:text-white'}`}
                    >
                        <FileText className="w-5 h-5 md:w-4 md:h-4" />
                        <span className="hidden md:inline">Notes</span>
                        {activeTab === 'notes' && <div className="absolute top-0 left-0 right-0 h-[1px] bg-white" />}
                    </button>
                </div>

                {/* Grid Content */}
                {activeTab === 'artifacts' && (
                    <div className="grid grid-cols-3 gap-2 md:gap-4 animate-[fadeIn_0.5s_ease-out]">
                        {ARTIFACTS.map((artifact) => {
                            const isUnlocked = unlockedArtifacts.includes(artifact.id);
                            const Icon = ICON_MAP[artifact.icon as keyof typeof ICON_MAP] || Box;

                            return (
                                <div
                                    key={artifact.id}
                                    className={`aspect-square relative group overflow-hidden rounded-xl border transition-all ${isUnlocked
                                        ? 'bg-zinc-900/50 border-white/10 hover:border-white/20 hover:bg-zinc-800/50 cursor-pointer'
                                        : 'bg-zinc-900/20 border-white/5 opacity-50 grayscale'
                                        }`}
                                    onClick={() => {
                                        if (isUnlocked) {
                                            // Optional: Open detail view or something
                                        }
                                    }}
                                >
                                    <div className="absolute inset-0 flex flex-col items-center justify-center p-2">
                                        <div
                                            className={`w-8 h-8 md:w-12 md:h-12 rounded-full flex items-center justify-center mb-1 md:mb-2 transition-transform group-hover:scale-110 ${isUnlocked ? 'bg-black/50 shadow-lg' : 'bg-white/5'
                                                }`}
                                            style={isUnlocked ? { boxShadow: `0 0 20px ${artifact.color}40`, color: artifact.color } : {}}
                                        >
                                            <Icon className="w-4 h-4 md:w-6 md:h-6" />
                                        </div>
                                        <span className={`text-[10px] md:text-xs font-bold text-center truncate w-full px-1 ${isUnlocked ? 'text-zinc-300' : 'text-zinc-600'}`}>
                                            {artifact.name}
                                        </span>
                                    </div>

                                    {/* Hover Overlay */}
                                    <div className="absolute inset-0 bg-black/90 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center p-3 text-center pointer-events-none backdrop-blur-sm">
                                        {isUnlocked ? (
                                            <>
                                                <span className="text-[10px] md:text-xs font-bold text-white mb-1">{artifact.name}</span>
                                                <span className="text-[9px] md:text-[10px] text-zinc-400 line-clamp-3 leading-tight">{artifact.description}</span>
                                            </>
                                        ) : (
                                            <>
                                                <Lock className="w-4 h-4 md:w-5 md:h-5 text-zinc-500 mb-1" />
                                                <span className="text-[9px] md:text-[10px] text-zinc-500 font-mono leading-tight">{artifact.condition}</span>
                                            </>
                                        )}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                )}

                {activeTab === 'streaks' && (
                    <div className="py-12 text-center animate-[fadeIn_0.5s_ease-out]">
                        <div className="inline-block p-6 rounded-full bg-zinc-900 mb-4">
                            <Flame className="w-12 h-12 text-zinc-700" />
                        </div>
                        <h3 className="text-xl font-bold mb-2">Active Streaks</h3>
                        <p className="text-zinc-500 text-sm mb-8">Detailed streak visualization coming soon.</p>
                        <div className="grid grid-cols-2 gap-4 max-w-sm mx-auto">
                            <div className="bg-zinc-900/50 p-6 rounded-xl col-span-2">
                                <div className="text-3xl font-bold text-white mb-1">{totalEntries}</div>
                                <div className="text-xs text-zinc-500 uppercase tracking-widest">Total Entries</div>
                            </div>
                            <div className="bg-zinc-900/50 p-6 rounded-xl">
                                <div className="text-3xl font-bold text-white mb-1">
                                    {profileStreakMode === 'combined' ? calculateAverageStreak() : getStreakForDate(new Date().toISOString().split('T')[0], defaultFilterTaskId)}
                                </div>
                                <div className="text-xs text-zinc-500 uppercase tracking-widest">{profileStreakMode === 'combined' ? 'Avg Streak' : 'Pinned'}</div>
                            </div>
                            <div className="bg-zinc-900/50 p-6 rounded-xl">
                                <div className="text-3xl font-bold text-white mb-1">{consistencyScore}%</div>
                                <div className="text-xs text-zinc-500 uppercase tracking-widest">Consistency</div>
                            </div>
                        </div>
                    </div>
                )}

                {activeTab === 'history' && (
                    <div className="space-y-6 animate-[fadeIn_0.5s_ease-out]">
                        {historyDates.length > 0 ? historyDates.slice(0, 30).map(date => {
                            const dayRecords = records[date].sort((a, b) => {
                                if (a.timestamp && b.timestamp) return new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime();
                                return 0;
                            });

                            return (
                                <div key={date} className="bg-zinc-900/30 rounded-xl overflow-hidden border border-white/5">
                                    <div className="px-4 py-3 bg-white/5 flex items-center justify-between border-b border-white/5">
                                        <div className="font-semibold text-white text-sm">
                                            {new Date(date).toLocaleDateString(undefined, { weekday: 'long', month: 'long', day: 'numeric' })}
                                        </div>
                                        <div className="text-xs text-zinc-500 font-mono">
                                            {dayRecords.length} entries
                                        </div>
                                    </div>

                                    <div className="divide-y divide-white/5">
                                        {dayRecords.map((record, i) => {
                                            const task = tasks.find(t => t.id === record.taskId);
                                            const timeStr = record.timestamp
                                                ? new Date(record.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
                                                : 'Completed';

                                            return (
                                                <div key={i} className="flex items-center gap-4 p-4 hover:bg-white/5 transition-colors">
                                                    {/* Task Color Indicator */}
                                                    <div
                                                        className="w-2 h-10 rounded-full shrink-0"
                                                        style={{ backgroundColor: task?.color || '#555' }}
                                                    />

                                                    <div className="flex-1 min-w-0">
                                                        <div className="flex items-center justify-between mb-1">
                                                            <h4 className="font-medium text-white truncate pr-2">
                                                                {task?.name || 'Unknown Task'}
                                                            </h4>
                                                            <span className="text-xs text-zinc-500 font-mono shrink-0">
                                                                {timeStr}
                                                            </span>
                                                        </div>

                                                        <div className="flex items-center gap-3 text-xs text-zinc-400">
                                                            {record.value !== undefined && (
                                                                <span className="bg-zinc-800 px-2 py-0.5 rounded text-zinc-300">
                                                                    Value: {record.value} {task?.metricConfig?.unit}
                                                                </span>
                                                            )}
                                                            {record.intensity !== null && record.intensity !== undefined && (
                                                                <div className="flex items-center gap-1">
                                                                    <Flame className="w-3 h-3 text-orange-500" />
                                                                    <span>Intensity: {record.intensity}</span>
                                                                </div>
                                                            )}
                                                            {!record.value && record.intensity === null && (
                                                                <span>Task Completed</span>
                                                            )}
                                                        </div>
                                                    </div>
                                                </div>
                                            );
                                        })}
                                    </div>
                                </div>
                            );
                        }) : (
                            <div className="text-center py-12 text-zinc-500 text-sm">
                                No history recorded yet. The void awaits your actions.
                            </div>
                        )}
                    </div>
                )}

                {activeTab === 'notes' && (
                    <div className="py-12 text-center animate-[fadeIn_0.5s_ease-out]">
                        <div className="inline-block p-6 rounded-full bg-zinc-900 mb-4">
                            <FileText className="w-12 h-12 text-zinc-700" />
                        </div>
                        <h3 className="text-xl font-bold mb-2">Notes</h3>
                        <p className="text-zinc-500 text-sm">Your personal notes will appear here.</p>
                    </div>
                )}

            </div>

            <SettingsModal isOpen={isSettingsOpen} onClose={() => setIsSettingsOpen(false)} />

            <EditProfileModal
                isOpen={isEditProfileOpen}
                onClose={() => setIsEditProfileOpen(false)}
                user={user}
                onUpdate={getUser}
            />

            <CreateStoryModal
                isOpen={isCreateStoryOpen}
                onClose={() => setIsCreateStoryOpen(false)}
            />

            {viewingStoryIndex !== null && (
                <StoryViewer
                    initialStoryIndex={viewingStoryIndex}
                    stories={stories}
                    onClose={() => setViewingStoryIndex(null)}
                />
            )}

            <ArtifactGallery isOpen={isArtifactGalleryOpen} onClose={() => setIsArtifactGalleryOpen(false)} />
        </div>
    );
}

"use client";

import { useEffect, useState } from 'react';
import { use } from 'react';
import { Header } from '@/components/header';
import { Heatmap } from '@/components/heatmap';
import { createClient } from '@/utils/supabase/client';
import { ArrowLeft, User } from 'lucide-react';
import { useRouter } from 'next/navigation';
import { getUserAvatar } from '@/utils/avatar-helpers';
import { FriendButton } from '@/components/friend-button';

interface PublicProfileData {
    id: string;
    username: string | null;
    full_name: string | null;
    avatar_url: string | null;
    bio: string | null;
    gender: string | null;
}

export default function PublicProfilePage({ params }: { params: Promise<{ username: string }> }) {
    const resolvedParams = use(params);
    const username = resolvedParams.username;
    const router = useRouter();
    const supabase = createClient();

    const [profile, setProfile] = useState<PublicProfileData | null>(null);
    const [currentUser, setCurrentUser] = useState<string | null>(null);
    const [isLoading, setIsLoading] = useState(true);
    const [notFound, setNotFound] = useState(false);
    const [stats, setStats] = useState({ totalEntries: 0, currentStreak: 0, consistencyScore: 0 });

    useEffect(() => {
        const getCurrentUser = async () => {
            const { data: { user } } = await supabase.auth.getUser();
            setCurrentUser(user?.id || null);
        };
        getCurrentUser();
    }, []);

    useEffect(() => {
        const fetchPublicProfile = async () => {
            setIsLoading(true);
            try {
                // Try to fetch profile by username first, then by ID if username fails
                let profileData = null;

                // First try username
                const { data: usernameData, error: usernameError } = await supabase
                    .from('profiles')
                    .select('*')
                    .eq('username', username)
                    .maybeSingle();

                if (usernameData) {
                    profileData = usernameData;
                } else {
                    // If not found by username, try by ID
                    const { data: idData, error: idError } = await supabase
                        .from('profiles')
                        .select('*')
                        .eq('id', username)
                        .maybeSingle();

                    if (idData) {
                        profileData = idData;
                    }
                }

                if (!profileData) {
                    setNotFound(true);
                    setIsLoading(false);
                    return;
                }

                setProfile(profileData);

                // Fetch user's records to calculate stats
                const { data: records } = await supabase
                    .from('records')
                    .select('*')
                    .eq('user_id', profileData.id)
                    .order('date', { ascending: false });

                if (records) {
                    const totalEntries = records.length;

                    // Calculate streak
                    let streak = 0;
                    const today = new Date().toISOString().split('T')[0];
                    const uniqueDates = [...new Set(records.map(r => r.date))].sort().reverse();

                    if (uniqueDates.length > 0 && uniqueDates[0] === today) {
                        streak = 1;
                        const currentDate = new Date(today);
                        for (let i = 1; i < uniqueDates.length; i++) {
                            currentDate.setDate(currentDate.getDate() - 1);
                            const expectedDate = currentDate.toISOString().split('T')[0];
                            if (uniqueDates[i] === expectedDate) {
                                streak++;
                            } else {
                                break;
                            }
                        }
                    }

                    // Calculate consistency (last 30 days)
                    const thirtyDaysAgo = new Date();
                    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
                    const recentRecords = records.filter(r => new Date(r.date) >= thirtyDaysAgo);
                    const daysWithRecords = new Set(recentRecords.map(r => r.date)).size;
                    const consistencyScore = Math.round((daysWithRecords / 30) * 100);

                    setStats({ totalEntries, currentStreak: streak, consistencyScore });
                }

            } catch (err) {
                console.error('Error fetching public profile:', err);
                setNotFound(true);
            } finally {
                setIsLoading(false);
            }
        };

        fetchPublicProfile();
    }, [username]);

    if (isLoading) {
        return (
            <div className="min-h-screen flex flex-col bg-black text-white">
                <Header />
                <div className="flex-1 flex items-center justify-center">
                    <div className="inline-block w-8 h-8 border-2 border-zinc-600 border-t-white rounded-full animate-spin" />
                </div>
            </div>
        );
    }

    if (notFound || !profile) {
        return (
            <div className="min-h-screen flex flex-col bg-black text-white">
                <Header />
                <div className="flex-1 flex flex-col items-center justify-center p-6">
                    <User className="w-16 h-16 text-zinc-600 mb-4" />
                    <h1 className="text-2xl font-bold mb-2">User Not Found</h1>
                    <p className="text-zinc-500 mb-6">@{username} doesn't exist</p>
                    <button
                        onClick={() => router.back()}
                        className="px-6 py-3 bg-white text-black rounded-lg hover:bg-zinc-200 transition-colors flex items-center gap-2"
                    >
                        <ArrowLeft className="w-4 h-4" />
                        Go Back
                    </button>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen flex flex-col bg-black text-white">
            <Header />

            <div className="max-w-4xl mx-auto w-full px-4 sm:px-6 lg:px-8 pt-8">
                {/* Back Button */}
                <button
                    onClick={() => router.back()}
                    className="flex items-center gap-2 text-zinc-400 hover:text-white transition-colors mb-6"
                >
                    <ArrowLeft className="w-4 h-4" />
                    Back
                </button>

                {/* Profile Header */}
                <div className="flex items-start gap-6 mb-8">
                    {/* Avatar */}
                    <div className="w-24 h-24 md:w-32 md:h-32 rounded-full bg-gradient-to-br from-zinc-700 to-zinc-900 border-2 border-white/10 overflow-hidden flex-shrink-0">
                        <img
                            src={getUserAvatar(profile.avatar_url, profile.gender, profile.id)}
                            alt={profile.full_name || 'User'}
                            className="w-full h-full object-cover"
                        />
                    </div>

                    {/* Info */}
                    <div className="flex-1">
                        <h1 className="text-2xl md:text-3xl font-bold mb-1">{profile.full_name || profile.username || 'Anonymous'}</h1>
                        {profile.username && <p className="text-zinc-400 mb-3">@{profile.username}</p>}
                        {profile.bio && <p className="text-zinc-300 text-sm md:text-base">{profile.bio}</p>}
                    </div>
                </div>

                {/* Stats */}
                <div className="grid grid-cols-3 gap-4 mb-8 p-6 bg-white/5 border border-white/10 rounded-2xl">
                    <div className="text-center">
                        <div className="text-2xl md:text-3xl font-bold text-white">{stats.totalEntries}</div>
                        <div className="text-xs md:text-sm text-zinc-400">Entries</div>
                    </div>
                    <div className="text-center">
                        <div className="text-2xl md:text-3xl font-bold text-white">{stats.currentStreak}</div>
                        <div className="text-xs md:text-sm text-zinc-400">Streak</div>
                    </div>
                    <div className="text-center">
                        <div className="text-2xl md:text-3xl font-bold text-white">{stats.consistencyScore}%</div>
                        <div className="text-xs md:text-sm text-zinc-400">Consistency</div>
                    </div>
                </div>

                {/* Friend Actions */}
                {currentUser && profile && (
                    <div className="mb-8 flex justify-center">
                        <FriendButton userId={profile.id} currentUserId={currentUser} />
                    </div>
                )}

                {/* Activity Heatmap */}
                <div className="mb-8">
                    <h2 className="text-xl font-bold mb-4">Activity</h2>
                    <Heatmap />
                </div>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { Header } from "@/components/header";
import { RecommendedReel } from "@/components/world/recommended-reel";
import { WorldFeedCard } from "@/components/world/world-feed-card";
import { SearchModal } from "@/components/modals/search-modal";
import { FriendRequestsModal } from "@/components/modals/friend-requests-modal";
import { createClient } from "@/utils/supabase/client";
import { Bell, Search, Sparkles, Loader2 } from "lucide-react";
import { WorldUser, FeedPost } from "@/data/mock-world"; // Keeping interfaces, ignoring mock data
import { DEFAULT_FACTIONS } from "@/context/user-data-context";
import { useMessageNotifications } from "@/context/message-notification-context";

export default function WorldPage() {
    const supabase = createClient();
    const [users, setUsers] = useState<WorldUser[]>([]);
    const [posts, setPosts] = useState<FeedPost[]>([]);
    const [factionsPower, setFactionsPower] = useState<{ name: string, sigil: string, power: number, primaryColor: string }[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [currentUser, setCurrentUser] = useState<any>(null);
    const [isSearchModalOpen, setIsSearchModalOpen] = useState(false);
    const [isFriendRequestsModalOpen, setIsFriendRequestsModalOpen] = useState(false);
    const { friendRequestCount } = useMessageNotifications();

    useEffect(() => {
        const fetchData = async () => {
            setIsLoading(true);

            // 1. Get Current User
            const { data: { user } } = await supabase.auth.getUser();
            setCurrentUser(user);

            // 2. Fetch Profiles for Reel (Real Users)
            const { data: profiles } = await supabase
                .from('profiles')
                .select('*')
                .limit(20);

            if (profiles) {
                const mappedUsers: WorldUser[] = profiles.map(p => ({
                    id: p.id,
                    name: p.full_name || 'Anonymous',
                    handle: p.username ? `@${p.username}` : '@user',
                    avatar: p.avatar_url || `https://api.dicebear.com/7.x/shapes/svg?seed=${p.id}`,
                    // Mocking social stats as they don't exist in DB yet
                    followers: '-',
                    following: '-',
                    creations: '-',
                    bio: p.bio || '',
                    isLive: false
                }));
                setUsers(mappedUsers);
            }

            // 3. Fetch Recent Records for Feed (Real Activity)
            const { data: records } = await supabase
                .from('records')
                .select(`
                    *,
                    tasks (name, color)
                `)
                .order('timestamp', { ascending: false })
                .limit(20);

            if (records) {
                const mappedPosts: FeedPost[] = records.map(r => {
                    // Try to find profile in fetched profiles
                    const author = profiles?.find(p => p.id === r.user_id) || {
                        id: r.user_id,
                        full_name: 'Unknown',
                        username: 'unknown',
                        avatar_url: null
                    };

                    return {
                        id: r.id,
                        user: {
                            id: author.id,
                            name: author.full_name || 'Anonymous',
                            handle: author.username ? `@${author.username}` : '@user',
                            avatar: author.avatar_url || `https://api.dicebear.com/7.x/shapes/svg?seed=${author.id}`,
                            followers: '',
                            following: '',
                            creations: '',
                            bio: ''
                        },
                        title: r.tasks?.name || 'Unknown Task',
                        description: `Logged with intensity ${r.intensity}`,
                        backgroundImage: `https://ui-avatars.com/api/?name=${r.tasks?.name || 'Task'}&background=random&size=800`,
                        stats: {
                            likes: r.value ? `${r.value}` : '-',
                            isHot: (r.intensity || 0) > 3
                        }
                    };
                });
                setPosts(mappedPosts);
            }

            // 4. Fetch Faction Power (Leaderboard)
            const { data: factions } = await supabase.from('factions').select('*');
            if (factions && profiles) {
                const power = factions.map(f => {
                    const houseMembers = profiles.filter(p => p.faction_id === f.id);
                    const totalPower = houseMembers.reduce((sum, p) => sum + (p.activity_points || 0), 0);

                    // Reconcile with local config for high-quality sigils
                    const localMatch = DEFAULT_FACTIONS.find(df => df.name === f.name);

                    return {
                        name: f.name,
                        sigil: localMatch ? localMatch.sigilUrl : f.sigil_url,
                        power: totalPower,
                        primaryColor: localMatch ? localMatch.primaryColor : f.primary_color
                    };
                }).sort((a, b) => b.power - a.power);
                setFactionsPower(power);
            }

            setIsLoading(false);
        };

        fetchData();
    }, []);

    return (
        <div className="min-h-screen flex flex-col bg-black text-white font-sans selection:bg-purple-500/30">
            {/* Custom Header for World Page (Adverse Style) */}
            <div className="fixed top-0 left-0 right-0 z-50 bg-black/80 backdrop-blur-xl border-b border-white/5 hidden md:block">
                <div className="flex items-center justify-between px-6 py-4 max-w-md mx-auto md:max-w-4xl">
                    <div className="flex items-center gap-2">
                        <Sparkles className="w-6 h-6 text-transparent bg-clip-text bg-gradient-to-tr from-yellow-400 to-purple-600 fill-current" />
                        <span className="text-lg font-bold tracking-tight">Diogenes</span>
                    </div>
                    <div className="flex items-center gap-4">
                        <button
                            onClick={() => setIsSearchModalOpen(true)}
                            className="relative text-zinc-400 hover:text-white transition-colors"
                        >
                            <Search className="w-6 h-6" />
                        </button>
                        <button
                            onClick={() => setIsFriendRequestsModalOpen(true)}
                            className="relative text-zinc-400 hover:text-white transition-colors"
                        >
                            <Bell className="w-6 h-6" />
                            {friendRequestCount > 0 && (
                                <span className="absolute -top-1 -right-1 w-5 h-5 bg-purple-500 text-white text-[10px] font-bold rounded-full flex items-center justify-center animate-pulse">
                                    {friendRequestCount > 9 ? '9+' : friendRequestCount}
                                </span>
                            )}
                        </button>
                        {currentUser && (
                            <div className="w-8 h-8 rounded-full bg-gradient-to-br from-zinc-700 to-zinc-900 border border-white/20 overflow-hidden">
                                <img
                                    src={currentUser.user_metadata?.avatar_url || `https://api.dicebear.com/7.x/shapes/svg?seed=${currentUser.id}`}
                                    alt="Profile"
                                    className="w-full h-full object-cover"
                                />
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* Main Content */}
            <main className="flex-1 pt-24 pb-24 px-6 md:px-0 max-w-md mx-auto md:max-w-4xl w-full space-y-10 animate-in fade-in duration-700">

                {isLoading ? (
                    <div className="flex items-center justify-center py-20">
                        <Loader2 className="w-8 h-8 text-purple-500 animate-spin" />
                    </div>
                ) : (
                    <>
                        {/* Recommended Reel (Stories) */}
                        <section>
                            <RecommendedReel />
                        </section>

                        {/* Great Houses Leaderboard */}
                        <section className="space-y-4">
                            <div className="flex items-center justify-between">
                                <h3 className="text-zinc-500 text-xs font-medium tracking-wide uppercase">Great Houses of the Realm</h3>
                                <div className="flex items-center gap-1.5 px-2 py-1 bg-yellow-500/10 border border-yellow-500/20 rounded-md">
                                    <Sparkles className="w-3 h-3 text-yellow-500" />
                                    <span className="text-[10px] font-bold text-yellow-500 uppercase">Supremacy</span>
                                </div>
                            </div>

                            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                                {factionsPower.slice(0, 4).map((house, index) => (
                                    <div
                                        key={house.name}
                                        className="relative group p-4 rounded-3xl bg-zinc-900/50 border border-white/5 hover:border-white/10 transition-all overflow-hidden"
                                    >
                                        <div
                                            className="absolute -top-12 -right-12 w-24 h-24 rounded-full blur-[40px] opacity-10 group-hover:opacity-20 transition-opacity"
                                            style={{ backgroundColor: house.primaryColor }}
                                        />
                                        <div className="relative flex flex-col items-center text-center gap-3">
                                            <div className="w-12 h-12 rounded-xl bg-black border border-white/5 flex items-center justify-center p-1.5 overflow-hidden">
                                                <img src={house.sigil} alt={house.name} className="w-full h-full object-cover rounded-lg" />
                                            </div>
                                            <div>
                                                <div className="text-[10px] font-bold text-zinc-500 uppercase tracking-wider">{house.name.replace('House ', '')}</div>
                                                <div className="text-lg font-black text-white">{house.power} <span className="text-[10px] text-zinc-500 font-medium">PWR</span></div>
                                            </div>
                                            {index === 0 && (
                                                <div className="absolute -top-2 -left-2 bg-yellow-500 text-black text-[8px] font-black px-1.5 py-0.5 rounded-full uppercase tracking-tighter">Ruling</div>
                                            )}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </section>

                        {/* Feed Section */}
                        <section className="space-y-4">
                            <div className="flex items-center justify-between">
                                <h3 className="text-zinc-500 text-xs font-medium tracking-wide">Protocol Live Feed</h3>
                                <span className="text-xs font-bold text-white bg-white/10 px-2 py-1 rounded-md">
                                    {posts.length} Active
                                </span>
                            </div>

                            {posts.length > 0 ? (
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    {posts.map((post, index) => (
                                        <div
                                            key={post.id}
                                            className="animate-in fade-in slide-in-from-bottom-8 fill-mode-backwards"
                                            style={{ animationDelay: `${index * 150}ms` }}
                                        >
                                            <WorldFeedCard post={post} />
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <div className="py-20 text-center border border-dashed border-white/10 rounded-3xl bg-white/5">
                                    <h4 className="text-zinc-500 font-medium mb-2">The Ether is Silent</h4>
                                    <p className="text-zinc-600 text-sm">Be the first to create a ripple.</p>
                                </div>
                            )}
                        </section>
                    </>
                )}

                {/* Discovery / Popular Section (Bottom) */}
                <section className="space-y-4 pt-4 border-t border-white/5">
                    <h3 className="text-zinc-500 text-xs font-medium tracking-wide">Popular Protocols</h3>
                    <div className="relative h-48 rounded-2xl overflow-hidden group cursor-pointer">
                        <img
                            src="https://images.unsplash.com/photo-1451187580459-43490279c0fa?q=80&w=800&auto=format&fit=crop"
                            alt="Universe"
                            className="w-full h-full object-cover opacity-60 group-hover:opacity-80 transition-opacity duration-500 group-hover:scale-105"
                        />
                        <div className="absolute inset-0 flex items-center justify-center">
                            <div className="bg-black/50 backdrop-blur-md px-6 py-3 rounded-full border border-white/10">
                                <span className="text-sm font-bold text-white tracking-widest uppercase">Explore Deep Space</span>
                            </div>
                        </div>
                    </div>
                </section>

            </main>

            <SearchModal
                isOpen={isSearchModalOpen}
                onClose={() => setIsSearchModalOpen(false)}
            />
            <FriendRequestsModal
                isOpen={isFriendRequestsModalOpen}
                onClose={() => setIsFriendRequestsModalOpen(false)}
                currentUserId={currentUser?.id}
            />
        </div>
    );
}

"use client";

import { useUserData } from "@/context/user-data-context";
import { CloudRain, Sun, Zap, Wind } from "lucide-react";

export function CitadelVisualizer() {
    const { consistencyScore, streakTier, streakStatus } = useUserData();

    // Visual Logic - Use percentages for responsive heights
    const wallHeightPercent = Math.max(20, consistencyScore); // 20-100%
    const towerCount = streakTier === 'committed' ? 4 : streakTier === 'habit' ? 2 : 0;

    // Weather Logic
    const isStormy = streakStatus === 'at-risk';
    const isLost = streakStatus === 'lost';

    return (
        <div className={`relative w-full h-full flex flex-col items-center justify-end overflow-hidden transition-colors duration-1000 
            ${isLost ? 'bg-zinc-950' : isStormy ? 'bg-zinc-900' : 'bg-gradient-to-t from-zinc-900 to-zinc-800'}
        `}>

            {/* SKY / ATMOSPHERE */}
            <div className="absolute inset-0 z-0 pointer-events-none">
                {isStormy && (
                    <>
                        <div className="absolute top-10 right-20 animate-pulse text-yellow-500/20"><Zap size={200} /></div>
                        <div className="absolute top-0 w-full h-full bg-black/40" />
                        <div className="rain-container absolute inset-0 opacity-30" />
                    </>
                )}
                {!isStormy && !isLost && (
                    <div className="absolute top-20 left-1/2 -translate-x-1/2 w-96 h-96 bg-orange-500/10 rounded-full blur-3xl animate-[pulse-slow_8s_ease-in-out_infinite]" />
                )}
                {isLost && (
                    <div className="absolute inset-0 bg-red-900/10 z-10" />
                )}
            </div>

            {/* FORTRESS CONTAINER */}
            <div className="relative z-10 w-full max-w-2xl px-4 md:px-8 flex items-end justify-center gap-1 perspective-1000 h-[60%]">

                {/* Left Tower (Habit Tier) */}
                {towerCount >= 2 && (
                    <div className="w-12 md:w-16 bg-zinc-800 border-2 border-zinc-700 relative animate-in slide-in-from-bottom duration-1000" style={{ height: `${wallHeightPercent * 0.6}%` }}>
                        <div className="absolute -top-6 md:-top-8 left-0 w-full h-6 md:h-8 bg-zinc-900 border-2 border-zinc-700 flex justify-between px-1">
                            <div className="w-1.5 md:w-2 h-3 md:h-4 bg-black/50" />
                            <div className="w-1.5 md:w-2 h-3 md:h-4 bg-black/50" />
                            <div className="w-1.5 md:w-2 h-3 md:h-4 bg-black/50" />
                        </div>
                        {/* Lit Window */}
                        <div className="absolute top-[20%] left-1/2 -translate-x-1/2 w-3 md:w-4 h-6 md:h-8 bg-yellow-500/50 blur-[2px] rounded-t-full animate-pulse" />
                    </div>
                )}

                {/* Main Wall */}
                <div
                    className="flex-1 bg-zinc-900/80 backdrop-blur-sm border-2 border-zinc-700 relative transition-all duration-1000 ease-in-out group hover:bg-zinc-800"
                    style={{ height: `${wallHeightPercent}%` }}
                >
                    {/* Battlements */}
                    <div className="absolute -top-3 md:-top-4 w-full h-3 md:h-4 flex justify-between px-1 md:px-2">
                        {Array.from({ length: 6 }).map((_, i) => (
                            <div key={i} className="w-3 md:w-4 h-3 md:h-4 bg-zinc-900 border-x-2 border-t-2 border-zinc-700" />
                        ))}
                    </div>

                    {/* Gate */}
                    <div className="absolute bottom-0 left-1/2 -translate-x-1/2 w-16 md:w-24 h-20 md:h-32 bg-zinc-950 border-x-2 border-t-2 border-zinc-600 rounded-t-full flex items-end justify-center overflow-hidden">
                        <div className="w-full h-full bg-[linear-gradient(45deg,transparent_25%,rgba(0,0,0,0.8)_25%,rgba(0,0,0,0.8)_50%,transparent_50%,transparent_75%,rgba(0,0,0,0.8)_75%,rgba(0,0,0,0.8)_100%)] bg-[length:10px_10px]" />
                        {streakStatus === 'safe' && <div className="absolute bottom-0 w-full h-1 bg-yellow-500 shadow-[0_0_20px_rgba(234,179,8,0.5)]" />}
                    </div>

                    {/* Stats Display on Hover/Touch */}
                    <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                        <span className="bg-black/80 px-3 py-1 rounded text-xs font-mono border border-white/20">
                            Fortitude: {consistencyScore}%
                        </span>
                    </div>
                </div>

                {/* Right Tower (Habit + Committed) */}
                {towerCount >= 2 && (
                    <div className="w-12 md:w-16 bg-zinc-800 border-2 border-zinc-700 relative animate-in slide-in-from-bottom duration-1000 delay-100" style={{ height: `${wallHeightPercent * 0.6}%` }}>
                        <div className="absolute -top-6 md:-top-8 left-0 w-full h-6 md:h-8 bg-zinc-900 border-2 border-zinc-700 flex justify-between px-1">
                            <div className="w-1.5 md:w-2 h-3 md:h-4 bg-black/50" />
                            <div className="w-1.5 md:w-2 h-3 md:h-4 bg-black/50" />
                            <div className="w-1.5 md:w-2 h-3 md:h-4 bg-black/50" />
                        </div>
                        {/* Lit Window */}
                        <div className="absolute top-[20%] left-1/2 -translate-x-1/2 w-3 md:w-4 h-6 md:h-8 bg-yellow-500/50 blur-[2px] rounded-t-full animate-pulse delay-500" />
                    </div>
                )}

                {/* Keep (Committed Tier) */}
                {towerCount >= 4 && (
                    <div className="absolute bottom-[100%] z-[-1] w-32 md:w-40 bg-zinc-800 border-2 border-zinc-600 animate-in slide-in-from-bottom duration-1000 delay-200 h-[40%] max-h-[150px]">
                        <div className="absolute -top-10 left-1/2 -translate-x-1/2 w-full h-10 bg-zinc-900 border-2 border-zinc-600 flex justify-around items-end">
                            <div className="w-4 h-6 bg-black/50" />
                            <div className="w-4 h-6 bg-black/50" />
                            <div className="w-4 h-6 bg-black/50" />
                        </div>
                        {/* Banner */}
                        <div className="absolute -top-24 left-1/2 -translate-x-1/2 flex flex-col items-center">
                            <div className="w-1 h-14 bg-zinc-400" />
                            <div className="w-12 h-8 bg-blue-600 animate-[wave_3s_ease-in-out_infinite] origin-left rounded-tr-lg rounded-br-lg opacity-80" />
                        </div>
                    </div>
                )}

            </div>

            {/* GROUND */}
            <div className="w-full h-20 md:h-32 bg-black border-t border-white/10 relative z-20">
                <div className="absolute top-0 w-full h-4 bg-gradient-to-b from-black/50 to-transparent" />
            </div>
        </div>
    );
}

