      <NightsWatchModal isOpen={isWatchModalOpen} onClose={() => setIsWatchModalOpen(false)} />
      <SearchModal isOpen={isSearchModalOpen} onClose={() => setIsSearchModalOpen(false)} />
      <FriendRequestsModal
        isOpen={isFriendRequestsModalOpen}
        onClose={() => setIsFriendRequestsModalOpen(false)}
        currentUserId={user?.id || ''}
      />
      <DailyReviewModal
        isOpen={isDailyReviewModalOpen}
        onClose={() => setIsDailyReviewModalOpen(false)}
      />
      <FactionPickerModal isOpen={isFactionModalOpen} onClose={() => setIsFactionModalOpen(false)} />
      <InvestmentModal isOpen={isInvestmentModalOpen} onClose={() => setIsInvestmentModalOpen(false)} />
    </>
  );
}

"use client";

import { useState, useEffect, useRef } from 'react';
import { Calendar as CalendarIcon } from 'lucide-react';
import { useUserData, Record } from '@/context/user-data-context';
import { LogActivityModal } from './modals/log-activity-modal';
import { format, setYear, setMonth, setDate, getDay, getDaysInMonth, startOfYear } from 'date-fns';

export function Heatmap() {
    const { records, tasks, activeFilterTaskId } = useUserData();
    const [selectedDate, setSelectedDate] = useState<string | null>(null);
    const scrollContainerRef = useRef<HTMLDivElement>(null);
    const currentMonthRef = useRef<HTMLDivElement>(null);

    // Current Year 2026 Logic
    const currentYear = 2026;
    const currentMonth = new Date().getMonth(); // 0-11

    // Generate months data dynamically for 2026
    const months = Array.from({ length: 12 }, (_, monthIndex) => {
        const date = new Date(currentYear, monthIndex, 1);
        return {
            name: format(date, 'MMM'),
            days: getDaysInMonth(date),
            startDay: getDay(date), // 0 = Sunday
            monthIndex: monthIndex
        };
    });

    // Get today's date string YYYY-MM-DD
    const today = new Date();
    const todayStr = `${today.getFullYear()}-${String(today.getMonth() + 1).padStart(2, '0')}-${String(today.getDate()).padStart(2, '0')}`;

    // Auto-scroll to current month on mount
    useEffect(() => {
        if (currentMonthRef.current && scrollContainerRef.current) {
            const container = scrollContainerRef.current;
            const currentMonthElement = currentMonthRef.current;

            // Calculate scroll position to center the current month
            const containerWidth = container.clientWidth;
            const elementLeft = currentMonthElement.offsetLeft;
            const elementWidth = currentMonthElement.clientWidth;

            // Center the current month
            const scrollPosition = elementLeft - (containerWidth / 2) + (elementWidth / 2);

            // Smooth scroll to position
            container.scrollTo({
                left: scrollPosition,
                behavior: 'smooth'
            });
        }
    }, []);

    const getDayColor = (dateStr: string) => {
        const dayRecords = records[dateStr];
        if (!dayRecords || dayRecords.length === 0) return null;

        // FILTER LOGIC:
        // If a filter is active, only consider records for that task.
        // If filtered list is empty, return null (gray).
        let filteredRecords = dayRecords;
        if (activeFilterTaskId) {
            filteredRecords = dayRecords.filter(r => r.taskId === activeFilterTaskId);
        }

        if (filteredRecords.length === 0) return null;

        // Visualizing the last added record for now, or could be a mix
        // For simplicity, let's take the last record of the filtered set
        const lastRecord = filteredRecords[filteredRecords.length - 1];
        const task = tasks.find(t => t.id === lastRecord.taskId);

        if (!task) return null;

        const intensity = lastRecord.intensity || 0; // 0 if null (standard)

        // Intensity Logic for Glow
        // Instead of fading out the color (opacity), let's keep the color vibrant
        // and change the strength of the GLOW.

        let glowStrength = 0;
        let opacity = 1;

        if (intensity === 0) {
            // Standard completed (no specific intensity)
            glowStrength = 15; // Moderate glow
            opacity = 1;
        } else {
            // Scale glow with intensity
            // 1: Subtle
            // 4: Super bright neon
            glowStrength = 5 + (intensity * 8);
            opacity = 0.6 + (intensity * 0.1);
        }

        return {
            color: task.color,
            boxShadow: `0 0 ${glowStrength}px ${task.color}, 0 0 ${glowStrength * 2}px ${task.color}40`,
            opacity
        };
    };

    return (
        <div className="space-y-4 md:space-y-6">
            {/* Scrollable Container with auto-scroll to current month */}
            <div
                ref={scrollContainerRef}
                className="flex gap-4 md:gap-6 overflow-x-auto pb-4 scrollbar-thin scrollbar-thumb-muted scrollbar-track-transparent -mx-4 px-4 md:mx-0 md:px-0"
            >
                {months.map((month) => (
                    <div
                        key={month.name}
                        ref={month.monthIndex === currentMonth ? currentMonthRef : null}
                        className="flex-none"
                    >
                        <div className="text-center text-xs md:text-sm text-muted-foreground font-medium mb-2 md:mb-3">{month.name}</div>

                        {/* Calendar grid with proper alignment */}
                        <div className="grid grid-cols-7 gap-1 md:gap-1.5">
                            {/* Add empty boxes for offset (days before the 1st) */}
                            {/* Adjustment: getDay returns 0 for Sunday. If we want Mon start, we need to shift. 
                                Let's assume Standard JS getDay: 0=Sun, 1=Mon... 6=Sat.
                                If UI expects Mon=0, Tue=1.. Sun=6.
                                
                                JS: Sun=0, Mon=1, Tue=2, Wed=3, Thu=4, Fri=5, Sat=6
                                UI Target: Mon=0, Tue=1 ... Sun=6
                                Conversion: (day + 6) % 7
                            */}
                            {Array.from({ length: (month.startDay + 6) % 7 }).map((_, i) => (
                                <div key={`empty-${i}`} className="w-[28px] h-[28px] md:w-[25px] md:h-[25px]" />
                            ))}

                            {/* Actual day boxes - responsive size */}
                            {Array.from({ length: month.days }).map((_, i) => {
                                const day = i + 1;
                                // Create date string YYYY-MM-DD
                                // Note: monthIndex is 0-11, so +1 for string
                                const dateStr = `${currentYear}-${String(month.monthIndex + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
                                const isToday = dateStr === todayStr;
                                const style = getDayColor(dateStr);

                                // Base glow from activity
                                let boxStyle: React.CSSProperties | undefined = style ? {
                                    backgroundColor: style.color,
                                    opacity: style.opacity,
                                    boxShadow: style.boxShadow,
                                    border: `1px solid ${style.color}80`
                                } : undefined;

                                // Override/Enhance for Today
                                if (isToday) {
                                    boxStyle = {
                                        ...boxStyle,
                                        boxShadow: style
                                            ? `0 0 15px white, ${style.boxShadow}` // Combine white glow with activity glow
                                            : `0 0 10px rgba(255, 255, 255, 0.8)`, // Pure white glow if no activity
                                        border: '1px solid rgba(255, 255, 255, 0.9)',
                                    };
                                }

                                return (
                                    <div
                                        key={i}
                                        onClick={() => setSelectedDate(dateStr)}
                                        className={`w-[28px] h-[28px] md:w-[25px] md:h-[25px] rounded-[5px] md:rounded-[4px] transition-all duration-300 cursor-pointer hover:scale-110 active:scale-95 relative group ${!style ? 'bg-gradient-to-br from-[#1a1a1a] to-[#0f0f0f] shadow-[inset_0_1px_2px_rgba(0,0,0,0.5)] hover:from-[#2a2a2a] hover:to-[#1a1a1a] hover:shadow-[0_0_15px_rgba(16,185,129,0.4),inset_0_1px_2px_rgba(0,0,0,0.3)]' : ''} ${isToday ? 'z-20 scale-110' : 'hover:z-10'}`}
                                        style={boxStyle}
                                        title={`${month.name} ${day}${isToday ? ' (Today)' : ''}`}
                                    >
                                        {/* Shimmer Effect */}
                                        <div className="absolute inset-0 bg-gradient-to-br from-white/40 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500 rounded-[4px]" />
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                ))}
            </div>

            <div className="flex justify-center">
                <a href="/calendar" className="flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-card to-card/80 border border-border/60 rounded-lg text-xs md:text-sm text-[#f5f5f5] hover:bg-gradient-to-r hover:from-muted hover:to-muted/80 transition-all duration-500 cursor-pointer shadow-[0_10px_40px_rgba(0,0,0,0.5)] hover:shadow-[0_15px_60px_rgba(16,185,129,0.2)] hover:scale-105 hover:-translate-y-1 backdrop-blur-xl group">
                    <CalendarIcon className="w-4 h-4 group-hover:text-accent transition-colors duration-300" />
                    View Full Calendar
                </a>
            </div>

            {selectedDate && (
                <LogActivityModal
                    isOpen={!!selectedDate}
                    onClose={() => setSelectedDate(null)}
                    dateStr={selectedDate}
                />
            )}
        </div>
    );
}

"use client";

import { useState, useEffect } from 'react';
import { Droplet, Plus, Minus, Waves, CupSoda, Milk, Wine } from 'lucide-react';
import { useUserData } from '@/context/user-data-context';

export function HydrationWidget() {
    const { tasks, records, addTask, addRecord } = useUserData();
    const [waterTask, setWaterTask] = useState<any>(null);
    const [amount, setAmount] = useState(500);
    const [todaysTotal, setTodaysTotal] = useState(0);
    const [isAnimating, setIsAnimating] = useState(false);

    // Find the water task
    useEffect(() => {
        const task = tasks.find(t =>
            t.name.toLowerCase().includes('water') ||
            t.name.toLowerCase().includes('hydration') ||
            t.name.toLowerCase().includes('drink')
        );
        setWaterTask(task);
    }, [tasks]);

    // Calculate today's total
    useEffect(() => {
        if (!waterTask) return;

        const today = new Date().toISOString().split('T')[0];
        const todaysRecords = records[today] || [];
        const taskRecords = todaysRecords.filter(r => r.taskId === waterTask.id);

        const total = taskRecords.reduce((sum, r) => sum + (r.value || 0), 0);
        setTodaysTotal(total);
    }, [waterTask, records]);

    const handleCreateTask = () => {
        addTask("Hydration", "#3b82f6", {
            unit: "ml",
            phases: [
                { name: "Hydrated", threshold: 1500, intensity: 1 },
                { name: "Well Hydrated", threshold: 2000, intensity: 2 },
                { name: "Super Hydrated", threshold: 2500, intensity: 3 },
                { name: "Peak Performance", threshold: 3000, intensity: 4 }
            ],
            noMercy: true
        });
    };

    const handleDrink = (value: number) => {
        if (!waterTask) return;

        setIsAnimating(true);
        const today = new Date().toISOString().split('T')[0];
        addRecord(today, waterTask.id, null, value);
        setTimeout(() => setIsAnimating(false), 1000);
    };

    if (!waterTask) {
        return (
            <div className="bg-blue-900/10 border border-blue-500/20 rounded-xl p-6 flex flex-col items-center justify-center text-center space-y-4">
                <div className="p-3 bg-blue-500/20 rounded-full">
                    <Droplet className="w-6 h-6 text-blue-400" />
                </div>
                <div>
                    <h3 className="text-lg font-bold text-white">Track Hydration?</h3>
                    <p className="text-sm text-blue-200/60">Create a dedicated task to track your water intake.</p>
                </div>
                <button
                    onClick={handleCreateTask}
                    className="px-4 py-2 bg-blue-600 hover:bg-blue-500 text-white rounded-lg font-bold transition-all"
                >
                    Initialize Water Protocol
                </button>
            </div>
        );
    }

    // Visuals
    const target = 3000;
    const percentage = Math.min((todaysTotal / target) * 100, 100);

    return (
        <div className="relative overflow-hidden bg-gradient-to-br from-blue-950/40 to-black border border-blue-500/20 rounded-2xl p-6 shadow-xl group">
            {/* Background Liquid Effect */}
            <div
                className="absolute bottom-0 left-0 right-0 bg-blue-500/10 transition-all duration-1000 ease-in-out"
                style={{ height: `${percentage}%` }}
            >
                <div className="absolute top-0 left-0 right-0 h-1 bg-blue-400/30 blur-md" />
            </div>

            <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-6">

                {/* Status Section */}
                <div className="flex-1 flex items-center gap-4">
                    <div className="relative w-16 h-16 flex-shrink-0">
                        {/* Circular Progress */}
                        <svg className="w-full h-full -rotate-90">
                            <circle cx="32" cy="32" r="28" className="stroke-blue-900/30 fill-none" strokeWidth="6" />
                            <circle
                                cx="32" cy="32" r="28"
                                className="stroke-blue-500 fill-none transition-all duration-1000"
                                strokeWidth="6"
                                strokeDasharray="175.9"
                                strokeDashoffset={175.9 - (175.9 * percentage) / 100}
                                strokeLinecap="round"
                            />
                        </svg>
                        <div className="absolute inset-0 flex items-center justify-center">
                            <Droplet className={`w-6 h-6 text-blue-400 ${isAnimating ? 'animate-bounce' : ''}`} />
                        </div>
                    </div>

                    <div>
                        <div className="flex items-baseline gap-2">
                            <h3 className="text-2xl font-bold text-white tracking-tight">{todaysTotal}</h3>
                            <span className="text-sm text-blue-300 font-medium">/ {target}ml</span>
                        </div>
                        <p className="text-xs text-blue-400/60 uppercase tracking-widest font-semibold flex items-center gap-1">
                            <Waves className="w-3 h-3" />
                            Hydration Level
                        </p>
                    </div>
                </div>

                {/* Controls - Revised UX */}
                <div className="flex flex-col gap-3 items-end">

                    {/* Quick Presets */}
                    <div className="flex gap-2">
                        <button
                            onClick={() => handleDrink(1500)}
                            className="bg-blue-900/20 hover:bg-blue-600/20 border border-blue-500/20 rounded-lg px-3 py-2 flex flex-col items-center gap-1 transition-all active:scale-95 group/btn"
                            title="Bottle (1.5L)"
                        >
                            <CupSoda className="w-4 h-4 text-blue-400 group-hover/btn:text-blue-300" />
                            <span className="text-[10px] font-bold text-blue-200">1.5L</span>
                        </button>
                        <button
                            onClick={() => handleDrink(2000)}
                            className="bg-blue-900/20 hover:bg-blue-600/20 border border-blue-500/20 rounded-lg px-3 py-2 flex flex-col items-center gap-1 transition-all active:scale-95 group/btn"
                            title="Jug (2L)"
                        >
                            <Milk className="w-4 h-4 text-blue-400 group-hover/btn:text-blue-300" />
                            <span className="text-[10px] font-bold text-blue-200">2L</span>
                        </button>
                        <button
                            onClick={() => handleDrink(2500)}
                            className="bg-blue-900/20 hover:bg-blue-600/20 border border-blue-500/20 rounded-lg px-3 py-2 flex flex-col items-center gap-1 transition-all active:scale-95 group/btn"
                            title="Daily Goal (2.5L)"
                        >
                            <Wine className="w-4 h-4 text-blue-400 group-hover/btn:text-blue-300" />
                            <span className="text-[10px] font-bold text-blue-200">2.5L</span>
                        </button>
                    </div>

                    {/* Manual Custom Amount */}
                    <div className="flex items-center gap-2 bg-black/40 p-1 rounded-lg border border-blue-500/10 backdrop-blur-sm">
                        <button
                            onClick={() => setAmount(Math.max(50, amount - 50))}
                            className="w-8 h-8 rounded-lg bg-blue-900/20 hover:bg-blue-900/40 text-blue-400 flex items-center justify-center transition-colors"
                        >
                            <Minus className="w-3 h-3" />
                        </button>
                        <input
                            type="number"
                            value={amount}
                            onChange={(e) => setAmount(parseInt(e.target.value) || 0)}
                            className="w-16 bg-transparent text-center font-mono font-bold text-white text-sm focus:outline-none"
                        />
                        <span className="text-xs text-blue-500/50 -ml-2 mr-2">ml</span>
                        <button
                            onClick={() => setAmount(Math.min(5000, amount + 50))}
                            className="w-8 h-8 rounded-lg bg-blue-900/20 hover:bg-blue-900/40 text-blue-400 flex items-center justify-center transition-colors"
                        >
                            <Plus className="w-3 h-3" />
                        </button>

                        <div className="h-6 w-px bg-white/10 mx-1" />

                        <button
                            onClick={() => handleDrink(amount)}
                            className="h-8 px-4 bg-blue-600 hover:bg-blue-500 text-white font-bold rounded-lg shadow-lg shadow-blue-600/20 transition-all active:scale-95 flex items-center gap-2 text-xs"
                        >
                            Add
                        </button>
                    </div>
                </div>
            </div>

            {/* Bubbles Animation Effect when drinking */}
            {isAnimating && (
                <div className="absolute inset-0 pointer-events-none overflow-hidden">
                    {Array.from({ length: 5 }).map((_, i) => (
                        <div
                            key={i}
                            className="absolute bottom-0 bg-blue-400/30 rounded-full animate-[bubble_1s_ease-out_forwards]"
                            style={{
                                left: `${20 + Math.random() * 60}%`,
                                width: `${4 + Math.random() * 8}px`,
                                height: `${4 + Math.random() * 8}px`,
                                animationDelay: `${Math.random() * 0.5}s`
                            }}
                        />
                    ))}
                </div>
            )}

            <style jsx>{`
                @keyframes bubble {
                    0% { transform: translateY(0) scale(1); opacity: 0; }
                    50% { opacity: 1; }
                    100% { transform: translateY(-100px) scale(1.5); opacity: 0; }
                }
            `}</style>
        </div>
    );
}

"use client";

import { useUserData } from "@/context/user-data-context";
import { useEffect, useState } from "react";
import { Clock, Calendar, CheckCircle, ArrowRight } from "lucide-react";
import Link from "next/link";

export function LongTermReminders() {
    const { pacts } = useUserData();
    const [reminders, setReminders] = useState<any[]>([]);

    useEffect(() => {
        const today = new Date();
        const todayStr = today.toISOString().split('T')[0];
        const newReminders: any[] = [];

        Object.entries(pacts).forEach(([dateStr, dayPacts]) => {
            // Must be in the future
            if (dateStr <= todayStr) return;

            dayPacts.forEach(pact => {
                // Must have createdAt to calculate progress
                if (!pact.createdAt) return;

                const targetDate = new Date(dateStr);
                const createdDate = new Date(pact.createdAt);

                // Calculate Total Duration (ms)
                const totalDuration = targetDate.getTime() - createdDate.getTime();
                const totalDays = totalDuration / (1000 * 60 * 60 * 24);

                // Only consider "Long Term" tasks (set > 4 days in advance)
                if (totalDays <= 4) return;

                // Calculate Elapsed Time
                const elapsed = today.getTime() - createdDate.getTime();
                const progress = elapsed / totalDuration; // 0 to 1

                const daysRemaining = (targetDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24);

                let reminderType = null;
                let message = "";

                // Milestone Logic
                // 1. ~25% Elapsed (75% Remaining) - "Just Started / Early"
                // Range: 20% - 30%
                if (progress >= 0.20 && progress <= 0.30) {
                    reminderType = "early";
                    message = "A gentle nudge. You set this a while ago.";
                }
                // 2. ~50% Elapsed - "Halfway"
                // Range: 45% - 55%
                else if (progress >= 0.45 && progress <= 0.55) {
                    reminderType = "halfway";
                    message = "Halfway to the deadline. precise.";
                }
                // 3. ~75% Elapsed - "Closing In"
                // Range: 70% - 80%
                else if (progress >= 0.70 && progress <= 0.80) {
                    reminderType = "late";
                    message = "The horizon is approaching.";
                }
                // 4. One Day Before
                else if (daysRemaining <= 1.5 && daysRemaining > 0.5) {
                    reminderType = "tomorrow";
                    message = "Tomorrow is the day.";
                }

                if (reminderType) {
                    newReminders.push({
                        ...pact,
                        date: dateStr,
                        daysRemaining: Math.ceil(daysRemaining),
                        progress,
                        reminderType,
                        message
                    });
                }
            });
        });

        // Limit to maybe 1 or 2 reminders to not clutter?
        // Let's show all unique applicable ones but unique by day+pact?
        setReminders(newReminders);
    }, [pacts]);

    if (reminders.length === 0) return null;

    return (
        <div className="space-y-4 animate-[fadeIn_0.5s_ease-out]">
            {reminders.map((r, i) => (
                <div key={`${r.id}-${i}`} className="bg-gradient-to-r from-blue-900/10 to-transparent border-l-2 border-blue-500 p-4 rounded-r-xl backdrop-blur-sm relative overflow-hidden group animate-in fade-in slide-in-from-top-4 duration-500" style={{ animationDelay: `${i * 100}ms` }}>
                    {/* Background Glow */}
                    <div className="absolute inset-0 bg-blue-500/5 group-hover:bg-blue-500/10 transition-colors" />

                    <div className="flex items-start gap-4 relative z-10">
                        <div className="bg-blue-500/20 p-2 rounded-full">
                            <Clock className="w-5 h-5 text-blue-400" />
                        </div>
                        <div className="flex-1">
                            <div className="flex items-center justify-between mb-1">
                                <h4 className="text-sm font-bold text-blue-200 uppercase tracking-wider">
                                    {r.reminderType === 'tomorrow' ? 'Prepare Yourself' : 'Gentle Reminder'}
                                </h4>
                                <span className="text-xs text-blue-400/60 font-mono">
                                    {r.daysRemaining} days left
                                </span>
                            </div>
                            <p className="text-white font-medium text-lg leading-tight mb-1">
                                {r.text}
                            </p>
                            <p className="text-sm text-blue-300/70 italic">
                                "{r.message}"
                            </p>

                            {/* Progress Bar */}
                            <div className="mt-3 h-1 w-full bg-blue-900/30 rounded-full overflow-hidden">
                                <div
                                    className="h-full bg-blue-500 shadow-[0_0_10px_currentColor]"
                                    style={{ width: `${Math.min(r.progress * 100, 100)}%` }}
                                />
                            </div>
                        </div>

                        <div className="self-center">
                            <Link href="/citadel?date=${r.date}" className="p-2 hover:bg-white/10 rounded-full transition-colors">
                                <ArrowRight className="w-5 h-5 text-zinc-400 hover:text-white" />
                            </Link>
                        </div>
                    </div>
                </div>
            ))}
        </div>
    );
}

"use client";

import { useState, useRef, useEffect } from 'react';
import { Ghost, Send } from 'lucide-react';

interface Message {
    role: 'user' | 'lucius';
    text: string;
}

interface LuciusChatProps {
    initialHistory: Message[];
    onSendMessage: (message: string) => Promise<void>;
    isLocked: boolean;
    turnsLeft: number;
    onClose: () => void;
}

export function LuciusChat({ initialHistory, onSendMessage, isLocked, turnsLeft, onClose }: LuciusChatProps) {
    const [input, setInput] = useState("");
    const [isSending, setIsSending] = useState(false);
    const bottomRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        bottomRef.current?.scrollIntoView({ behavior: "smooth" });
    }, [initialHistory, isSending]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim() || isLocked || isSending || turnsLeft <= 0) return;

        const message = input;
        setInput("");
        setIsSending(true);
        await onSendMessage(message);
        setIsSending(false);
    };

    return (
        <div className="w-full max-w-2xl mx-auto flex flex-col h-[60vh] md:h-[500px] relative lucius-enter-active">

            {/* Header / Context */}
            <div className="absolute -top-12 left-0 right-0 text-center opacity-50">
                <span className="text-[10px] uppercase tracking-[0.3em] text-white/40">
                    Communion ({turnsLeft} turns remaining)
                </span>
            </div>

            {/* Script / Dialogue Area */}
            <div className="flex-1 overflow-y-auto custom-scrollbar px-4 space-y-8 py-8">
                {initialHistory.length === 0 && (
                    <div className="text-center text-white/10 text-sm italic pt-20">
                        The void listens.
                    </div>
                )}

                {initialHistory.map((msg, i) => (
                    <div
                        key={i}
                        className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'} lucius-enter-active`}
                    >
                        <span className="text-[10px] uppercase tracking-widest mb-1 text-white/20 select-none">
                            {msg.role === 'user' ? 'You' : 'Lucius'}
                        </span>
                        <div
                            className={`max-w-[85%] text-lg md:text-xl leading-relaxed ${msg.role === 'lucius'
                                    ? 'font-serif italic text-[var(--lucius-text-primary)] text-left'
                                    : 'font-mono text-[var(--lucius-text-muted)] text-right'
                                }`}
                        >
                            {msg.text}
                        </div>
                    </div>
                ))}

                {isSending && (
                    <div className="flex flex-col items-end lucius-enter-active">
                        <span className="text-[10px] uppercase tracking-widest mb-1 text-white/20">You</span>
                        <div className="text-lg md:text-xl font-mono text-white/30 animate-pulse">...</div>
                    </div>
                )}
                <div ref={bottomRef} />
            </div>

            {/* Input Area */}
            <div className="mt-4 relative group">
                <div className={`absolute inset-0 bg-gradient-to-t from-[var(--lucius-void-900)] to-transparent -top-20 pointer-events-none`} />

                <form onSubmit={handleSubmit} className="relative z-10 flex items-center gap-4 border-t border-white/5 pt-6">
                    <button
                        type="button"
                        onClick={onClose}
                        className="text-xs uppercase tracking-widest text-white/20 hover:text-white/50 transition-colors px-2"
                    >
                        End
                    </button>

                    <div className="flex-1 relative">
                        <input
                            type="text"
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            placeholder={isLocked ? "Silence falls..." : "Speak your truth..."}
                            disabled={isLocked || isSending || turnsLeft <= 0}
                            className="w-full bg-transparent border-none text-lg md:text-xl font-serif italic text-white/80 placeholder:text-white/10 focus:ring-0 focus:outline-none py-2 px-0"
                            autoFocus
                        />
                    </div>

                    <button
                        type="submit"
                        disabled={!input.trim() || isLocked || isSending}
                        className="text-white/40 hover:text-white transition-colors disabled:opacity-20 disabled:cursor-not-allowed"
                    >
                        <Send className="w-5 h-5" />
                    </button>
                </form>
            </div>
        </div>
    );
}

