"use client";

import React, { useState } from 'react';
import { usePathname } from 'next/navigation';
import Link from 'next/link';
import {
    Home, Globe, Flame, Coins, Shield, Sword,
    ClipboardList, MessageCircle, ScrollText, User, Skull
} from 'lucide-react';
import { useUserData, ALL_NAV_ITEMS, NavItemKey } from '@/context/user-data-context';
import { getUserAvatar } from '@/utils/avatar-helpers';
import { RitualModal } from './modals/ritual-modal';
import { BankModal } from './modals/bank-modal';
import { NightsWatchModal } from './modals/nights-watch-modal';
import { ShareModal } from './modals/share-modal';
import { PactsModal } from './modals/pacts-modal';

const ICON_MAP: Record<string, any> = {
    Home, Globe, Flame, Coins, Shield, Sword,
    ClipboardList, MessageCircle, ScrollText, User, Skull
};

export function MobileNav() {
    const pathname = usePathname();
    const { navPreferences, profile, user } = useUserData();

    const [isRitualModalOpen, setIsRitualModalOpen] = useState(false);
    const [isBankModalOpen, setIsBankModalOpen] = useState(false);
    const [isWatchModalOpen, setIsWatchModalOpen] = useState(false);
    const [isArenaModalOpen, setIsArenaModalOpen] = useState(false);
    const [isPactsModalOpen, setIsPactsModalOpen] = useState(false);

    // Get the actual nav items based on preferences
    const activeNavItems = navPreferences
        .map(key => ALL_NAV_ITEMS.find(item => item.key === key))
        .filter(Boolean) as typeof ALL_NAV_ITEMS;

    const handleAction = (key: NavItemKey) => {
        if (key === 'ritual') setIsRitualModalOpen(true);
        if (key === 'bank') setIsBankModalOpen(true);
        if (key === 'watch') setIsWatchModalOpen(true);
        if (key === 'arena') setIsArenaModalOpen(true);
        if (key === 'pacts') setIsPactsModalOpen(true);
    };

    const isActive = (href: string) => {
        if (href === '/') return pathname === '/';
        return pathname.startsWith(href);
    };

    // Hide nav on full-screen pages like notes editor
    const hideNav = pathname.startsWith('/notes');

    return (
        <>
            {!hideNav && (
                <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-black/95 backdrop-blur-xl border-t border-white/10 z-[60] pb-safe">
                    <div className="flex items-center justify-around h-16 px-2">
                        {/* Home Button - Fixed */}
                        <Link
                            href="/"
                            className="flex flex-col items-center justify-center flex-1 h-full relative"
                        >
                            <Home
                                className={`w-6 h-6 transition-all ${isActive('/') ? 'text-white scale-110' : 'text-white/50'}`}
                                strokeWidth={isActive('/') ? 2.5 : 2}
                            />
                            {isActive('/') && (
                                <div className="absolute -top-1 w-1 h-1 rounded-full bg-accent" />
                            )}
                        </Link>

                        {/* Dynamic User Items */}
                        {activeNavItems.map((item) => {
                            const Icon = ICON_MAP[item.icon];
                            if (!Icon) return null;
                            const active = item.href ? isActive(item.href) : false;

                            if (item.href) {
                                return (
                                    <Link
                                        key={item.key}
                                        href={item.href}
                                        className="flex flex-col items-center justify-center flex-1 h-full relative"
                                    >
                                        <Icon
                                            className={`w-6 h-6 transition-all ${active ? 'text-white scale-110' : 'text-white/50'}`}
                                            strokeWidth={active ? 2.5 : 2}
                                        />
                                        {active && (
                                            <div className="absolute -top-1 w-1 h-1 rounded-full bg-accent" />
                                        )}
                                    </Link>
                                );
                            }

                            return (
                                <button
                                    key={item.key}
                                    onClick={() => handleAction(item.key)}
                                    className="flex flex-col items-center justify-center flex-1 h-full relative"
                                >
                                    <Icon className="w-6 h-6 text-white/50 hover:text-white transition-all" />
                                </button>
                            );
                        })}

                        {/* Profile Button - Fixed */}
                        <Link
                            href="/profile"
                            className="flex flex-col items-center justify-center flex-1 h-full relative"
                        >
                            <div className={`w-7 h-7 rounded-full border-2 flex items-center justify-center overflow-hidden transition-all ${isActive('/profile') ? 'border-white' : 'border-white/30'} bg-gradient-to-tr from-zinc-800 to-zinc-700`}>
                                <img
                                    src={getUserAvatar(profile?.avatar_url, profile?.gender, user?.id)}
                                    alt="Profile"
                                    className="w-full h-full object-cover"
                                />
                            </div>
                            {isActive('/profile') && (
                                <div className="absolute -top-1 w-1 h-1 rounded-full bg-accent" />
                            )}
                        </Link>
                    </div>
                </nav>
            )}

            <RitualModal isOpen={isRitualModalOpen} onClose={() => setIsRitualModalOpen(false)} />
            <BankModal isOpen={isBankModalOpen} onClose={() => setIsBankModalOpen(false)} />
            <NightsWatchModal isOpen={isWatchModalOpen} onClose={() => setIsWatchModalOpen(false)} />
            <ShareModal isOpen={isArenaModalOpen} onClose={() => setIsArenaModalOpen(false)} />
            <PactsModal isOpen={isPactsModalOpen} onClose={() => setIsPactsModalOpen(false)} />
        </>
    );
}

"use client";

import { useState } from "react";
import { useUserData, LifeEvent } from "@/context/user-data-context";
import { X, Calendar, Flag, BookOpen } from "lucide-react";

interface AddLifeEventModalProps {
    isOpen: boolean;
    onClose: () => void;
    weekIndex: number;
    birthDate: string;
}

export function AddLifeEventModal({ isOpen, onClose, weekIndex, birthDate }: AddLifeEventModalProps) {
    const { addLifeEvent } = useUserData();
    const [title, setTitle] = useState("");
    const [description, setDescription] = useState("");
    const [type, setType] = useState<'MEMORY' | 'GOAL'>('MEMORY');
    const [isSubmitting, setIsSubmitting] = useState(false);

    if (!isOpen) return null;

    // Calculate approximate date from weekIndex
    const getEventDate = () => {
        const birth = new Date(birthDate);
        birth.setDate(birth.getDate() + (weekIndex * 7));
        return birth.toISOString().split('T')[0];
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSubmitting(true);

        await addLifeEvent({
            event_date: getEventDate(),
            title,
            description,
            type
        });

        setIsSubmitting(false);
        setTitle("");
        setDescription("");
        onClose();
    };

    const isPast = new Date(getEventDate()) < new Date();

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} />

            <div className="relative w-full max-w-md bg-[#0a0a0a] border border-white/10 rounded-3xl p-6 shadow-2xl animate-in fade-in zoom-in-95 duration-300">
                <button
                    onClick={onClose}
                    className="absolute top-4 right-4 text-zinc-500 hover:text-white transition-colors"
                >
                    <X className="w-5 h-5" />
                </button>

                <div className="mb-6">
                    <h2 className="text-xl font-bold text-white flex items-center gap-2">
                        {type === 'MEMORY' ? <BookOpen className="w-5 h-5 text-yellow-500" /> : <Flag className="w-5 h-5 text-blue-500" />}
                        {type === 'MEMORY' ? 'Capture Memory' : 'Set Life Goal'}
                    </h2>
                    <p className="text-zinc-500 text-xs font-mono mt-1">
                        Week {weekIndex} • {getEventDate()}
                    </p>
                </div>

                <form onSubmit={handleSubmit} className="space-y-4">
                    {/* Type Toggle */}
                    <div className="flex bg-white/5 p-1 rounded-xl">
                        <button
                            type="button"
                            onClick={() => setType('MEMORY')}
                            className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all ${type === 'MEMORY' ? 'bg-yellow-500/20 text-yellow-500' : 'text-zinc-500 hover:text-zinc-300'}`}
                        >
                            Memory
                        </button>
                        <button
                            type="button"
                            onClick={() => setType('GOAL')}
                            className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all ${type === 'GOAL' ? 'bg-blue-500/20 text-blue-500' : 'text-zinc-500 hover:text-zinc-300'}`}
                        >
                            Goal
                        </button>
                    </div>

                    <div className="space-y-2">
                        <label className="text-xs uppercase tracking-wider text-zinc-500 font-bold">Title</label>
                        <input
                            type="text"
                            value={title}
                            onChange={(e) => setTitle(e.target.value)}
                            placeholder={type === 'MEMORY' ? "Graduated College" : "Retire Early"}
                            className="w-full bg-zinc-900 border border-white/10 rounded-xl px-4 py-3 text-white placeholder:text-zinc-700 focus:outline-none focus:border-white/20 transition-colors"
                            required
                        />
                    </div>

                    <div className="space-y-2">
                        <label className="text-xs uppercase tracking-wider text-zinc-500 font-bold">Details</label>
                        <textarea
                            value={description}
                            onChange={(e) => setDescription(e.target.value)}
                            placeholder="Add context..."
                            className="w-full bg-zinc-900 border border-white/10 rounded-xl px-4 py-3 text-white placeholder:text-zinc-700 focus:outline-none focus:border-white/20 transition-colors min-h-[100px] resize-none"
                        />
                    </div>

                    <button
                        type="submit"
                        disabled={isSubmitting}
                        className={`
                            w-full py-3 rounded-xl font-bold text-black transition-all hover:scale-[1.02] active:scale-95
                            ${type === 'MEMORY' ? 'bg-white hover:bg-yellow-50' : 'bg-white hover:bg-blue-50'}
                            ${isSubmitting ? 'opacity-50 cursor-not-allowed' : ''}
                        `}
                    >
                        {isSubmitting ? "Scribing..." : "Etch into Life Map"}
                    </button>
                </form>
            </div>
        </div>
    );
}

