"use client";

import { useEffect, useState } from 'react';
import { useUserData } from '@/context/user-data-context';
import { ARTIFACTS } from '@/lib/artifacts';
import { motion, AnimatePresence } from 'framer-motion';
import { Shield, Book, Zap, Activity, BookOpen, Clock, Flame, Triangle, Hexagon, Compass, Skull, Box } from 'lucide-react';
import confetti from 'canvas-confetti';

const ICON_MAP: any = {
    'Flame': Flame,
    'Triangle': Triangle,
    'Hexagon': Hexagon,
    'Compass': Compass,
    'Skull': Skull,
    'Box': Box,
    'Shield': Shield,
    'Book': Book,
    'Zap': Zap,
    'Activity': Activity,
    'BookOpen': BookOpen,
    'Clock': Clock
};

export function ArtifactUnlockModal() {
    const { newlyUnlockedArtifacts, clearNewlyUnlocked } = useUserData();
    const [currentIndex, setCurrentIndex] = useState(0);
    const [isOpen, setIsOpen] = useState(false);

    useEffect(() => {
        if (newlyUnlockedArtifacts.length > 0) {
            setIsOpen(true);
            setCurrentIndex(0);
            confetti({
                particleCount: 100,
                spread: 70,
                origin: { y: 0.6 }
            });
        }
    }, [newlyUnlockedArtifacts]);

    const handleNext = () => {
        if (currentIndex < newlyUnlockedArtifacts.length - 1) {
            setCurrentIndex(prev => prev + 1);
            confetti({
                particleCount: 100,
                spread: 70,
                origin: { y: 0.6 }
            });
        } else {
            setIsOpen(false);
            clearNewlyUnlocked();
        }
    };

    if (!isOpen || newlyUnlockedArtifacts.length === 0) return null;

    const artifactId = newlyUnlockedArtifacts[currentIndex];
    const artifact = ARTIFACTS.find(a => a.id === artifactId);

    if (!artifact) {
        handleNext();
        return null;
    }

    const Icon = ICON_MAP[artifact.icon] || Box;

    return (
        <AnimatePresence>
            {isOpen && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                    {/* Backdrop */}
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="absolute inset-0 bg-black/80 backdrop-blur-md"
                    />

                    {/* Modal Content */}
                    <motion.div
                        key={artifactId}
                        initial={{ scale: 0.8, opacity: 0, y: 20 }}
                        animate={{ scale: 1, opacity: 1, y: 0 }}
                        exit={{ scale: 0.8, opacity: 0, y: -20 }}
                        transition={{ type: "spring", duration: 0.5 }}
                        className="relative w-full max-w-md bg-[#0a0a0a] border border-[#333] rounded-2xl p-8 flex flex-col items-center text-center shadow-[0_0_50px_rgba(0,0,0,0.8)] overflow-hidden"
                    >
                        {/* Glow Background */}
                        <div
                            className="absolute inset-0 opacity-20 blur-3xl"
                            style={{ background: `radial-gradient(circle at center, ${artifact.color}, transparent 70%)` }}
                        />

                        <motion.div
                            initial={{ scale: 0, rotate: -180 }}
                            animate={{ scale: 1, rotate: 0 }}
                            transition={{ type: "spring", duration: 0.8, delay: 0.2 }}
                            className="relative z-10 w-24 h-24 rounded-full flex items-center justify-center mb-6 shadow-[0_0_30px_rgba(0,0,0,0.5)] bg-[#111] border border-[#333]"
                            style={{ boxShadow: `0 0 30px ${artifact.color}40`, borderColor: artifact.color }}
                        >
                            <Icon className="w-12 h-12" style={{ color: artifact.color }} />
                        </motion.div>

                        <motion.h2
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.4 }}
                            className="text-white text-3xl font-bold mb-2 tracking-wide font-serif relative z-10"
                        >
                            Artifact Acquired
                        </motion.h2>

                        <motion.p
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            transition={{ delay: 0.5 }}
                            className="text-lg font-medium mb-4 relative z-10"
                            style={{ color: artifact.color }}
                        >
                            {artifact.name}
                        </motion.p>

                        <motion.p
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            transition={{ delay: 0.6 }}
                            className="text-muted-foreground text-sm italic mb-8 relative z-10 max-w-[80%]"
                        >
                            "{artifact.description}"
                        </motion.p>

                        <motion.button
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: 0.8 }}
                            onClick={handleNext}
                            className="relative z-10 px-8 py-3 rounded-xl font-bold text-black transition-transform active:scale-95 hover:scale-105 shadow-[0_0_20px_rgba(0,0,0,0.3)]"
                            style={{
                                backgroundColor: artifact.color,
                                boxShadow: `0 0 20px ${artifact.color}60`
                            }}
                        >
                            {currentIndex < newlyUnlockedArtifacts.length - 1 ? "Next Reward" : "Claim Artifact"}
                        </motion.button>

                    </motion.div>
                </div>
            )}
        </AnimatePresence>
    );
}

"use client";

import { useState } from 'react';
import { X, Coins, Plus, Trash2, AlertTriangle, CheckCircle2 } from 'lucide-react';
import { useUserData } from '@/context/user-data-context';

interface BankModalProps {
    isOpen: boolean;
    onClose: () => void;
}

export function BankModal({ isOpen, onClose }: BankModalProps) {
    const { debts, addDebt, payDebt } = useUserData();
    const [description, setDescription] = useState('');
    const [amount, setAmount] = useState('');
    const [isSubmitting, setIsSubmitting] = useState(false);

    if (!isOpen) return null;

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!description || !amount) return;

        setIsSubmitting(true);
        await addDebt({ description, amount });
        setDescription('');
        setAmount('');
        setIsSubmitting(false);
    };

    const handlePay = async (id: string) => {
        await payDebt(id);
    };

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            {/* Backdrop */}
            <div
                className="absolute inset-0 bg-black/90 backdrop-blur-sm animate-[fadeIn_0.3s_ease-out]"
                onClick={onClose}
            />

            {/* Modal Content */}
            <div className="relative w-full max-w-lg bg-zinc-950 border border-yellow-900/40 rounded-2xl shadow-[0_0_50px_rgba(234,179,8,0.1)] overflow-hidden animate-[scaleIn_0.3s_ease-out]">

                {/* Header */}
                <div className="p-6 border-b border-yellow-900/20 flex justify-between items-center bg-gradient-to-r from-zinc-950 to-yellow-950/20">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-yellow-900/20 rounded-full border border-yellow-700/30">
                            <Coins className="w-6 h-6 text-yellow-500" />
                        </div>
                        <div>
                            <h2 className="text-xl font-bold text-white tracking-wide">THE IRON BANK</h2>
                            <p className="text-xs text-yellow-600 font-serif italic">"The Bank will have its due."</p>
                        </div>
                    </div>
                    <button
                        onClick={onClose}
                        className="text-zinc-500 hover:text-white transition-colors"
                    >
                        <X className="w-6 h-6" />
                    </button>
                </div>

                <div className="p-6 space-y-8">

                    {/* CONFESSION FORM */}
                    <div className="space-y-4">
                        <h3 className="text-sm font-bold text-zinc-400 uppercase tracking-widest flex items-center gap-2">
                            <AlertTriangle className="w-4 h-4 text-orange-500" /> Confess Failure
                        </h3>
                        <form onSubmit={handleSubmit} className="space-y-3">
                            <input
                                type="text"
                                value={description}
                                onChange={(e) => setDescription(e.target.value)}
                                placeholder="I failed to..."
                                className="w-full bg-black/50 border border-zinc-800 rounded-lg px-4 py-3 text-white placeholder-zinc-600 focus:outline-none focus:border-yellow-700/50 transition-colors"
                                autoFocus
                            />
                            <div className="flex gap-2">
                                <input
                                    type="text"
                                    value={amount}
                                    onChange={(e) => setAmount(e.target.value)}
                                    placeholder="Price (Penalty)"
                                    className="flex-1 bg-black/50 border border-zinc-800 rounded-lg px-4 py-3 text-white placeholder-zinc-600 focus:outline-none focus:border-yellow-700/50 transition-colors"
                                />
                                <button
                                    type="submit"
                                    disabled={!description || !amount || isSubmitting}
                                    className="px-6 py-3 bg-yellow-900/20 hover:bg-yellow-900/40 border border-yellow-700/30 text-yellow-500 rounded-lg font-bold transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
                                >
                                    <Plus className="w-4 h-4" /> Add Debt
                                </button>
                            </div>
                        </form>
                    </div>

                    {/* LEDGER */}
                    <div className="space-y-4">
                        <h3 className="text-sm font-bold text-zinc-400 uppercase tracking-widest flex items-center gap-2">
                            <Coins className="w-4 h-4 text-yellow-600" /> Outstanding Debts
                        </h3>

                        <div className="max-h-[300px] overflow-y-auto pr-2 space-y-3 custom-scrollbar">
                            {debts.length === 0 ? (
                                <div className="text-center py-8 border border-dashed border-zinc-800 rounded-lg">
                                    <div className="inline-flex p-3 bg-zinc-900 rounded-full mb-3">
                                        <CheckCircle2 className="w-6 h-6 text-green-500" />
                                    </div>
                                    <p className="text-zinc-500 text-sm">Your accounts are balanced.</p>
                                </div>
                            ) : (
                                debts.map((debt) => (
                                    <div key={debt.id} className="group bg-black/30 border border-zinc-800 hover:border-red-900/50 p-4 rounded-lg flex items-center justify-between transition-colors">
                                        <div>
                                            <p className="font-medium text-white">{debt.description}</p>
                                            <p className="text-sm text-yellow-600 font-mono mt-0.5">{debt.amount}</p>
                                        </div>
                                        <button
                                            onClick={() => handlePay(debt.id)}
                                            className="px-3 py-1.5 text-xs font-bold bg-zinc-900 hover:bg-green-900/30 text-zinc-500 hover:text-green-500 border border-zinc-800 hover:border-green-800 rounded transition-all flex items-center gap-1 opacity-0 group-hover:opacity-100"
                                        >
                                            <Coins className="w-3 h-3" /> PAY DEBT
                                        </button>
                                    </div>
                                ))
                            )}
                        </div>
                    </div>

                </div>
            </div>
        </div>
    );
}

"use client";

import { useState } from 'react';
import { createClient } from '@/utils/supabase/client';
import { X, Ban, Flag } from 'lucide-react';

interface BlockReportModalProps {
    isOpen: boolean;
    onClose: () => void;
    userId: string;
    userName: string;
}

export function BlockReportModal({ isOpen, onClose, userId, userName }: BlockReportModalProps) {
    const [action, setAction] = useState<'block' | 'report' | null>(null);
    const [reportType, setReportType] = useState<'harassment' | 'spam' | 'inappropriate' | 'other'>('harassment');
    const [reportContent, setReportContent] = useState('');
    const [blockReason, setBlockReason] = useState('');
    const [isProcessing, setIsProcessing] = useState(false);
    const supabase = createClient();

    const handleBlock = async () => {
        setIsProcessing(true);
        try {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) return;

            await supabase
                .from('blocked_users')
                .insert({
                    blocker_id: user.id,
                    blocked_id: userId,
                    reason: blockReason.trim() || null
                });

            // Also remove friendship if exists
            await supabase
                .from('friendships')
                .delete()
                .or(`user_id.eq.${user.id},friend_id.eq.${user.id}`)
                .or(`user_id.eq.${userId},friend_id.eq.${userId}`);

            alert(`${userName} has been blocked`);
            onClose();
        } catch (error) {
            console.error('Error blocking user:', error);
            alert('Failed to block user');
        } finally {
            setIsProcessing(false);
        }
    };

    const handleReport = async () => {
        if (!reportContent.trim()) {
            alert('Please provide details about the report');
            return;
        }

        setIsProcessing(true);
        try {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) return;

            await supabase
                .from('reports')
                .insert({
                    reporter_id: user.id,
                    reported_id: userId,
                    type: reportType,
                    content: reportContent.trim()
                });

            alert('Report submitted successfully');
            onClose();
        } catch (error) {
            console.error('Error submitting report:', error);
            alert('Failed to submit report');
        } finally {
            setIsProcessing(false);
        }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
            <div className="bg-gradient-to-br from-zinc-900 to-black border border-white/20 rounded-2xl w-full max-w-lg shadow-2xl">
                {/* Header */}
                <div className="p-6 border-b border-white/10 flex items-center justify-between">
                    <h2 className="text-xl font-bold">
                        {action ? (action === 'block' ? 'Block User' : 'Report User') : 'User Actions'}
                    </h2>
                    <button
                        onClick={onClose}
                        className="p-2 hover:bg-white/10 rounded-full transition-colors"
                    >
                        <X className="w-5 h-5" />
                    </button>
                </div>

                {/* Content */}
                <div className="p-6">
                    {!action ? (
                        <div className="space-y-3">
                            <p className="text-sm text-zinc-400 mb-4">
                                Choose an action for <span className="font-bold text-white">{userName}</span>
                            </p>

                            <button
                                onClick={() => setAction('block')}
                                className="w-full p-4 bg-red-500/10 border border-red-500/30 rounded-xl hover:bg-red-500/20 transition-colors flex items-center gap-3"
                            >
                                <Ban className="w-5 h-5 text-red-500" />
                                <div className="text-left">
                                    <div className="font-bold text-white">Block User</div>
                                    <div className="text-xs text-zinc-400">They won't be able to message you</div>
                                </div>
                            </button>

                            <button
                                onClick={() => setAction('report')}
                                className="w-full p-4 bg-orange-500/10 border border-orange-500/30 rounded-xl hover:bg-orange-500/20 transition-colors flex items-center gap-3"
                            >
                                <Flag className="w-5 h-5 text-orange-500" />
                                <div className="text-left">
                                    <div className="font-bold text-white">Report User</div>
                                    <div className="text-xs text-zinc-400">Report inappropriate behavior</div>
                                </div>
                            </button>
                        </div>
                    ) : action === 'block' ? (
                        <div className="space-y-4">
                            <div className="p-4 bg-red-500/10 border border-red-500/30 rounded-lg">
                                <p className="text-sm text-red-200">
                                    <strong>{userName}</strong> will no longer be able to:
                                </p>
                                <ul className="text-xs text-red-300 mt-2 ml-4 space-y-1">
                                    <li>• Send you messages</li>
                                    <li>• See your profile or activities</li>
                                    <li>• Send you friend requests</li>
                                </ul>
                            </div>

                            <div>
                                <label className="block text-sm font-semibold mb-2">
                                    Reason (Optional)
                                </label>
                                <textarea
                                    value={blockReason}
                                    onChange={(e) => setBlockReason(e.target.value)}
                                    placeholder="Why are you blocking this user?"
                                    rows={3}
                                    className="w-full bg-white/10 border border-white/20 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-white/40 transition-colors placeholder:text-zinc-500 resize-none"
                                />
                            </div>

                            <div className="flex gap-3">
                                <button
                                    onClick={() => setAction(null)}
                                    className="flex-1 px-4 py-3 bg-zinc-700 hover:bg-zinc-600 text-white rounded-lg font-semibold transition-colors"
                                >
                                    Cancel
                                </button>
                                <button
                                    onClick={handleBlock}
                                    disabled={isProcessing}
                                    className="flex-1 px-4 py-3 bg-red-500 hover:bg-red-600 text-white rounded-lg font-semibold transition-colors disabled:opacity-50"
                                >
                                    {isProcessing ? 'Blocking...' : 'Block User'}
                                </button>
                            </div>
                        </div>
                    ) : (
                        <div className="space-y-4">
                            <div>
                                <label className="block text-sm font-semibold mb-2">
                                    Report Type
                                </label>
                                <select
                                    value={reportType}
                                    onChange={(e) => setReportType(e.target.value as any)}
                                    className="w-full bg-white/10 border border-white/20 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-white/40 transition-colors"
                                >
                                    <option value="harassment">Harassment</option>
                                    <option value="spam">Spam</option>
                                    <option value="inappropriate">Inappropriate Content</option>
                                    <option value="other">Other</option>
                                </select>
                            </div>

                            <div>
                                <label className="block text-sm font-semibold mb-2">
                                    Details *
                                </label>
                                <textarea
                                    value={reportContent}
                                    onChange={(e) => setReportContent(e.target.value)}
                                    placeholder="Please describe what happened..."
                                    rows={4}
                                    className="w-full bg-white/10 border border-white/20 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-white/40 transition-colors placeholder:text-zinc-500 resize-none"
                                />
                            </div>

                            <div className="p-3 bg-blue-500/10 border border-blue-500/30 rounded-lg">
                                <p className="text-xs text-blue-200">
                                    Reports are reviewed by our team. Thank you for helping keep the community safe.
                                </p>
                            </div>

                            <div className="flex gap-3">
                                <button
                                    onClick={() => setAction(null)}
                                    className="flex-1 px-4 py-3 bg-zinc-700 hover:bg-zinc-600 text-white rounded-lg font-semibold transition-colors"
                                >
                                    Cancel
                                </button>
                                <button
                                    onClick={handleReport}
                                    disabled={isProcessing || !reportContent.trim()}
                                    className="flex-1 px-4 py-3 bg-orange-500 hover:bg-orange-600 text-white rounded-lg font-semibold transition-colors disabled:opacity-50"
                                >
                                    {isProcessing ? 'Submitting...' : 'Submit Report'}
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState } from 'react';
import { createClient } from '@/utils/supabase/client';
import { X, Users as UsersIcon, Camera } from 'lucide-react';
import { getUserAvatar } from '@/utils/avatar-helpers';

interface Friend {
    id: string;
    full_name: string | null;
    username: string | null;
    avatar_url: string | null;
    gender: string | null;
}

interface CreateGroupModalProps {
    isOpen: boolean;
    onClose: () => void;
    friends: Friend[];
}

export function CreateGroupModal({ isOpen, onClose, friends }: CreateGroupModalProps) {
    const [groupName, setGroupName] = useState('');
    const [groupBio, setGroupBio] = useState('');
    const [selectedMembers, setSelectedMembers] = useState<string[]>([]);
    const [isCreating, setIsCreating] = useState(false);
    const supabase = createClient();

    const toggleMember = (userId: string) => {
        setSelectedMembers(prev =>
            prev.includes(userId)
                ? prev.filter(id => id !== userId)
                : [...prev, userId]
        );
    };

    const createGroup = async () => {
        if (!groupName.trim() || selectedMembers.length === 0) {
            alert('Please enter a group name and select at least one member');
            return;
        }

        setIsCreating(true);

        try {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) return;

            // Create group
            const { data: group, error: groupError } = await supabase
                .from('groups')
                .insert({
                    name: groupName.trim(),
                    bio: groupBio.trim() || null,
                    created_by: user.id
                })
                .select()
                .single();

            if (groupError) throw groupError;

            // Add creator as admin
            await supabase
                .from('group_members')
                .insert({
                    group_id: group.id,
                    user_id: user.id,
                    role: 'admin'
                });

            // Add selected members
            const memberInserts = selectedMembers.map(userId => ({
                group_id: group.id,
                user_id: userId,
                role: 'member'
            }));

            await supabase
                .from('group_members')
                .insert(memberInserts);

            // Reset and close
            setGroupName('');
            setGroupBio('');
            setSelectedMembers([]);
            onClose();
        } catch (error) {
            console.error('Error creating group:', error);
            alert('Failed to create group');
        } finally {
            setIsCreating(false);
        }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
            <div className="bg-gradient-to-br from-zinc-900 to-black border border-white/20 rounded-2xl w-full max-w-2xl max-h-[80vh] flex flex-col shadow-2xl">
                {/* Header */}
                <div className="p-6 border-b border-white/10 flex items-center justify-between">
                    <h2 className="text-2xl font-bold flex items-center gap-2">
                        <UsersIcon className="w-6 h-6 text-blue-400" />
                        Create Group
                    </h2>
                    <button
                        onClick={onClose}
                        className="p-2 hover:bg-white/10 rounded-full transition-colors"
                    >
                        <X className="w-5 h-5" />
                    </button>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto p-6 space-y-6">
                    {/* Group Name */}
                    <div>
                        <label className="block text-sm font-semibold mb-2">
                            Group Name *
                        </label>
                        <input
                            type="text"
                            value={groupName}
                            onChange={(e) => setGroupName(e.target.value)}
                            placeholder="Enter group name..."
                            className="w-full bg-white/10 border border-white/20 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-white/40 transition-colors placeholder:text-zinc-500"
                        />
                    </div>

                    {/* Group Bio */}
                    <div>
                        <label className="block text-sm font-semibold mb-2">
                            Group Bio (Optional)
                        </label>
                        <textarea
                            value={groupBio}
                            onChange={(e) => setGroupBio(e.target.value)}
                            placeholder="Describe your group..."
                            rows={3}
                            className="w-full bg-white/10 border border-white/20 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-white/40 transition-colors placeholder:text-zinc-500 resize-none"
                        />
                    </div>

                    {/* Select Members */}
                    <div>
                        <label className="block text-sm font-semibold mb-2">
                            Add Members * ({selectedMembers.length} selected)
                        </label>
                        <div className="space-y-2 max-h-64 overflow-y-auto">
                            {friends.map(friend => (
                                <button
                                    key={friend.id}
                                    onClick={() => toggleMember(friend.id)}
                                    className={`w-full p-3 flex items-center gap-3 rounded-lg transition-colors ${selectedMembers.includes(friend.id)
                                            ? 'bg-blue-500/20 border-2 border-blue-500'
                                            : 'bg-white/5 border-2 border-transparent hover:bg-white/10'
                                        }`}
                                >
                                    <div className="w-10 h-10 rounded-full overflow-hidden border border-white/10">
                                        <img
                                            src={getUserAvatar(friend.avatar_url, friend.gender, friend.id)}
                                            alt={friend.full_name || 'User'}
                                            className="w-full h-full object-cover"
                                        />
                                    </div>
                                    <div className="flex-1 text-left">
                                        <div className="font-semibold">
                                            {friend.full_name || friend.username || 'User'}
                                        </div>
                                        {friend.username && (
                                            <div className="text-sm text-zinc-400">@{friend.username}</div>
                                        )}
                                    </div>
                                    {selectedMembers.includes(friend.id) && (
                                        <div className="w-5 h-5 bg-blue-500 rounded-full flex items-center justify-center">
                                            <span className="text-xs">✓</span>
                                        </div>
                                    )}
                                </button>
                            ))}
                        </div>
                    </div>
                </div>

                {/* Footer */}
                <div className="p-6 border-t border-white/10 flex justify-end gap-3">
                    <button
                        onClick={onClose}
                        className="px-6 py-3 bg-zinc-700 hover:bg-zinc-600 text-white rounded-lg font-semibold transition-colors"
                    >
                        Cancel
                    </button>
                    <button
                        onClick={createGroup}
                        disabled={isCreating || !groupName.trim() || selectedMembers.length === 0}
                        className="px-6 py-3 bg-blue-500 hover:bg-blue-600 text-white rounded-lg font-semibold transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        {isCreating ? 'Creating...' : 'Create Group'}
                    </button>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from 'react';
import { X, Check, Moon, Sparkles, ArrowRight } from 'lucide-react';
import { useUserData } from '@/context/user-data-context';

interface DailyReviewModalProps {
    isOpen: boolean;
    onClose: () => void;
}

export function DailyReviewModal({ isOpen, onClose }: DailyReviewModalProps) {
    const { tasks, records, addRecord, deleteRecord } = useUserData();
    const [dateStr, setDateStr] = useState<string>('');
    const [updates, setUpdates] = useState<Record<string, { intensity: number | null, value?: number, isMarked: boolean }>>({});
    const [isSaving, setIsSaving] = useState(false);
    const [reviewedCount, setReviewedCount] = useState(0);

    const activeTasks = tasks.filter(t => !t.isArchived);

    useEffect(() => {
        if (isOpen) {
            const today = new Date();
            const dStr = `${today.getFullYear()}-${String(today.getMonth() + 1).padStart(2, '0')}-${String(today.getDate()).padStart(2, '0')}`;
            setDateStr(dStr);

            const dayRecords = records[dStr] || [];
            const initialUpdates: Record<string, any> = {};
            let count = 0;

            activeTasks.forEach(task => {
                const rec = dayRecords.find(r => r.taskId === task.id);
                if (rec) {
                    initialUpdates[task.id] = {
                        intensity: rec.intensity,
                        value: rec.value,
                        isMarked: true
                    };
                    count++;
                } else {
                    initialUpdates[task.id] = {
                        intensity: null,
                        value: undefined,
                        isMarked: false
                    };
                }
            });
            setUpdates(initialUpdates);
            setReviewedCount(count);
        }
    }, [isOpen, records, tasks]);

    const handleToggle = (taskId: string) => {
        setUpdates(prev => {
            const isMarked = !prev[taskId]?.isMarked;
            // Update reviewed count roughly
            setReviewedCount(Object.values({ ...prev, [taskId]: { ...prev[taskId], isMarked } }).filter((u: any) => u.isMarked).length);

            return {
                ...prev,
                [taskId]: {
                    ...prev[taskId],
                    isMarked,
                    intensity: isMarked && !prev[taskId]?.intensity ? 1 : prev[taskId]?.intensity
                }
            };
        });
    };

    const handleValueChange = (taskId: string, value: string) => {
        const numVal = parseFloat(value);
        setUpdates(prev => {
            const newState = {
                ...prev,
                [taskId]: {
                    ...prev[taskId],
                    value: isNaN(numVal) ? undefined : numVal,
                    isMarked: value !== ''
                }
            };
            setReviewedCount(Object.values(newState).filter((u: any) => u.isMarked).length);
            return newState;
        });
    };

    const handleSave = async () => {
        setIsSaving(true);
        const promises = activeTasks.map(async (task) => {
            const update = updates[task.id];
            if (update?.isMarked) {
                const status = await addRecord(dateStr, task.id, update.intensity || 1, update.value);

                // Immediate feedback for mercy/failure in the loop? 
                // Or collect them? Collecting is better UX but simpler to just alert for now.
                if (status.valid && status.mercyUsed) {
                    alert(`⚠️ Mercy Used for ${task.name}\n\n"I have given you this for now."`);
                } else if (!status.valid) {
                    alert(`❌ Streak Risk for ${task.name}\n\nMercy exhausted. This won't count for streak.`);
                }
            } else {
                const dayRecords = records[dateStr] || [];
                if (dayRecords.some(r => r.taskId === task.id)) {
                    await deleteRecord(dateStr, task.id);
                }
            }
        });

        await Promise.all(promises);

        // Show success briefly? For now just close.
        setIsSaving(false);
        onClose();
    };

    if (!isOpen) return null;

    const progress = Math.round((reviewedCount / activeTasks.length) * 100) || 0;

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            {/* Backdrop with Blur */}
            <div className="absolute inset-0 bg-black/80 backdrop-blur-xl animate-[fadeIn_0.5s_ease-out]" onClick={onClose} />

            {/* Main Modal */}
            <div className="relative w-full max-w-lg bg-[#09090b] border border-white/10 rounded-3xl p-0 shadow-[0_0_50px_rgba(0,0,0,0.8)] h-[85vh] flex flex-col animate-[messageSlideIn_0.4s_cubic-bezier(0.16,1,0.3,1)] overflow-hidden">

                {/* Header Section */}
                <div className="relative p-6 pb-2 border-b border-white/5 bg-zinc-900/50">
                    <div className="flex items-center justify-between mb-4">
                        <div>
                            <h2 className="text-2xl font-black text-white flex items-center gap-2 tracking-tight">
                                <Sparkles className="w-5 h-5 text-yellow-500 animate-pulse" /> Ritual Review
                            </h2>
                            <p className="text-zinc-500 text-sm font-medium">{dateStr}</p>
                        </div>
                        <button onClick={onClose} className="p-2 bg-white/5 rounded-full hover:bg-white/10 text-zinc-400 hover:text-white transition-all transform hover:rotate-90">
                            <X className="w-5 h-5" />
                        </button>
                    </div>

                    {/* Progress Bar */}
                    <div className="w-full h-1.5 bg-zinc-800 rounded-full overflow-hidden mb-2">
                        <div
                            className="h-full bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500 transition-all duration-700 ease-out"
                            style={{ width: `${progress}%` }}
                        />
                    </div>
                    <div className="flex justify-between text-[10px] uppercase tracking-widest text-zinc-500 font-bold">
                        <span>Daily Consistency</span>
                        <span>{progress}%</span>
                    </div>
                </div>

                {/* List Container */}
                <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-3">
                    {activeTasks.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-full text-zinc-500 gap-4">
                            <Moon className="w-12 h-12 opacity-20" />
                            <p>No rituals to review.</p>
                        </div>
                    ) : (
                        activeTasks.map(task => {
                            const state = updates[task.id] || { isMarked: false, intensity: null };
                            const isDone = state.isMarked;

                            return (
                                <div
                                    key={task.id}
                                    onClick={() => handleToggle(task.id)}
                                    className={`group relative p-4 rounded-2xl border transition-all duration-300 cursor-pointer overflow-hidden ${isDone
                                        ? 'bg-zinc-900 border-white/10'
                                        : 'bg-black/20 border-white/5 hover:bg-zinc-900/30 hover:border-white/10'
                                        }`}
                                    style={isDone ? {
                                        boxShadow: `inset 0 0 20px ${task.color}10, 0 4px 20px rgba(0,0,0,0.5)`,
                                        borderColor: `${task.color}40`
                                    } : {}}
                                >
                                    {/* Background Glow Effect */}
                                    {isDone && (
                                        <div
                                            className="absolute inset-0 opacity-10 blur-xl transition-all duration-500"
                                            style={{ background: `radial-gradient(circle at center, ${task.color}, transparent 70%)` }}
                                        />
                                    )}

                                    <div className="relative flex items-center gap-4 z-10">
                                        {/* Custom Checkbox */}
                                        <div
                                            className={`flex-shrink-0 w-10 h-10 rounded-xl border flex items-center justify-center transition-all duration-300 ${isDone
                                                ? 'bg-white text-black scale-100'
                                                : 'bg-white/5 border-white/10 text-transparent scale-90 group-hover:scale-95'
                                                }`}
                                            style={isDone ? {
                                                borderColor: task.color,
                                                backgroundColor: task.color,
                                                color: '#000' // Assuming dark text on colored bg, or white on dark? Let's use black text for vibrant colors.
                                            } : {}}
                                        >
                                            <Check className="w-6 h-6" strokeWidth={3} />
                                        </div>

                                        {/* Task Details */}
                                        <div className="flex-1 min-w-0">
                                            <h3 className={`font-bold text-lg leading-tight transition-colors duration-300 ${isDone ? 'text-white' : 'text-zinc-400 group-hover:text-zinc-200'}`}>
                                                {task.name}
                                            </h3>

                                            <div className="mt-4" onClick={e => e.stopPropagation()}>
                                                {task.metricConfig ? (
                                                    <div className="space-y-3 animate-[fadeIn_0.3s_ease-out]">
                                                        {/* Animated Phase Selector */}
                                                        {task.metricConfig.phases && task.metricConfig.phases.length > 0 && isDone && (
                                                            <div className="space-y-1.5">
                                                                <div className="text-[10px] uppercase tracking-widest text-zinc-500 font-bold pl-1">Select Intensity</div>
                                                                <div className="flex flex-wrap gap-2">
                                                                    {task.metricConfig.phases.sort((a, b) => a.threshold - b.threshold).map(phase => {
                                                                        const isActivePhase = (state.value || 0) >= phase.threshold;
                                                                        // Actually, active means we met the threshold.

                                                                        return (
                                                                            <button
                                                                                key={phase.name}
                                                                                onClick={(e) => {
                                                                                    e.stopPropagation();
                                                                                    handleValueChange(task.id, phase.threshold.toString());
                                                                                }}
                                                                                className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all duration-300 relative overflow-hidden group/phase ${isActivePhase
                                                                                    ? 'text-black shadow-[0_0_15px_rgba(255,255,255,0.4)] scale-105'
                                                                                    : 'bg-white/5 text-zinc-500 hover:bg-white/10 hover:text-white border border-white/5'
                                                                                    }`}
                                                                                style={isActivePhase ? {
                                                                                    backgroundColor: 'white',
                                                                                    borderColor: 'white'
                                                                                } : {}}
                                                                            >
                                                                                <span className="relative z-10">{phase.name}</span>
                                                                                {isActivePhase && <div className="absolute inset-0 bg-gradient-to-tr from-transparent via-white to-transparent opacity-50 animate-[shimmer_1s_infinite]" />}
                                                                            </button>
                                                                        );
                                                                    })}
                                                                </div>
                                                            </div>
                                                        )}

                                                        {/* Precision Metric Input */}
                                                        {isDone && (
                                                            <div className="bg-black/40 rounded-xl p-3 border border-white/5 flex items-center justify-between group/input hover:border-white/10 transition-colors">
                                                                <span className="text-xs text-zinc-500 font-bold uppercase tracking-wider pl-1">Exact Value</span>
                                                                <div className="flex items-center gap-2">
                                                                    <input
                                                                        type="number"
                                                                        placeholder="0"
                                                                        value={state.value || ''}
                                                                        onChange={(e) => handleValueChange(task.id, e.target.value)}
                                                                        className="bg-transparent text-right text-xl font-black text-white w-24 focus:outline-none placeholder:text-zinc-800"
                                                                    />
                                                                    <span className="text-xs text-zinc-500 font-bold">{task.metricConfig.unit}</span>
                                                                </div>
                                                            </div>
                                                        )}
                                                    </div>
                                                ) : (
                                                    // "Square Cells" Intensity Bar
                                                    isDone && (
                                                        <div className="animate-[fadeIn_0.3s_ease-out] w-full max-w-[200px]">
                                                            <div className="flex justify-between text-[10px] uppercase font-bold text-zinc-500 mb-2 px-1">
                                                                <span>Effort Level</span>
                                                                <span className="text-white">{state.intensity === 4 ? 'MAXIMUM' : state.intensity === 3 ? 'High' : state.intensity === 2 ? 'Medium' : 'Low'}</span>
                                                            </div>
                                                            <div className="flex gap-2 h-8">
                                                                {[1, 2, 3, 4].map(lvl => {
                                                                    const isActive = (state.intensity || 0) >= lvl;
                                                                    return (
                                                                        <button
                                                                            key={lvl}
                                                                            onClick={(e) => {
                                                                                e.stopPropagation();
                                                                                setUpdates(prev => ({
                                                                                    ...prev,
                                                                                    [task.id]: { ...prev[task.id], intensity: lvl }
                                                                                }));
                                                                            }}
                                                                            className={`flex-1 aspect-square rounded-md transition-all duration-200 ${isActive
                                                                                ? 'bg-white'
                                                                                : 'bg-zinc-800 hover:bg-zinc-700'
                                                                                }`}
                                                                        />
                                                                    );
                                                                })}
                                                            </div>
                                                        </div>
                                                    )
                                                )}
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            );
                        })
                    )}
                </div>

                {/* Footer Action */}
                <div className="p-6 bg-zinc-900/80 backdrop-blur-md border-t border-white/5">
                    <button
                        onClick={handleSave}
                        disabled={isSaving}
                        className="group w-full py-4 bg-white text-black font-black text-lg uppercase tracking-widest rounded-xl hover:bg-slate-200 transition-all duration-300 hover:scale-[1.01] active:scale-[0.99] shadow-[0_0_30px_rgba(255,255,255,0.15)] disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-3 relative overflow-hidden"
                    >
                        {/* Shimmer overlay */}
                        <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/50 to-transparent translate-x-[-100%] group-hover:animate-[shimmer_1.5s_infinite]" />

                        {isSaving ? (
                            <span>Committing to Memory...</span>
                        ) : (
                            <>
                                End The Day <ArrowRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
                            </>
                        )}
                    </button>
                    <p className="text-center text-[10px] text-zinc-600 mt-3 font-medium uppercase tracking-widest">
                        Consistent action creates character
                    </p>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useRef, useEffect } from 'react';
import { X, Upload, Loader2, Camera, Trash2 } from 'lucide-react';
import { createClient } from '@/utils/supabase/client';
import { User } from '@supabase/supabase-js';

interface EditProfileModalProps {
    isOpen: boolean;
    onClose: () => void;
    user: User | null;
    onUpdate: () => void;
}

export function EditProfileModal({ isOpen, onClose, user, onUpdate }: EditProfileModalProps) {
    const [fullName, setFullName] = useState('');
    const [bio, setBio] = useState('');
    const [avatarUrl, setAvatarUrl] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [file, setFile] = useState<File | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        if (user) {
            setFullName(user.user_metadata?.full_name || '');
            setBio(user.user_metadata?.bio || '');
            setAvatarUrl(user.user_metadata?.avatar_url || '');
        }
    }, [user, isOpen]);

    if (!isOpen) return null;

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            const selectedFile = e.target.files[0];
            setFile(selectedFile);
            setAvatarUrl(URL.createObjectURL(selectedFile)); // Preview
        }
    };

    const handleSave = async () => {
        if (!user) return;
        setIsLoading(true);

        try {
            const supabase = createClient();
            let uploadedAvatarUrl = user.user_metadata?.avatar_url;

            // 1. Upload Image if changed
            if (file) {
                // Delete old avatar if exists
                const oldAvatarUrl = user.user_metadata?.avatar_url;
                if (oldAvatarUrl) {
                    try {
                        // Extract file path from URL
                        // URL format: https://<project>.supabase.co/storage/v1/object/public/avatars/<filename>
                        const urlParts = oldAvatarUrl.split('/avatars/');
                        if (urlParts.length > 1) {
                            const oldFileName = urlParts[1];
                            await supabase.storage
                                .from('avatars')
                                .remove([oldFileName]);
                            console.log('Deleted old avatar:', oldFileName);
                        }
                    } catch (deleteError) {
                        console.warn('Could not delete old avatar:', deleteError);
                        // Don't fail upload if deletion fails
                    }
                }

                const fileExt = file.name.split('.').pop();
                const fileName = `${user.id}-${Date.now()}.${fileExt}`;
                const filePath = `${fileName}`;

                const { error: uploadError } = await supabase.storage
                    .from('avatars')
                    .upload(filePath, file);

                if (uploadError) {
                    console.error('Upload error:', uploadError);
                    // Fallback check - maybe create bucket? (Can't via client usually)
                    alert("Failed to upload image. Ensure 'avatars' bucket exists and is public.");
                } else {
                    const { data: { publicUrl } } = supabase.storage
                        .from('avatars')
                        .getPublicUrl(filePath);
                    uploadedAvatarUrl = publicUrl;
                }
            }

            // 2. Update User Metadata
            const { error: updateError } = await supabase.auth.updateUser({
                data: {
                    full_name: fullName,
                    bio: bio,
                    avatar_url: uploadedAvatarUrl
                }
            });

            if (updateError) throw updateError;

            // 3. Sync to profiles table (for public access in World/etc)
            const { error: profileError } = await supabase
                .from('profiles')
                .upsert({
                    id: user.id,
                    email: user.email,
                    full_name: fullName,
                    bio: bio,
                    avatar_url: uploadedAvatarUrl,
                    updated_at: new Date().toISOString()
                }, {
                    onConflict: 'id'
                });

            if (profileError) {
                console.error('Profile sync error:', profileError);
                // Don't throw - user_metadata is already updated
            }

            onUpdate(); // Refresh parent
            onClose();
        } catch (error) {
            console.error('Update error:', error);
            alert("Failed to update profile.");
        } finally {
            setIsLoading(false);
        }
    };

    const handleRemovePhoto = async () => {
        if (!user) return;
        setIsLoading(true);

        try {
            const supabase = createClient();
            const oldAvatarUrl = user.user_metadata?.avatar_url;

            // Delete from storage if exists
            if (oldAvatarUrl) {
                try {
                    const urlParts = oldAvatarUrl.split('/avatars/');
                    if (urlParts.length > 1) {
                        const oldFileName = urlParts[1];
                        await supabase.storage
                            .from('avatars')
                            .remove([oldFileName]);
                    }
                } catch (deleteError) {
                    console.warn('Could not delete avatar from storage:', deleteError);
                }
            }

            // Update user metadata - set avatar_url to null
            const { error: updateError } = await supabase.auth.updateUser({
                data: {
                    full_name: fullName,
                    bio: bio,
                    avatar_url: null  // Remove avatar
                }
            });

            if (updateError) throw updateError;

            // Sync to profiles table
            const { error: profileError } = await supabase
                .from('profiles')
                .upsert({
                    id: user.id,
                    email: user.email,
                    full_name: fullName,
                    bio: bio,
                    avatar_url: null,  // Remove avatar
                    updated_at: new Date().toISOString()
                }, {
                    onConflict: 'id'
                });

            if (profileError) {
                console.error('Profile sync error:', profileError);
            }

            setAvatarUrl('');  // Clear preview
            setFile(null);
            onUpdate();
            onClose();
        } catch (error) {
            console.error('Remove photo error:', error);
            alert("Failed to remove photo.");
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            {/* Backdrop */}
            <div
                className="absolute inset-0 bg-black/80 backdrop-blur-md animate-[fadeIn_0.3s_ease-out]"
                onClick={onClose}
            />

            {/* Modal */}
            <div className="relative w-full max-w-md bg-[#0a0a0a] border border-white/10 rounded-xl overflow-hidden shadow-2xl animate-[scaleIn_0.3s_ease-out]">
                <div className="flex items-center justify-between p-4 border-b border-white/5">
                    <h2 className="text-lg font-bold text-white">Edit Profile</h2>
                    <button onClick={onClose} className="text-zinc-500 hover:text-white transition-colors">
                        <X className="w-5 h-5" />
                    </button>
                </div>

                <div className="p-6 space-y-6">
                    {/* Avatar Upload */}
                    <div className="flex flex-col items-center gap-4">
                        <div className="relative group cursor-pointer" onClick={() => fileInputRef.current?.click()}>
                            <div className="w-24 h-24 rounded-full overflow-hidden border-2 border-white/10 group-hover:border-white/50 transition-colors">
                                {avatarUrl ? (
                                    <img src={avatarUrl} alt="Avatar" className="w-full h-full object-cover" />
                                ) : (
                                    <div className="w-full h-full bg-zinc-800 flex items-center justify-center text-zinc-500 text-2xl font-bold">
                                        {fullName?.[0] || "?"}
                                    </div>
                                )}
                            </div>
                            <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 flex items-center justify-center rounded-full transition-opacity">
                                <Camera className="w-6 h-6 text-white" />
                            </div>
                        </div>
                        <input
                            type="file"
                            ref={fileInputRef}
                            onChange={handleFileChange}
                            accept="image/*"
                            className="hidden"
                        />
                        <button
                            onClick={() => fileInputRef.current?.click()}
                            className="text-blue-400 text-sm font-semibold hover:text-blue-300 transition-colors"
                        >
                            Change Profile Photo
                        </button>
                        {(user?.user_metadata?.avatar_url || avatarUrl) && (
                            <button
                                onClick={handleRemovePhoto}
                                disabled={isLoading}
                                className="text-red-400 text-sm font-semibold hover:text-red-300 transition-colors flex items-center gap-1.5 disabled:opacity-50"
                            >
                                <Trash2 className="w-3.5 h-3.5" />
                                Remove Photo
                            </button>
                        )}
                    </div>

                    {/* Inputs */}
                    <div className="space-y-4">
                        <div className="space-y-1">
                            <label className="text-xs font-bold text-zinc-400 uppercase tracking-wider">Name</label>
                            <input
                                type="text"
                                value={fullName}
                                onChange={(e) => setFullName(e.target.value)}
                                className="w-full bg-black border border-white/20 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-white transition-colors placeholder:text-zinc-700"
                                placeholder="Your Name"
                            />
                        </div>

                        <div className="space-y-1">
                            <label className="text-xs font-bold text-zinc-400 uppercase tracking-wider">Bio</label>
                            <textarea
                                value={bio}
                                onChange={(e) => setBio(e.target.value)}
                                className="w-full bg-black border border-white/20 rounded-lg px-3 py-2 text-white focus:outline-none focus:border-white transition-colors placeholder:text-zinc-700 min-h-[100px] resize-none"
                                placeholder="Tell your story..."
                            />
                        </div>
                    </div>

                    <button
                        onClick={handleSave}
                        disabled={isLoading}
                        className="w-full py-3 bg-white text-black font-bold rounded-lg hover:bg-zinc-200 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                    >
                        {isLoading && <Loader2 className="w-4 h-4 animate-spin" />}
                        {isLoading ? "Saving..." : "Save Changes"}
                    </button>
                </div>
            </div>
        </div>
    );
}

