"use client";

import { useUserData, DEFAULT_FACTIONS } from "@/context/user-data-context";
import { Shield, Check, X, Flame, Snowflake, Leaf, Waves, Cloud, Sun, Zap, Fish, PawPrint } from "lucide-react";
import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

function FactionCardEffect({ factionName }: { factionName: string }) {
    if (factionName === 'House Stark') {
        return (
            <div className="absolute inset-0 pointer-events-none overflow-hidden pb-10">
                {[...Array(20)].map((_, i) => {
                    const size = 1 + Math.random() * 3;
                    const blur = Math.random() > 0.7 ? 'blur(1px)' : 'none';
                    return (
                        <motion.div
                            key={i}
                            className="absolute bg-white rounded-full opacity-40 shadow-[0_0_5px_rgba(255,255,255,0.3)]"
                            initial={{ top: -20, left: `${Math.random() * 120 - 10}%` }}
                            animate={{
                                top: '120%',
                                left: [`${Math.random() * 100}%`, `${Math.random() * 100}%`],
                                opacity: [0, 0.6, 0]
                            }}
                            style={{ width: size, height: size, filter: blur }}
                            transition={{
                                duration: 4 + Math.random() * 4,
                                repeat: Infinity,
                                ease: "linear",
                                delay: Math.random() * 10
                            }}
                        />
                    );
                })}
            </div>
        );
    }

    if (factionName === 'House Targaryen') {
        return (
            <div className="absolute inset-0 pointer-events-none overflow-hidden">
                {/* Heat Haze / Core Glow */}
                <motion.div
                    className="absolute -bottom-20 -left-10 w-[150%] h-[150%] rounded-full opacity-20 blur-[100px]"
                    style={{ background: 'radial-gradient(circle, #ef4444 0%, transparent 70%)' }}
                    animate={{
                        scale: [1, 1.2, 1],
                        opacity: [0.1, 0.3, 0.1]
                    }}
                    transition={{ duration: 4, repeat: Infinity, ease: "easeInOut" }}
                />

                {/* Embers */}
                {[...Array(15)].map((_, i) => (
                    <motion.div
                        key={i}
                        className="absolute rounded-full"
                        style={{
                            width: 1 + Math.random() * 3,
                            height: 1 + Math.random() * 3,
                            background: Math.random() > 0.5 ? '#f97316' : '#ef4444',
                            boxShadow: '0 0 10px #f97316'
                        }}
                        initial={{ bottom: -20, left: `${Math.random() * 100}%` }}
                        animate={{
                            bottom: '120%',
                            left: [`${Math.random() * 100}%`, `${Math.random() * 100}%`, `${Math.random() * 100}%`],
                            opacity: [0, 1, 0],
                            scale: [0.5, 1.5, 0.5],
                            rotate: [0, 360]
                        }}
                        transition={{
                            duration: 3 + Math.random() * 3,
                            repeat: Infinity,
                            ease: "easeOut",
                            delay: Math.random() * 5
                        }}
                    />
                ))}

                {/* Dragons */}
                {[...Array(2)].map((_, i) => (
                    <motion.div
                        key={`dragon-${i}`}
                        className="absolute text-red-950/20 pointer-events-none"
                        initial={{
                            left: i === 0 ? '-20%' : '110%',
                            top: `${20 + Math.random() * 40}%`,
                            scale: 0.4 + Math.random() * 0.4,
                            rotate: i === 0 ? 0 : 180
                        }}
                        animate={{
                            left: i === 0 ? '120%' : '-30%',
                            y: [0, -20, 20, 0],
                        }}
                        transition={{
                            duration: 10 + Math.random() * 5,
                            repeat: Infinity,
                            ease: "linear",
                            delay: i * 4
                        }}
                    >
                        <svg width="100" height="60" viewBox="0 0 100 60" fill="currentColor">
                            <path d="M10,30 Q30,10 50,30 T90,30 M50,30 L45,20 M50,30 L45,40 M30,20 Q40,5 50,20 M70,20 Q60,5 50,20" stroke="currentColor" strokeWidth="2" fill="none" />
                            <path d="M50,30 C60,20 80,20 90,30 C80,40 60,40 50,30" />
                            <path d="M20,30 C30,20 40,20 50,30 C40,40 30,40 20,30" />
                        </svg>
                    </motion.div>
                ))}
            </div>
        );
    }

    if (factionName === 'House Greyjoy') {
        return (
            <div className="absolute inset-0 pointer-events-none overflow-hidden bg-slate-950/20">
                {/* Falling Rain */}
                {[...Array(25)].map((_, i) => (
                    <motion.div
                        key={i}
                        className="absolute bg-blue-400/20"
                        style={{ width: '1px', height: 10 + Math.random() * 20 }}
                        initial={{ top: -50, left: `${Math.random() * 100}%` }}
                        animate={{ top: '110%' }}
                        transition={{
                            duration: 0.5 + Math.random() * 0.3,
                            repeat: Infinity,
                            ease: "linear",
                            delay: Math.random() * 2
                        }}
                    />
                ))}
                {/* Splashes */}
                {[...Array(8)].map((_, i) => (
                    <motion.div
                        key={`s-${i}`}
                        className="absolute border border-blue-400/10 rounded-full"
                        style={{ bottom: 0, left: `${Math.random() * 100}%` }}
                        initial={{ width: 0, height: 0, opacity: 0.5 }}
                        animate={{ width: 40, height: 10, opacity: 0, x: -20 }}
                        transition={{
                            duration: 1 + Math.random(),
                            repeat: Infinity,
                            delay: Math.random() * 3
                        }}
                    />
                ))}
            </div>
        );
    }

    if (factionName === 'House Lannister') {
        return (
            <div className="absolute inset-0 pointer-events-none overflow-hidden">
                <motion.div
                    className="absolute inset-x-0 top-0 h-1/2 bg-gradient-to-b from-yellow-500/10 to-transparent"
                    animate={{ opacity: [0.2, 0.4, 0.2] }}
                    transition={{ duration: 4, repeat: Infinity }}
                />
                {[...Array(12)].map((_, i) => (
                    <motion.div
                        key={i}
                        className="absolute w-2 h-2"
                        initial={{ top: '100%', left: `${Math.random() * 100}%`, scale: 0, rotate: 0 }}
                        animate={{
                            top: '-10%',
                            left: [`${Math.random() * 100}%`, `${Math.random() * 100}%`],
                            scale: [0, 1, 0],
                            rotate: [0, 360]
                        }}
                        transition={{
                            duration: 5 + Math.random() * 5,
                            repeat: Infinity,
                            ease: "easeOut",
                            delay: Math.random() * 10
                        }}
                    >
                        <div className="w-full h-full bg-yellow-400 rounded-sm shadow-[0_0_10px_#eab308] rotate-45" />
                    </motion.div>
                ))}
            </div>
        );
    }

    if (factionName === 'House Tyrell') {
        return (
            <div className="absolute inset-0 pointer-events-none overflow-hidden">
                {[...Array(10)].map((_, i) => (
                    <motion.div
                        key={i}
                        className="absolute text-green-600/30"
                        initial={{
                            top: -30,
                            left: `${Math.random() * 100}%`,
                            rotate: Math.random() * 360,
                            scale: 0.5 + Math.random() * 0.5
                        }}
                        animate={{
                            top: '110%',
                            left: [`${Math.random() * 100}%`, `${Math.random() * 100}%`, `${Math.random() * 100}%`],
                            rotate: [0, 360 * (Math.random() > 0.5 ? 1 : -1)],
                            opacity: [0, 1, 1, 0]
                        }}
                        transition={{
                            duration: 6 + Math.random() * 6,
                            repeat: Infinity,
                            ease: "easeInOut",
                            delay: Math.random() * 10
                        }}
                    >
                        <Leaf size={16 + Math.random() * 10} />
                    </motion.div>
                ))}
            </div>
        );
    }

    if (factionName === 'House Martell') {
        return (
            <div className="absolute inset-0 pointer-events-none overflow-hidden">
                {/* Heat Distortion / Sun Glow */}
                <motion.div
                    className="absolute inset-0 bg-orange-500/5 blur-[40px]"
                    animate={{
                        opacity: [0.1, 0.4, 0.1],
                        scale: [1, 1.1, 1]
                    }}
                    transition={{ duration: 5, repeat: Infinity }}
                />
                <div className="absolute top-0 right-0 p-6 opacity-10">
                    <motion.div
                        animate={{ rotate: 360 }}
                        transition={{ duration: 40, repeat: Infinity, ease: "linear" }}
                    >
                        <Sun size={120} strokeWidth={0.5} />
                    </motion.div>
                </div>
                {/* Sand Dust Particles */}
                {[...Array(15)].map((_, i) => (
                    <motion.div
                        key={i}
                        className="absolute bg-orange-300/20 rounded-full"
                        style={{ width: 1 + Math.random() * 2, height: 1 + Math.random() * 2 }}
                        initial={{ left: '-10%', top: `${Math.random() * 100}%` }}
                        animate={{
                            left: '110%',
                            top: `${Math.random() * 100}%`,
                            opacity: [0, 0.5, 0]
                        }}
                        transition={{
                            duration: 3 + Math.random() * 4,
                            repeat: Infinity,
                            ease: "linear",
                            delay: Math.random() * 5
                        }}
                    />
                ))}
            </div>
        );
    }

    if (factionName === 'House Baratheon') {
        return (
            <div className="absolute inset-0 pointer-events-none overflow-hidden">
                {/* Lightning */}
                <motion.div
                    className="absolute inset-0 bg-blue-100 opacity-0"
                    animate={{
                        opacity: [0, 0, 0.8, 0, 0.5, 0, 0, 0]
                    }}
                    transition={{
                        duration: 8,
                        repeat: Infinity,
                        times: [0, 0.7, 0.72, 0.74, 0.76, 0.78, 0.8, 1]
                    }}
                />
                {/* Distant Clouds */}
                {[...Array(3)].map((_, i) => (
                    <motion.div
                        key={i}
                        className="absolute text-slate-800/40"
                        initial={{ left: '-20%', top: `${10 + i * 30}%` }}
                        animate={{ left: '120%' }}
                        transition={{
                            duration: 20 + Math.random() * 20,
                            repeat: Infinity,
                            ease: "linear"
                        }}
                    >
                        <Cloud size={100} strokeWidth={0.5} />
                    </motion.div>
                ))}
            </div>
        );
    }

    if (factionName === 'House Arryn') {
        return (
            <div className="absolute inset-0 pointer-events-none overflow-hidden">
                {[...Array(6)].map((_, i) => (
                    <motion.div
                        key={i}
                        className="absolute text-blue-100/30"
                        initial={{ left: '-30%', top: `${Math.random() * 80}%`, scale: 0.5 + Math.random() }}
                        animate={{
                            left: '130%',
                            y: [0, 20, 0]
                        }}
                        transition={{
                            duration: 15 + Math.random() * 15,
                            repeat: Infinity,
                            ease: "linear",
                            delay: Math.random() * 10
                        }}
                    >
                        <Cloud size={60} strokeWidth={1} />
                    </motion.div>
                ))}
            </div>
        );
    }

    if (factionName === 'House Mormont') {
        return (
            <div className="absolute inset-0 pointer-events-none overflow-hidden opacity-10">
                {[...Array(4)].map((_, i) => (
                    <motion.div
                        key={i}
                        className="absolute text-emerald-900/40"
                        initial={{ scale: 0.8, opacity: 0, rotate: Math.random() * 30 }}
                        animate={{ scale: [0.8, 1.2, 0.8], opacity: [0.2, 0.5, 0.2] }}
                        transition={{ duration: 4, repeat: Infinity, delay: i * 1.5 }}
                        style={{ left: `${15 + i * 25}%`, top: `${20 + i * 20}%` }}
                    >
                        <PawPrint size={40} />
                    </motion.div>
                ))}
            </div>
        );
    }

    if (factionName === 'House Tully') {
        return (
            <div className="absolute inset-0 pointer-events-none overflow-hidden opacity-20">
                {[...Array(6)].map((_, i) => (
                    <motion.div
                        key={i}
                        className="absolute text-blue-400/30"
                        initial={{ left: '-20%', top: `${20 + i * 15}%` }}
                        animate={{
                            left: '120%',
                            y: [0, 10, -10, 0]
                        }}
                        transition={{
                            duration: 5 + Math.random() * 3,
                            repeat: Infinity,
                            ease: "easeInOut",
                            delay: Math.random() * 5
                        }}
                    >
                        <Fish size={24} />
                    </motion.div>
                ))}
            </div>
        );
    }

    return null;
}

interface FactionPickerModalProps {
    isOpen: boolean;
    onClose: () => void;
}

export function FactionPickerModal({ isOpen, onClose }: FactionPickerModalProps) {
    const { factions, currentFaction, setFaction } = useUserData();
    const [selectedId, setSelectedId] = useState<string | null>(currentFaction?.id || null);

    // Robust Fallback: If context factions are missing, use defaults
    const displayFactions = (factions && factions.length > 0) ? factions : DEFAULT_FACTIONS;

    if (!isOpen) return null;

    const handleConfirm = async () => {
        if (selectedId) {
            await setFaction(selectedId);
            onClose();
        }
    };

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/90 backdrop-blur-xl" onClick={onClose} />

            <div className="relative max-w-4xl w-full bg-zinc-950 border border-white/10 rounded-[2.5rem] overflow-hidden shadow-2xl flex flex-col max-h-[90vh]">
                {/* Header */}
                <div className="p-8 md:p-12 text-center space-y-2 border-b border-white/5">
                    <h2 className="text-3xl font-bold tracking-tighter text-white">Choose Your House</h2>
                    <p className="text-zinc-500 text-sm">Align your spirit with a legacy. This choice will define your Sigil.</p>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto p-8 grid grid-cols-1 md:grid-cols-2 gap-6">
                    {displayFactions.map((f) => {
                        const isSelected = selectedId === f.id;
                        return (
                            <motion.button
                                key={f.id}
                                whileHover={{ scale: 1.02, y: -2 }}
                                whileTap={{ scale: 0.98 }}
                                onClick={() => setSelectedId(f.id)}
                                className={`relative group text-left p-8 rounded-[2rem] border transition-all duration-500 min-h-[140px] flex items-center overflow-hidden ${isSelected
                                    ? 'bg-white/5 border-white/20 ring-1 ring-white/10'
                                    : 'bg-transparent border-white/5 hover:border-white/10 hover:bg-white/[0.02]'
                                    }`}
                            >
                                <div className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-300 pointer-events-none">
                                    <FactionCardEffect factionName={f.name} />
                                </div>
                                {/* Faction Glow */}
                                <div
                                    className="absolute -top-12 -right-12 w-48 h-48 rounded-full blur-[100px] opacity-20 transition-opacity group-hover:opacity-40 pointer-events-none"
                                    style={{ backgroundColor: f.primaryColor }}
                                />

                                <div className="relative flex items-center gap-6 w-full">
                                    <div className="shrink-0 relative">
                                        <div className="w-16 h-16 rounded-2xl bg-zinc-900 border border-white/10 flex items-center justify-center overflow-hidden shadow-2xl group-hover:border-white/20 transition-all p-1">
                                            <img src={f.sigilUrl} alt={f.name} className="w-full h-full object-cover rounded-xl group-hover:scale-110 transition-transform duration-500" />
                                        </div>
                                        {isSelected && (
                                            <motion.div
                                                initial={{ scale: 0 }}
                                                animate={{ scale: 1 }}
                                                className="absolute -top-2 -right-2 w-7 h-7 rounded-full bg-white text-black flex items-center justify-center shadow-xl z-20"
                                            >
                                                <Check className="w-4 h-4" />
                                            </motion.div>
                                        )}
                                    </div>

                                    <div className="flex-1 min-w-0">
                                        <h3 className="text-xl font-bold text-white group-hover:translate-x-1 transition-transform truncate">{f.name}</h3>
                                        <p className="text-sm font-serif italic text-zinc-500 mt-1 line-clamp-1 group-hover:text-zinc-400 transition-colors">"{f.quote}"</p>
                                    </div>
                                </div>
                            </motion.button>
                        );
                    })}
                </div>

                {/* Footer */}
                <div className="p-8 flex gap-4 border-t border-white/5 bg-zinc-950/50">
                    <button
                        onClick={onClose}
                        className="flex-1 py-4 text-zinc-500 font-medium hover:text-white transition-colors"
                    >
                        Dismiss
                    </button>
                    <button
                        onClick={handleConfirm}
                        disabled={!selectedId}
                        className="flex-[2] py-4 bg-white text-black font-bold rounded-2xl hover:scale-[1.02] active:scale-95 transition-all disabled:opacity-50 disabled:scale-100"
                    >
                        Pledge Loyalty
                    </button>
                </div>

                <button
                    onClick={onClose}
                    className="absolute top-6 right-6 w-10 h-10 rounded-full bg-white/5 flex items-center justify-center text-zinc-400 hover:text-white transition-all hover:rotate-90"
                >
                    <X className="w-5 h-5" />
                </button>
            </div>
        </div>
    );
}

import { useEffect, useState } from 'react';
import { createClient } from '@/utils/supabase/client';
import { X, Check, UserPlus, Shield } from 'lucide-react';
import { getUserAvatar } from '@/utils/avatar-helpers';

interface FriendRequest {
    id: string;
    created_at: string;
    user: {
        id: string;
        username: string | null;
        full_name: string | null;
        avatar_url: string | null;
        gender: string | null;
    };
}

interface FriendRequestsModalProps {
    isOpen: boolean;
    onClose: () => void;
    currentUserId: string;
}

export function FriendRequestsModal({ isOpen, onClose, currentUserId }: FriendRequestsModalProps) {
    const [requests, setRequests] = useState<FriendRequest[]>([]);
    const [loading, setLoading] = useState(false);
    const supabase = createClient();

    useEffect(() => {
        if (isOpen && currentUserId) {
            loadRequests();
        }
    }, [isOpen, currentUserId]);

    const loadRequests = async () => {
        setLoading(true);
        // Safety timeout to prevent infinite spinner
        const safetyTimer = setTimeout(() => {
            console.warn('Friend request loading timed out');
            setLoading(false);
        }, 8000);

        try {
            // 1. Fetch pending requests
            const { data: friendships, error: friendError } = await supabase
                .from('friendships')
                .select('id, created_at, user_id')
                .eq('friend_id', currentUserId)
                .eq('status', 'pending');

            if (friendError) {
                console.error('Error fetching requests:', friendError);
                return;
            }

            if (!friendships || friendships.length === 0) {
                setRequests([]);
                return;
            }

            // 2. Fetch sender profiles
            const senderIds = friendships.map(f => f.user_id);
            const { data: profiles, error: profileError } = await supabase
                .from('profiles')
                .select('id, username, full_name, avatar_url, gender')
                .in('id', senderIds);

            if (profileError) {
                console.error('Error fetching profiles:', profileError);
                return;
            }

            // 3. Combine data
            const formattedRequests = friendships.map(friendship => {
                const profile = profiles?.find(p => p.id === friendship.user_id);
                return {
                    id: friendship.id,
                    created_at: friendship.created_at,
                    user: profile || {
                        id: friendship.user_id,
                        username: 'Unknown User',
                        full_name: 'Unknown User',
                        avatar_url: null,
                        gender: null
                    }
                };
            });

            setRequests(formattedRequests);
        } catch (e) {
            console.error('Unexpected error loading requests:', e);
        } finally {
            clearTimeout(safetyTimer);
            setLoading(false);
        }
    };

    const handleAccept = async (requestId: string) => {
        const { error } = await supabase
            .from('friendships')
            .update({ status: 'accepted' })
            .eq('id', requestId);

        if (!error) {
            setRequests(prev => prev.filter(r => r.id !== requestId));
            // Ideally trigger a refresh of friends list in parent, but Realtime might handle it
        }
    };

    const handleDecline = async (requestId: string) => {
        const { error } = await supabase
            .from('friendships')
            .delete()
            .eq('id', requestId);

        if (!error) {
            setRequests(prev => prev.filter(r => r.id !== requestId));
        }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
            <div className="w-full max-w-md bg-zinc-900 border border-zinc-800 rounded-2xl shadow-xl overflow-hidden animate-in zoom-in-95 duration-200">
                {/* Header */}
                <div className="p-4 border-b border-zinc-800 flex items-center justify-between bg-zinc-900/50">
                    <h2 className="text-lg font-semibold text-white flex items-center gap-2">
                        <UserPlus className="w-5 h-5 text-blue-500" />
                        Friend Requests
                        {requests.length > 0 && (
                            <span className="bg-blue-500 text-white text-xs px-2 py-0.5 rounded-full">
                                {requests.length}
                            </span>
                        )}
                    </h2>
                    <button
                        onClick={onClose}
                        className="p-1 text-zinc-400 hover:text-white rounded-full hover:bg-zinc-800 transition-colors"
                    >
                        <X className="w-5 h-5" />
                    </button>
                </div>

                {/* Content */}
                <div className="max-h-[60vh] overflow-y-auto p-2">
                    {loading ? (
                        <div className="flex justify-center py-8">
                            <div className="w-6 h-6 border-2 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
                        </div>
                    ) : requests.length === 0 ? (
                        <div className="text-center py-12 px-4">
                            <div className="w-12 h-12 bg-zinc-800 rounded-full flex items-center justify-center mx-auto mb-3">
                                <Shield className="w-6 h-6 text-zinc-500" />
                            </div>
                            <h3 className="text-zinc-300 font-medium mb-1">No pending requests</h3>
                            <p className="text-sm text-zinc-500">
                                Call to the void, and perhaps it shall answer.
                            </p>
                        </div>
                    ) : (
                        <div className="space-y-1">
                            {requests.map((request) => (
                                <div
                                    key={request.id}
                                    className="p-3 rounded-xl bg-zinc-800/30 hover:bg-zinc-800/50 border border-transparent hover:border-zinc-700 transition-all group"
                                >
                                    <div className="flex items-center gap-3">
                                        <div className="relative">
                                            <img
                                                src={getUserAvatar(request.user.avatar_url, request.user.gender, request.user.id)}
                                                alt={request.user.username || 'User'}
                                                className="w-10 h-10 rounded-full object-cover border border-zinc-700"
                                            />
                                        </div>

                                        <div className="flex-1 min-w-0">
                                            <h3 className="text-sm font-medium text-white truncate">
                                                {request.user.full_name || request.user.username}
                                            </h3>
                                            <p className="text-xs text-zinc-400 truncate">
                                                @{request.user.username}
                                            </p>
                                        </div>

                                        <div className="flex items-center gap-2">
                                            <button
                                                onClick={() => handleAccept(request.id)}
                                                className="p-2 bg-blue-500/10 text-blue-400 hover:bg-blue-500 hover:text-white rounded-lg transition-colors"
                                                title="Accept"
                                            >
                                                <Check className="w-4 h-4" />
                                            </button>
                                            <button
                                                onClick={() => handleDecline(request.id)}
                                                className="p-2 bg-red-500/10 text-red-400 hover:bg-red-500 hover:text-white rounded-lg transition-colors"
                                                title="Decline"
                                            >
                                                <X className="w-4 h-4" />
                                            </button>
                                        </div>
                                    </div>
                                    <div className="mt-2 text-[10px] text-zinc-600 pl-14">
                                        Sent {new Date(request.created_at).toLocaleDateString()}
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from 'react';
import { X } from 'lucide-react';
import { useUserData, Task } from '@/context/user-data-context';

interface LogActivityModalProps {
    isOpen: boolean;
    onClose: () => void;
    dateStr: string; // Format: YYYY-MM-DD
}

export function LogActivityModal({ isOpen, onClose, dateStr }: LogActivityModalProps) {
    const { tasks, addRecord, deleteRecord, getRecordsForDate, getTaskAnalytics } = useUserData();
    const [selectedTaskId, setSelectedTaskId] = useState<string>('');
    const [useIntensity, setUseIntensity] = useState(false);
    const [intensity, setIntensity] = useState<number>(1);
    const [metricValue, setMetricValue] = useState<string>(''); // Raw input as string
    const [activePhase, setActivePhase] = useState<number | null>(null); // Calculated intensity
    const [existingRecords, setExistingRecords] = useState<any[]>([]);
    const [analytics, setAnalytics] = useState<any>(null);
    const [expandedRecords, setExpandedRecords] = useState<Set<string>>(new Set());

    const toggleRecordView = (taskId: string) => {
        setExpandedRecords(prev => {
            const next = new Set(prev);
            if (next.has(taskId)) {
                next.delete(taskId);
            } else {
                next.add(taskId);
            }
            return next;
        });
    };

    // Filter out archived tasks for the selection list
    const activeTasks = tasks.filter(t => !t.isArchived);

    useEffect(() => {
        if (isOpen) {
            // Default to first active task if none selected
            if (!selectedTaskId && activeTasks.length > 0) {
                setSelectedTaskId(activeTasks[0].id);
            }

            // Load info for this date
            const records = getRecordsForDate(dateStr);
            setExistingRecords(records);
        }
    }, [isOpen, dateStr, tasks, getRecordsForDate, selectedTaskId]);

    // Load analytics when task changes
    useEffect(() => {
        if (selectedTaskId && getTaskAnalytics) {
            const data = getTaskAnalytics(selectedTaskId);
            setAnalytics(data);
        }
    }, [selectedTaskId, getTaskAnalytics]);

    if (!isOpen) return null;

    const selectedTask = tasks.find(t => t.id === selectedTaskId);

    // Auto-calculate intensity when metric value changes
    useEffect(() => {
        if (!selectedTask?.metricConfig || !metricValue) {
            setActivePhase(null);
            return;
        }

        const val = parseFloat(metricValue);
        if (isNaN(val)) return;

        // Find highest threshold met
        const sortedPhases = [...selectedTask.metricConfig.phases].sort((a, b) => b.threshold - a.threshold);
        const matchedPhase = sortedPhases.find(p => val >= p.threshold);

        if (matchedPhase) {
            setActivePhase(matchedPhase.intensity);
        } else {
            // Below lowest threshold
            setActivePhase(null); // Or phase 0?
        }

    }, [metricValue, selectedTask]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (selectedTaskId) {
            let status;
            if (selectedTask?.metricConfig) {
                const finalIntensity = activePhase || (parseFloat(metricValue) > 0 ? 1 : null);
                status = await addRecord(dateStr, selectedTaskId, finalIntensity, parseFloat(metricValue));
            } else {
                status = await addRecord(dateStr, selectedTaskId, useIntensity ? intensity : null);
            }

            // Notification Logic
            if (status) {
                if (status.valid && status.mercyUsed) {
                    alert(`⚠️ Mercy Used! (${status.mercyRemaining} left this month)\n\n"I have given you this for now."\nThis counts towards your streak, but try to hit your target next time!`);
                } else if (!status.valid) {
                    alert(`❌ Streak Risk!\n\nYou've exhausted your mercy buffer for this month.\nThis entry will NOT count towards your streak or consistency.`);
                } else {
                    // Standard success - maybe a subtle toast or nothing?
                    // User said "dont do shitty things like showing i dont count... and then show streak done"
                    // So we only notify on exceptions.
                }
            }

            onClose();
        }
    };

    const handleDeleteRecord = (taskId: string) => {
        deleteRecord(dateStr, taskId);
        // Refresh local view immediately (though useEffect normally handles it if context updates trigger re-render)
        setExistingRecords(prev => prev.filter(r => r.taskId !== taskId));
    };

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
            {/* Backdrop */}
            <div
                className="absolute inset-0 bg-black/80 backdrop-blur-md animate-[fadeIn_0.3s_ease-out]"
                onClick={onClose}
            />

            {/* Modal Content */}
            <div className="relative w-full max-w-md max-h-[85vh] overflow-y-auto bg-[#0a0a0a] border border-white/10 rounded-xl p-6 shadow-[0_20px_60px_rgba(0,0,0,0.8)] animate-[scaleIn_0.3s_ease-out] custom-scrollbar">
                <button
                    onClick={onClose}
                    className="absolute right-4 top-4 text-muted-foreground hover:text-white transition-colors"
                >
                    <X className="w-5 h-5" />
                </button>

                <h2 className="text-xl font-bold text-white mb-1 flex items-center gap-2">
                    Log Activity
                </h2>
                <p className="text-sm text-muted-foreground mb-6">{dateStr}</p>

                {/* Existing Records Display */}
                {existingRecords.length > 0 && (
                    <div className="mb-6 space-y-2 animate-[fadeIn_0.3s_ease-out]">
                        <h3 className="text-xs font-bold text-muted-foreground uppercase tracking-widest mb-3">Recorded Activity</h3>
                        {existingRecords.map((record, idx) => {
                            const task = tasks.find(t => t.id === record.taskId);
                            if (!task) return null;

                            const isExpanded = expandedRecords.has(record.taskId);
                            // Check for persistence of value (ensure not NaN)
                            const hasValue = record.value !== undefined && record.value !== null && !Number.isNaN(record.value);

                            return (
                                <div key={idx} className="flex items-center justify-between p-3 rounded-lg bg-white/5 border border-white/10 group hover:border-white/30 transition-all select-none">
                                    <div className="flex items-center gap-3">
                                        <div
                                            className="w-3 h-3 rounded-full shadow-[0_0_8px_currentColor]"
                                            style={{ backgroundColor: task.color, color: task.color }}
                                        />
                                        <div className="flex flex-col">
                                            <span className="font-medium text-white">{task.name}</span>
                                            {task.isArchived && <span className="text-[10px] text-accent uppercase tracking-wider">Archived</span>}
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-3">
                                        {isExpanded ? (
                                            <div
                                                className="text-sm font-bold text-accent cursor-pointer animate-[fadeIn_0.2s_ease-out]"
                                                onDoubleClick={() => toggleRecordView(record.taskId)}
                                                title="Double-click to switch view"
                                            >
                                                {hasValue ? `${record.value} ${task.metricConfig?.unit || ''}` : `Intensity: ${record.intensity}`}
                                            </div>
                                        ) : (
                                            <div
                                                className="flex gap-0.5 cursor-pointer"
                                                onDoubleClick={() => toggleRecordView(record.taskId)}
                                                title="Double-click to see details"
                                            >
                                                {record.intensity ? Array.from({ length: 4 }).map((_, i) => (
                                                    <div
                                                        key={i}
                                                        className={`w-1 h-3 rounded-full ${i < record.intensity! ? 'bg-accent' : 'bg-white/10'}`}
                                                    />
                                                )) : <span className="text-xs text-muted-foreground">Completed</span>}
                                            </div>
                                        )}

                                        <button
                                            onClick={() => handleDeleteRecord(task.id)}
                                            className="text-muted-foreground hover:text-red-500 transition-colors p-1"
                                            title="Delete Record"
                                        >
                                            <X className="w-4 h-4" />
                                        </button>
                                    </div>
                                </div>
                            );
                        })}
                        <div className="h-px bg-white/10 my-4" />
                    </div>
                )}

                {activeTasks.length === 0 ? (
                    <div className="text-center py-8">
                        <p className="text-muted-foreground mb-4">No active habits available.</p>
                        <button
                            onClick={onClose}
                            className="text-white underline hover:text-accent"
                        >
                            Manage habits
                        </button>
                    </div>
                ) : (
                    <form onSubmit={handleSubmit} className="space-y-6">
                        <div className="space-y-2">
                            <label className="text-sm text-muted-foreground font-medium uppercase tracking-wider">Select Habit</label>
                            <div className="grid grid-cols-1 gap-2 max-h-[200px] overflow-y-auto custom-scrollbar pr-1">
                                {activeTasks.map(task => (
                                    <button
                                        key={task.id}
                                        type="button"
                                        onClick={() => {
                                            setSelectedTaskId(task.id);
                                            setMetricValue('');
                                            setActivePhase(null);
                                        }}
                                        className={`flex items-center gap-3 px-4 py-3 rounded-lg border transition-all ${selectedTaskId === task.id
                                            ? 'bg-white/10 border-accent/50 text-white'
                                            : 'bg-white/5 border-transparent text-muted-foreground hover:bg-white/10'
                                            }`}
                                    >
                                        <div
                                            className="w-3 h-3 rounded-full shadow-[0_0_8px_currentColor]"
                                            style={{ backgroundColor: task.color, color: task.color }}
                                        />
                                        <span className="font-medium">{task.name}</span>
                                    </button>
                                ))}
                            </div>
                        </div>

                        <div className="space-y-4 pt-2 border-t border-white/5">
                            {selectedTask?.metricConfig ? (
                                // --- CUSTOM METRIC INPUT UI ---
                                <div className="space-y-4 animate-[fadeIn_0.3s_ease-out]">
                                    <div className="space-y-2">
                                        <label className="text-sm text-muted-foreground font-medium uppercase tracking-wider flex justify-between">
                                            <span>{selectedTask.metricConfig.unit}</span>
                                            {activePhase && <span className="text-accent">{selectedTask.metricConfig.phases.find(p => p.intensity === activePhase)?.name} (Phase {activePhase})</span>}
                                        </label>
                                        <input
                                            type="number"
                                            value={metricValue}
                                            onChange={(e) => setMetricValue(e.target.value)}
                                            placeholder={analytics ? `Usually ~${analytics.baselineValue} ${selectedTask.metricConfig.unit}` : `Enter ${selectedTask.metricConfig.unit}...`}
                                            className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-4 text-2xl text-white font-bold placeholder:text-white/10 focus:outline-none focus:border-accent/50 focus:bg-white/10 transition-all"
                                            autoFocus
                                        />
                                    </div>

                                    {/* Phase Progress Indicator */}
                                    {metricValue && (
                                        <div className="flex gap-1 h-2">
                                            {selectedTask.metricConfig.phases.map((phase) => (
                                                <div
                                                    key={phase.intensity}
                                                    className={`flex-1 rounded-full transition-all duration-500 ${(activePhase && activePhase >= phase.intensity)
                                                        ? 'bg-accent shadow-[0_0_8px_currentColor]'
                                                        : 'bg-white/10'
                                                        }`}
                                                    title={`${phase.name}: ${phase.threshold} ${selectedTask.metricConfig!.unit}`}
                                                />
                                            ))}
                                        </div>
                                    )}

                                    {/* Feedback text */}
                                    {activePhase && (
                                        <div className="text-xs text-center text-muted-foreground">
                                            Great job! You've hit the <span className="text-white font-bold">"{selectedTask.metricConfig.phases.find(p => p.intensity === activePhase)?.name}"</span> threshold.
                                        </div>
                                    )}
                                </div>
                            ) : (
                                // --- LEGACY INTENSITY UI --- 
                                <>
                                    <div className="flex items-center justify-between">
                                        <label className="text-sm text-muted-foreground font-medium uppercase tracking-wider">Record Intensity?</label>
                                        <button
                                            type="button"
                                            onClick={() => setUseIntensity(!useIntensity)}
                                            className={`relative w-11 h-6 rounded-full transition-colors shrink-0 ${useIntensity ? 'bg-accent' : 'bg-white/20'}`}
                                        >
                                            <div className={`absolute top-1 left-1 bg-white w-4 h-4 rounded-full transition-transform ${useIntensity ? 'translate-x-5' : 'translate-x-0'}`} />
                                        </button>
                                    </div>

                                    {useIntensity && (
                                        <div className="animate-[fadeIn_0.3s_ease-out]">
                                            <div className="flex justify-between gap-2 mt-2">
                                                {[1, 2, 3, 4].map((level) => (
                                                    <button
                                                        key={level}
                                                        type="button"
                                                        onClick={() => setIntensity(level)}
                                                        className={`flex-1 h-12 rounded-lg border flex items-center justify-center font-bold text-lg transition-all ${intensity === level
                                                            ? 'border-white text-white scale-105 shadow-[0_0_15px_rgba(255,255,255,0.2)]'
                                                            : 'border-white/10 bg-white/5 text-muted-foreground hover:bg-white/10'
                                                            }`}
                                                        style={{
                                                            backgroundColor: intensity === level && selectedTask ? selectedTask.color : undefined,
                                                            borderColor: intensity === level && selectedTask ? selectedTask.color : undefined,
                                                            opacity: intensity === level ? 1 : 0.5 + (level * 0.1)
                                                        }}
                                                    >
                                                        {level}
                                                    </button>
                                                ))}
                                            </div>
                                            <div className="flex justify-between text-[10px] text-muted-foreground uppercase mt-2 px-1">
                                                <span>Light</span>
                                                <span>Extreme</span>
                                            </div>
                                        </div>
                                    )}
                                </>
                            )}
                        </div>

                        <div className="pt-4">
                            <button
                                type="submit"
                                className="w-full bg-white text-black font-bold py-3 rounded-lg hover:bg-gray-200 transition-all hover:scale-[1.02] active:scale-[0.98] shadow-[0_0_20px_rgba(255,255,255,0.2)]"
                            >
                                Save Record
                            </button>
                        </div>
                    </form>
                )}
            </div>
        </div>
    );
}

