                    </blockquote>

                    {/* Behavioral Insight Footer */}
                    {content.insight && (
                        <div className="text-xs text-white/40 font-mono uppercase tracking-widest pt-2 border-t border-white/5 w-full">
                            Insight: {content.insight}
