"use client";

import { useUserData } from "@/context/user-data-context";
import { OnboardingModal } from "./modals/onboarding-modal";
import { NotificationPermissionModal } from "./modals/notification-permission-modal";
import { useState, useEffect } from "react";

export function OnboardingWrapper() {
    const { onboardingCompleted, user, profile } = useUserData();

    // Don't show anything until profile is loaded to prevent flash
    if (user && !profile) {
        return null; // Still loading profile data
    }

    // Only show onboarding if user is logged in and hasn't completed it
    const showOnboarding = user && profile && !onboardingCompleted;

    const [showNotificationModal, setShowNotificationModal] = useState(false);

    useEffect(() => {
        // Show notification modal if:
        // 1. User is fully onboarded
        // 2. User hasn't made a choice yet (check localStorage)
        // 3. User hasn't already granted permissions (native check)
        if (onboardingCompleted && user) {
            const hasChoice = localStorage.getItem('diogenes-notification-choice');
            if (!hasChoice && Notification.permission === 'default') {
                // Small delay to not overwhelm immediately after loading
                const timer = setTimeout(() => setShowNotificationModal(true), 2000);
                return () => clearTimeout(timer);
            }
        }
    }, [onboardingCompleted, user]);

    return (
        <>
            <OnboardingModal isOpen={!!showOnboarding} />
            <NotificationPermissionModal
                isOpen={showNotificationModal}
                onClose={() => setShowNotificationModal(false)}
            />
        </>
    );
}

"use client";

import { useUserData } from '@/context/user-data-context';
import { Dumbbell, BookOpen, Droplet, Carrot, Circle, Check, Zap, Brain, Moon, Plus, Calendar as CalendarIcon, ChevronLeft, ChevronRight } from 'lucide-react';
import { useState, useRef } from 'react';

export function PactWidget() {
    const { pacts, addPact, togglePact, deletePact, shiftPact } = useUserData();
    const [newPactText, setNewPactText] = useState('');
    const [isAdding, setIsAdding] = useState(false);
    const [deleteCandidateId, setDeleteCandidateId] = useState<string | null>(null);

    // Date State
    const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
    const dateInputRef = useRef<HTMLInputElement>(null);

    const todayStr = new Date().toISOString().split('T')[0];
    const isToday = selectedDate === todayStr;
    const displayDate = isToday ? "Today" : new Date(selectedDate).toLocaleDateString(undefined, { month: 'short', day: 'numeric' });

    const currentPacts = pacts[selectedDate] || [];

    const completedCount = currentPacts.filter(p => p.isCompleted).length;
    const totalCount = currentPacts.length;
    const progress = totalCount > 0 ? (completedCount / totalCount) * 100 : 0;

    // Helper: Icon Mapper
    const getIcon = (name: string) => {
        const lower = name.toLowerCase();
        if (lower.includes('workout') || lower.includes('gym') || lower.includes('exercise')) return <Dumbbell className="w-4 h-4" />;
        if (lower.includes('read') || lower.includes('book') || lower.includes('study')) return <BookOpen className="w-4 h-4" />;
        if (lower.includes('water') || lower.includes('drink')) return <Droplet className="w-4 h-4" />;
        if (lower.includes('diet') || lower.includes('eat') || lower.includes('food')) return <Carrot className="w-4 h-4" />;
        if (lower.includes('meditat') || lower.includes('mind')) return <Brain className="w-4 h-4" />;
        if (lower.includes('sleep')) return <Moon className="w-4 h-4" />;
        return <Zap className="w-4 h-4" />; // Generic energetic icon
    };

    const handleAddPact = (e: React.FormEvent) => {
        e.preventDefault();
        if (newPactText.trim()) {
            addPact(newPactText.trim(), selectedDate);
            setNewPactText('');
            // If we have pacts, close the adding mode
            if (currentPacts.length >= 0) {
                setIsAdding(false);
            }
        }
    };

    const showInput = isAdding;

    return (
        <div className="w-full max-w-2xl mx-auto">
            {/* The Widget Card */}
            <div className="bg-zinc-900/60 backdrop-blur-xl border border-white/10 rounded-3xl p-6 shadow-2xl relative overflow-hidden group transition-all duration-500">

                {/* Header Section */}
                <div className="flex justify-between items-start mb-6">
                    <div>
                        <h2 className="text-2xl font-bold text-white tracking-tight flex items-center gap-2">
                            {displayDate}'s Pacts
                        </h2>
                        <p className="text-zinc-500 font-medium text-sm mt-1">
                            {totalCount === 0
                                ? "What will you conquer?"
                                : completedCount === totalCount
                                    ? "All pacts sealed."
                                    : completedCount > 0
                                        ? "Momentum building..."
                                        : "The path is set."}
                        </p>
                    </div>

                    {/* Controls Group */}
                    <div className="flex items-center gap-4">

                        {/* Hidden (but layout-present) Date Input for positioning */}
                        <div className="relative">
                            <input
                                type="date"
                                ref={dateInputRef}
                                className="absolute top-full right-0 opacity-0 pointer-events-none w-0 h-0"
                                onChange={(e) => {
                                    if (e.target.value) setSelectedDate(e.target.value);
                                }}
                            />
                            {/* Calendar Button */}
                            <button
                                onClick={() => dateInputRef.current?.showPicker()}
                                className="w-10 h-10 rounded-full bg-white/5 hover:bg-white/10 flex items-center justify-center text-zinc-400 hover:text-white transition-all border border-transparent hover:border-white/20"
                                title="Select Date"
                            >
                                <CalendarIcon className="w-5 h-5" />
                            </button>
                        </div>

                        {/* Add Button (Only if not already adding and list exists) */}
                        {!showInput && (
                            <button
                                onClick={() => setIsAdding(true)}
                                className="w-10 h-10 bg-white/5 hover:bg-white/10 rounded-full flex items-center justify-center text-zinc-400 hover:text-white transition-all border border-transparent hover:border-white/20"
                                title="Add Pact"
                            >
                                <Plus className="w-5 h-5" />
                            </button>
                        )}

                        {/* Circular Progress */}
                        <div className="relative w-12 h-12 flex items-center justify-center">
                            {/* Track */}
                            <svg className="w-full h-full -rotate-90">
                                <circle
                                    cx="24"
                                    cy="24"
                                    r="20"
                                    className="stroke-white/10 fill-none"
                                    strokeWidth="4"
                                />
                                {/* Progress */}
                                <circle
                                    cx="24"
                                    cy="24"
                                    r="20"
                                    className={`fill-none transition-all duration-1000 ease-out ${completedCount === totalCount ? 'stroke-accent' : 'stroke-white'}`}
                                    strokeWidth="4"
                                    strokeDasharray="125.6"
                                    strokeDashoffset={125.6 - (125.6 * progress) / 100}
                                    strokeLinecap="round"
                                />
                            </svg>
                            <span className="absolute text-xs font-bold text-white">
                                {completedCount}/{totalCount}
                            </span>
                        </div>
                    </div>
                </div>

                {/* Input Form */}
                {showInput && (
                    <form onSubmit={handleAddPact} className="mb-6 relative animate-[fadeIn_0.3s_ease-out]">
                        <input
                            type="text"
                            value={newPactText}
                            onChange={(e) => setNewPactText(e.target.value)}
                            placeholder={`Add a pact for ${displayDate}...`}
                            autoFocus={isAdding}
                            className="w-full bg-black/20 border border-white/10 rounded-xl px-4 py-3 text-white placeholder:text-zinc-600 focus:outline-none focus:border-white/30 transition-all"
                        />
                        <button
                            type="submit"
                            disabled={!newPactText.trim()}
                            className="absolute right-2 top-2 p-1.5 bg-white text-black rounded-lg disabled:opacity-50 disabled:bg-zinc-800 disabled:text-zinc-600 transition-all hover:scale-105 flex items-center justify-center"
                        >
                            <Plus className="w-4 h-4" />
                        </button>
                    </form>
                )}

                {/* List */}
                <div className="flex flex-col gap-3">
                    {currentPacts.map(pact => {
                        const isDeleting = deleteCandidateId === pact.id;

                        if (isDeleting) {
                            return (
                                <div key={pact.id} className="relative flex items-center justify-between p-4 rounded-2xl bg-red-900/20 border border-red-500/30 animate-[pulse_2s_infinite]">
                                    <span className="text-red-200 font-bold ml-2">Delete this pact?</span>
                                    <div className="flex gap-2">
                                        <button
                                            onClick={() => setDeleteCandidateId(null)}
                                            className="px-3 py-1.5 rounded-lg bg-white/5 hover:bg-white/10 text-xs font-bold text-zinc-400 hover:text-white transition-colors"
                                        >
                                            CANCEL
                                        </button>

                                        {(!pact.shiftedCount || pact.shiftedCount < 1) && (
                                            <button
                                                onClick={() => {
                                                    shiftPact(pact.id, selectedDate);
                                                    setDeleteCandidateId(null);
                                                }}
                                                className="px-3 py-1.5 rounded-lg bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-xs font-bold text-white transition-all shadow-lg shadow-blue-900/50 flex items-center gap-1 hover:scale-105 active:scale-95"
                                                title="Move to tomorrow (One-time use)"
                                            >
                                                SHIFT <ChevronRight className="w-3 h-3" />
                                            </button>
                                        )}

                                        <button
                                            onClick={() => {
                                                deletePact(pact.id, selectedDate);
                                                setDeleteCandidateId(null);
                                            }}
                                            className="px-3 py-1.5 rounded-lg bg-red-600 hover:bg-red-500 text-xs font-bold text-white transition-colors shadow-lg shadow-red-900/50"
                                        >
                                            DELETE
                                        </button>
                                    </div>
                                </div>
                            );
                        }

                        return (
                            <button
                                key={pact.id}
                                onClick={() => togglePact(pact.id, selectedDate)}
                                onDoubleClick={() => setDeleteCandidateId(pact.id)}
                                className={`
                                    relative flex items-center justify-between p-4 rounded-2xl transition-all duration-500 group/item text-left select-none
                                    ${pact.isCompleted
                                        ? 'bg-white text-black shadow-[0_0_20px_rgba(255,255,255,0.3)] scale-[1.02]'
                                        : 'bg-zinc-800/40 text-zinc-400 hover:bg-zinc-800/60 hover:text-zinc-200 border border-transparent hover:border-white/5'}
                                `}
                            >
                                <div className="flex items-center gap-3">
                                    <div className={`p-2 rounded-full ${pact.isCompleted ? 'bg-black text-white' : 'bg-white/5 text-current'}`}>
                                        {getIcon(pact.text)}
                                    </div>
                                    <span className={`font-bold text-sm ${pact.isCompleted ? 'line-through decoration-black/20' : ''}`}>
                                        {pact.text}
                                        {pact.shiftedCount && pact.shiftedCount > 0 && (
                                            <span className="ml-2 text-[10px] px-1.5 py-0.5 rounded-full bg-blue-500/20 text-blue-300 border border-blue-500/30">
                                                Shifted
                                            </span>
                                        )}
                                    </span>
                                </div>

                                <div className={`
                                    w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all duration-300
                                    ${pact.isCompleted
                                        ? 'border-black bg-black text-white'
                                        : 'border-zinc-600 group-hover/item:border-zinc-400'}
                                `}>
                                    {pact.isCompleted && <Check className="w-3.5 h-3.5 stroke-[3]" />}
                                </div>
                            </button>
                        );
                    })}

                    {currentPacts.length === 0 && !showInput && (
                        <div className="text-center py-6 text-zinc-600 italic text-sm">
                            No pacts defined for {displayDate}.
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

"use client";
import { useEffect } from 'react';

export function PWAInit() {
    useEffect(() => {
        if (typeof window !== 'undefined') {
            const handlePrompt = (e: any) => {
                e.preventDefault();
                (window as any).deferredPrompt = e;
                window.dispatchEvent(new Event('deferred-prompt-available'));
            };

            window.addEventListener('beforeinstallprompt', handlePrompt);

            if ('serviceWorker' in navigator) {
                window.addEventListener('load', () => {
                    navigator.serviceWorker.register('/sw.js').then(reg => {
                        console.log('SW registered:', reg.scope);
                    }).catch(err => {
                        console.error('SW Error:', err);
                    });
                });
            }
        }
    }, []);
    return null;
}

"use client";

import { useRef, useState, useEffect, MouseEvent } from 'react';
import {
    Download, Shield, Database, Cloud, Upload, RefreshCw, Skull, Calendar,
    User, Lock, Bell, Globe, Moon, ChevronRight, Eye, EyeOff, Trash2,
    Home, Flame, Coins, Sword, ClipboardList, MessageCircle, ScrollText,
    Settings, LogOut, TestTube, LogIn, Volume2, VolumeX
} from 'lucide-react';
import { useUserData, ALL_NAV_ITEMS, NavItemKey } from '@/context/user-data-context';
import { sfx } from '@/utils/sfx';
import { useFCM } from '@/hooks/use-fcm';
import { useInstallPrompt } from '@/hooks/use-install-prompt';
import { getUserAvatar } from '@/utils/avatar-helpers';

const ICON_MAP = {
    Home, Globe, Flame, Coins, Shield, Sword,
    ClipboardList, MessageCircle, ScrollText, Skull, User
};

interface SettingsViewProps {
    isModal?: boolean;
}

export function SettingsView({ isModal = false }: SettingsViewProps) {
    const {
        tasks, records, pacts, notes,
        currentStreak, longestStreak, consistencyScore, streakTier, streakStrength,
        restoreData,
        birthDate, setBirthDate,
        mementoViewMode, toggleMementoViewMode,
        showStatsCard, toggleStatsCard,
        user, profile, theme, setTheme, language, setLanguage,
        navPreferences, updateNavPreferences,
        lifeEvents, debts, vows, investments, currentFaction, isExiled, exiledUntil, onboardingCompleted,
        profileStreakMode, setProfileStreakMode
    } = useUserData();

    const { isInstallable, promptInstall } = useInstallPrompt();
    const fileInputRef = useRef<HTMLInputElement>(null);
    const { token, loading: fcmLoading, requestPermission } = useFCM();
    const [pushNotifications, setPushNotifications] = useState(false);
    const [pushSupported, setPushSupported] = useState(true);
    const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info' } | null>(null);

    // Legacy state for other notifications if needed, generally replaced by pushNotifications
    const [notificationStatus, setNotificationStatus] = useState('Off');
    const [resetSending, setResetSending] = useState(false);
    const [isTestingPush, setIsTestingPush] = useState(false);

    // Date Logic
    const [day, setDay] = useState('');
    const [month, setMonth] = useState('');

    const [year, setYear] = useState('');
    const [soundEnabled, setSoundEnabled] = useState(true);

    useEffect(() => {
        setSoundEnabled(sfx.isEnabled());
    }, []);

    const handleSoundToggle = () => {
        const newState = sfx.toggle();
        setSoundEnabled(newState);
        if (newState) sfx.playSuccess();
    };

    useEffect(() => {
        if (birthDate) {
            const date = new Date(birthDate);
            if (!isNaN(date.getTime())) {
                setDay(date.getDate().toString().padStart(2, '0'));
                setMonth((date.getMonth() + 1).toString().padStart(2, '0'));
                setYear(date.getFullYear().toString());
            }
        }
    }, [birthDate]);

    useEffect(() => {
        const timeoutId = setTimeout(() => {
            if (day && month && year && year.length === 4) {
                const newDate = `${year}-${month.padStart(2, '0')}-${day.padStart(2, '0')}`;
                if (newDate !== birthDate) {
                    setBirthDate(newDate);
                }
            }
        }, 800);
        return () => clearTimeout(timeoutId);
    }, [day, month, year, birthDate, setBirthDate]);

    useEffect(() => {
        const checkPushStatus = async () => {
            const supported = 'serviceWorker' in navigator && 'PushManager' in window;
            setPushSupported(supported);

            if (supported) {
                const granted = Notification.permission === 'granted';
                // Because FCM hook saves token to hook state, if we have a token or permission granted, we consider it ON.
                setPushNotifications(granted);
                setNotificationStatus(granted ? 'On' : 'Off');
            } else {
                setNotificationStatus('Off');
            }
        };
        checkPushStatus();
    }, [token]);

    const showToast = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
        setToast({ message, type });
        setTimeout(() => setToast(null), 4000);
    };

    const handleResetPassword = async () => {
        if (!user?.email) return;
        if (!confirm(`Send password reset email to ${user.email}?`)) return;

        setResetSending(true);
        try {
            const { createClient } = require('@/utils/supabase/client');
            const supabase = createClient();
            const { error } = await supabase.auth.resetPasswordForEmail(user.email, {
                redirectTo: window.location.origin + '/auth/callback?next=/settings',
            });
            if (error) throw error;
            alert('Password reset email sent! Check your inbox.');
        } catch (e: any) {
            alert('Error sending reset email: ' + e.message);
        } finally {
            setResetSending(false);
        }
    };

    const handleTestPush = async (e?: MouseEvent<HTMLButtonElement>, type: 'morning' | 'evening' | 'general' = 'general') => {
        e?.stopPropagation();
        if (notificationStatus !== 'On') {
            alert("Enable notifications first.");
            return;
        }

        setIsTestingPush(true);

        const MESSAGES = {
            general: {
                title: "Signal Received",
                body: "The Neural Link is active even in the void."
            },
            morning: {
                title: "Morning Briefing",
                body: "The sun rises. What will you conquer today?"
            },
            evening: {
                title: "Evening Evaluation",
                body: "The day ends. Update your records. Did you live according to your nature?"
            }
        };

        const msg = MESSAGES[type];

        try {
            // Always show via native notification (reliable, works immediately)
            if ('serviceWorker' in navigator) {
                const reg = await navigator.serviceWorker.ready;
                await reg.showNotification(msg.title, {
                    body: msg.body,
                    icon: '/icons/icon-192.png',
                    badge: '/icons/icon-192.png',
                });
            } else {
                new Notification(msg.title, {
                    body: msg.body,
                    icon: '/icons/icon-192.png',
                });
            }

            // For morning/evening, also test the server API (in the background, non-blocking)
            if (type !== 'general') {
                fetch(`/api/cron/${type}`, { method: 'POST' })
                    .then(res => res.json())
                    .then(data => {
                        console.log(`Server ${type} test:`, data);
                        if (data.error) alert(`Server Error: ${data.error}`);
                        if (data.success) alert(`Server sent to ${data.sent || data.message} devices`);
                    })
                    .catch(err => {
                        console.warn(`Server ${type} test failed:`, err);
                        alert(`Server Connection Failed: ${err.message}`);
                    });
            }
        } catch (err: any) {
            console.error(err);
            alert("Signal failed: " + (err?.message || "Unknown error"));
        } finally {
            setIsTestingPush(false);
        }
    };

    const handlePushToggle = async () => {
        if (fcmLoading) return;

        if (!pushSupported) {
            showToast('Push notifications are not supported in this browser', 'error');
            return;
        }

        try {
            if (pushNotifications) {
                // Since Firebase handles tokens actively, "disabling" practically means 
                // we tell the user to block it in their browser settings.
                showToast('To disable, revoke Notification permissions in your browser settings.', 'info');
            } else {
                const success = await requestPermission();
                if (success) {
                    setPushNotifications(true);
                    setNotificationStatus('On');
                    showToast('🔔 Push notifications enabled! You\'ll receive notifications even when the app is closed.', 'success');
                } else {
                    const permission = Notification.permission;
                    if (permission === 'denied') {
                        showToast('Notification permission denied. Please enable it in your browser settings.', 'error');
                    } else {
                        showToast('Failed to enable push notifications. Please try again.', 'error');
                    }
                }
            }
        } catch (error) {
            console.error('Error toggling push notifications:', error);
            showToast('An error occurred. Please try again.', 'error');
        }
    };

    const handleExport = () => {
        const timestamp = new Date().toISOString();
        const data = {
            meta: {
                exportDate: timestamp,
                appVersion: "1.0.0",
                description: "Gyral Life Data Export - Complete Archive",
                generatedBy: "Gyral System"
            },
            identity: {
                user: { id: user?.id, email: user?.email, metadata: user?.user_metadata },
                profile,
                faction: currentFaction,
                preferences: { theme, language, navPreferences, showStatsCard }
            },
            core: {
                birthDate,
                onboardingCompleted,
                streaks: { currentStreak, longestStreak, consistencyScore, streakTier, streakStrength }
            },
            habits: { tasks, records },
            modules: {
                pacts, notes,
                memento_mori: { life_events: lifeEvents, debts },
                nights_watch: { vows, status: { isExiled, exiledUntil } },
                investment_bank: { investments }
            }
        };

        const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `gyral-archive-${timestamp.split('T')[0]}.json`;
