import { startOfWeek, endOfWeek, eachDayOfInterval, format, subDays, isSameDay, startOfMonth, endOfMonth } from 'date-fns';

type ViewPeriod = 'Day' | 'Week' | 'Month';

export function WeeklyProgress() {
