import { useEffect, useState } from 'react';
import { messaging } from '@/lib/firebase';
import { getToken, onMessage } from 'firebase/messaging';
import { createClient } from '@/utils/supabase/client';
import { PushNotifications } from '@capacitor/push-notifications';
import { Capacitor } from '@capacitor/core';
import { FirebaseMessaging } from '@capacitor-firebase/messaging';

export function useFCM() {
    const [token, setToken] = useState<string | null>(null);
    const [loading, setLoading] = useState<boolean>(false);
    const supabase = createClient();

    useEffect(() => {
        const checkAutoInit = async () => {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) return;

            // Only auto-init if we already have permission granted
            if (!Capacitor.isNativePlatform() && Notification.permission === 'granted') {
                await requestPermission();
            }
        };

        checkAutoInit();
    }, []);

    const requestPermission = async (): Promise<boolean> => {
        setLoading(true);
        try {
            const { data: { session } } = await supabase.auth.getSession();
            if (!session) {
                console.error("User not logged in");
                setLoading(false);
                return false;
            }

            if (Capacitor.isNativePlatform()) {
                await initMobileFCM(session.user.id);
            } else {
                await initWebFCM(session.user.id);
            }
            setLoading(false);
            return true;
        } catch (e) {
            console.error(e);
            setLoading(false);
            return false;
        }
    };

    const initWebFCM = async (userId: string) => {
        const msg = await messaging();
        if (!msg) throw new Error("Firebase Messaging not supported.");

        const permission = await Notification.requestPermission();
        if (permission === 'granted') {
            const vapidKey = process.env.NEXT_PUBLIC_VAPID_PUBLIC_KEY;
            if (!vapidKey) throw new Error('VAPID Key not found in environment');

            const fcmToken = await getToken(msg, { vapidKey });

            if (fcmToken) {
                setToken(fcmToken);
                await saveTokenToDatabase(userId, fcmToken, 'web');
            }

            onMessage(msg, (payload) => {
                console.log('[Web FCM] Message received. ', payload);
            });
        } else {
            throw new Error("Notification permission denied");
        }
    };

    const initMobileFCM = async (userId: string) => {
        let permStatus = await PushNotifications.checkPermissions();
        if (permStatus.receive === 'prompt') {
            permStatus = await PushNotifications.requestPermissions();
        }

        if (permStatus.receive !== 'granted') {
            throw new Error('User denied permissions!');
        }

        const { token: fcmToken } = await FirebaseMessaging.getToken();
        if (fcmToken) {
            setToken(fcmToken);
            const platform = Capacitor.getPlatform() === 'ios' ? 'ios' : 'android';
            await saveTokenToDatabase(userId, fcmToken, platform);
        }

        FirebaseMessaging.addListener('notificationReceived', (event) => {
            console.log('[Mobile FCM] Notification received:', event);
        });
    };

    const saveTokenToDatabase = async (userId: string, pushToken: string, platform: string) => {
        try {
            const { error } = await supabase
                .from('fcm_tokens')
                .upsert({ user_id: userId, token: pushToken, platform }); // removed onConflict as it might not be strictly necessary if token is unique pk

            if (error) {
                console.error('Error saving FCM token to DB:', error);
            }
        } catch (err) {
            console.error('Failed to save token:', err);
        }
    };

    return { token, loading, requestPermission };
}

"use client";
import { useState, useEffect } from 'react';

export function useInstallPrompt() {
    const [isInstallable, setIsInstallable] = useState(false);

    useEffect(() => {
        const check = () => {
            if ((window as any).deferredPrompt) {
                setIsInstallable(true);
            }
        };
        check();
        window.addEventListener('deferred-prompt-available', check);
        return () => window.removeEventListener('deferred-prompt-available', check);
    }, []);

    const promptInstall = async () => {
        const prompt = (window as any).deferredPrompt;
        if (prompt) {
            prompt.prompt();
            const { outcome } = await prompt.userChoice;
            if (outcome === 'accepted') {
                setIsInstallable(false);
                (window as any).deferredPrompt = null;
            }
        }
    };

    return { isInstallable, promptInstall };
}

"use client";

import { useEffect, useState } from 'react';
import { createClient } from '@/utils/supabase/client';

export function usePresence() {
    const [isOnline, setIsOnline] = useState(true);
    const supabase = createClient();

    useEffect(() => {
        let presenceChannel: any;
        let heartbeatInterval: NodeJS.Timeout;

        const initPresence = async () => {
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) return;

            // Mark user as online
            await updatePresence(user.id, 'online');

            // Set up heartbeat to keep presence alive
            heartbeatInterval = setInterval(async () => {
                if (isOnline) {
                    await updatePresence(user.id, 'online');
                }
            }, 30000); // Update every 30 seconds

            // Handle page visibility changes
            const handleVisibilityChange = async () => {
                if (document.hidden) {
                    setIsOnline(false);
                    await updatePresence(user.id, 'away');
                } else {
                    setIsOnline(true);
                    await updatePresence(user.id, 'online');
                }
            };

            document.addEventListener('visibilitychange', handleVisibilityChange);

            // Mark offline on unmount
            return () => {
                clearInterval(heartbeatInterval);
                document.removeEventListener('visibilitychange', handleVisibilityChange);
                updatePresence(user.id, 'offline');
            };
        };

        initPresence();

        // Cleanup on unmount
        return () => {
            if (heartbeatInterval) clearInterval(heartbeatInterval);
        };
    }, [isOnline]);

    const updatePresence = async (userId: string, status: 'online' | 'offline' | 'away') => {
        await supabase
            .from('user_presence')
            .upsert({
                user_id: userId,
                status,
                last_seen: new Date().toISOString(),
                updated_at: new Date().toISOString()
            }, { onConflict: 'user_id' });
    };

    return { isOnline };
}

// Hook to get presence for specific users
export function useUserPresence(userIds: string[]) {
    const [presenceMap, setPresenceMap] = useState<Record<string, {
        status: string;
        last_seen: string;
    }>>({});
    const supabase = createClient();

    useEffect(() => {
        if (!userIds || userIds.length === 0) return;

        const loadPresence = async () => {
            const { data } = await supabase
                .from('user_presence')
                .select('user_id, status, last_seen')
                .in('user_id', userIds);

            if (data) {
                const map: Record<string, { status: string; last_seen: string }> = {};
                data.forEach((p) => {
                    map[p.user_id] = {
                        status: p.status,
                        last_seen: p.last_seen
                    };
                });
                setPresenceMap(map);
            }
        };

        loadPresence();

        // Subscribe to presence changes
        const channel = supabase
            .channel('presence_changes')
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'user_presence',
                    filter: `user_id=in.(${userIds.join(',')})`
                },
                () => {
                    loadPresence();
                }
            )
            .subscribe();

        return () => {
            supabase.removeChannel(channel);
        };
    }, [userIds.join(',')]);

    return presenceMap;
}

